# ─── Model optimization profiles ────────────────────────────────────────────
#
# A profile is a sparse overlay on a model's config. Fields only appear when
# the profile has an opinion — everything else falls through to the raw model
# config / defaults. Profile name lives on the model as `profile`; resolved
# lazily via resolve_model_settings(mid) so editing a profile definition
# updates every model using it without touching config.json.
#
# Precedence (lowest → highest):
#   defaults < model profile overlay < raw model fields < agent config < per-request
#
# Why these specific knobs:
#   - speed: optimises for KV-prefix stability + instant first token on local
#     models. Fat-but-stable prompt beats lean-but-shifting — deferred tool
#     groups change between requests as the model calls tool_search, which
#     invalidates the primed prefix. Local compute is "free" so we don't care
#     about extra tokens.
#   - balanced: current default behaviour. What everything shipped with.
#   - frugal: cloud-money-saver. Aggressive deferral, caveman system prompt,
#     tighter limits. Only safe on capable cloud models — smaller locals get
#     dumber under caveman.
#   - custom: no overlay applied. Backward compat for hand-tuned models.
# MODEL_PROFILES + the four profile resolvers moved to engine/model_select.py
# (refactor C1). Re-exported here so `brain.MODEL_PROFILES`,
# `brain.get_model_profile`, etc. resolve unchanged for every caller.
from engine.model_select import (  # noqa: E402
    MODEL_PROFILES,
    get_model_profile,
    resolve_model_settings,
    resolve_profile_token_config,
    resolve_profile_limits,
)


def _filter_mcp_tools(mcp_tools: list[dict], is_openai: bool = False) -> list[dict]:
    """Apply per-agent MCP tool allow/deny patterns from token_config.

    Patterns match the prefixed LLM-facing name (e.g., "mcp_mempalace_search").
    Supports fnmatch glob syntax: "mcp_mempalace_*", "mcp_mempalace_diary_*".
    `mcp_tool_filter`: if set, only matching tools are kept.
    `mcp_tool_exclude`: applied after filter; matching tools are dropped.
    """
    if not mcp_tools:
        return mcp_tools
    tcfg = _get_token_config()
    allow = tcfg.get("mcp_tool_filter")
    deny = tcfg.get("mcp_tool_exclude")
    if not allow and not deny:
        return mcp_tools
    import fnmatch

    def _name_of(t: dict) -> str:
        if is_openai:
            return (t.get("function", {}) or {}).get("name", "")
        return t.get("name", "")

    def _matches_any(name: str, patterns) -> bool:
        if not patterns:
            return False
        for p in patterns:
            if p == name or fnmatch.fnmatchcase(name, p):
                return True
        return False

    result = []
    for t in mcp_tools:
        n = _name_of(t)
        if allow and not _matches_any(n, allow):
            continue
        if deny and _matches_any(n, deny):
            continue
        result.append(t)
    return result


def _get_token_config(agent_id: str | None = None) -> dict:
    """Get token optimization config for an agent, merged with defaults.

    Precedence (lowest → highest):
      TOKEN_CONFIG_DEFAULTS < model profile overlay < agent token_config

    Model comes from get_request_context()._current_model (set per request).
    Profile contributes deferred_tool_groups, compact_threshold, include_tools_guide.
    """
    agent = get_request_context().current_agent or _current_agent
    result = dict(TOKEN_CONFIG_DEFAULTS)

    # Overlay model profile's token_config fragment if a model is bound
    mid = get_request_context()._current_model
    if mid:
        prof = resolve_profile_token_config(mid)
        for k, v in prof.items():
            if k in result:
                result[k] = v

    if not agent:
        return result
    cfg = agent.config.get("token_config", {})
    if isinstance(cfg, dict):
        for k in TOKEN_CONFIG_DEFAULTS:
            if k in cfg:
                result[k] = cfg[k]
    return result


def _get_agent_tool_names(agent_id: str | None = None) -> set[str] | None:
    """Get the set of allowed tool names for an agent based on the global ×
    agent-override hierarchy.

    Resolution per tool:
      1. Global `tool_settings.<name>.enabled` (default True) — admin kill
         switch
      2. Agent override `token_config.tool_overrides.<name>.enabled` — when
         present, overrides the global value (tristate semantics: field
         absent = inherit, present = override)

    Returns the explicit set of enabled tool names. When `agent_id` is
    None or the agent has no overrides, returns the full TOOL_DISPATCH
    keyset minus globally-disabled tools (so callers can intersect with
    purpose-specific subsets cleanly).

    Returns None ONLY when nothing is disabled at any layer — caller
    treats None as 'all tools' and skips the explicit filter (small
    optimisation for the common no-config case).
    """
    # Cheap fast path: if no global tool_settings AND no agent overrides,
    # there's nothing to filter — return None.
    has_global = bool(_tool_settings)
    agent_overrides = {}
    if agent_id:
        agent = get_request_context().current_agent
        if agent and getattr(agent, 'agent_id', None) == agent_id:
            agent_overrides = (agent.config.get("token_config", {}) or {}).get("tool_overrides") or {}
        else:
            try:
                cfg_path = os.path.join(AGENTS_DIR, agent_id, "agent.json")
                with open(cfg_path, "r", encoding="utf-8") as f:
                    agent_overrides = (json.load(f).get("token_config", {}) or {}).get("tool_overrides") or {}
            except (OSError, json.JSONDecodeError):
                agent_overrides = {}
    if not has_global and not agent_overrides:
        return None  # No filter active — caller falls through to "all tools"

    # Walk every tool, apply layered enabled. Tools not in TOOL_DISPATCH
    # are ignored (they can't be called anyway).
    names: set[str] = set()
    for name in TOOL_DISPATCH.keys():
        # Resolve canonical state: global record, then agent override (status
        # opinion replaces global). Derive enabled from the collapsed state so
        # the impossible enabled/deferred combo can never sneak a tool in/out.
        state = _rec_tool_state((_tool_settings or {}).get(name), default="active")
        override = agent_overrides.get(name) or {}
        if "state" in override or "enabled" in override or "deferred" in override:
            state = _rec_tool_state(override, default=state)
        if _tool_state_to_flags(state)["enabled"]:
            names.add(name)
    return names


def _should_defer_mcp(defer_setting, mcp_tools: list[dict], model: str,
                      is_openai: bool = False) -> bool:
    """Decide whether to defer MCP tool schemas.

    defer_setting: True (always defer), False (never), "auto" (defer when MCP tokens > 10% of context)
    """
    if defer_setting is True:
        return bool(mcp_tools)
    if defer_setting is False:
        return False
    # "auto" mode: defer when MCP tool schemas would exceed 10% of context window
    if not mcp_tools:
        return False
    mcp_schema_chars = sum(len(json.dumps(t)) for t in mcp_tools)
    mcp_schema_tokens = mcp_schema_chars // 4
    max_ctx = get_model_max_context(model)
    threshold = max_ctx * 0.10  # 10% of context window
    return mcp_schema_tokens > threshold


def get_tool_breakdown(agent_id: str | None = None) -> dict:
    """Measure tool-definition token cost by group and individual tool.

    Each tool row is decomposed into:
      name_tokens / desc_tokens / schema_tokens / total_tokens
    so callers can see WHY a tool is expensive (usually: bloated input_schema).

    Token estimation uses len(json.dumps(x)) // 4 — same method as the request-payload snapshot.
    """

    def _tok(obj) -> int:
        if obj is None:
            return 0
        if isinstance(obj, str):
            return len(obj) // 4
        try:
            return len(json.dumps(obj)) // 4
        except (TypeError, ValueError):
            return 0

    def _decompose(td: dict) -> dict:
        name = td.get("name") or (td.get("function", {}) or {}).get("name", "")
        desc = td.get("description") or (td.get("function", {}) or {}).get("description", "")
        if isinstance(desc, (list, tuple)):
            desc = " ".join(str(x) for x in desc)
        schema = td.get("input_schema")
        if schema is None:
            schema = (td.get("function", {}) or {}).get("parameters", {})
        name_tok = _tok(name)
        desc_tok = _tok(desc)
        schema_tok = _tok(schema)
        total_tok = _tok(td)
        # Track schema complexity for at-a-glance diagnosis
        props = {}
        required_count = 0
        if isinstance(schema, dict):
            props = schema.get("properties", {}) or {}
            required_count = len(schema.get("required", []) or [])
        return {
            "name": name,
            "desc": (desc[:200] + "...") if isinstance(desc, str) and len(desc) > 200 else desc,
            "name_tokens": name_tok,
            "desc_tokens": desc_tok,
            "schema_tokens": schema_tok,
            "tokens": total_tok,  # alias for sorting
            "total_tokens": total_tok,
            "param_count": len(props) if isinstance(props, dict) else 0,
            "required_count": required_count,
        }

    # Reverse index for built-in tools: tool name -> group name
    name_to_group: dict[str, str] = {}
    for gname, names in TOOL_GROUPS.items():
        for n in names:
            name_to_group[n] = gname

    groups: dict[str, dict] = {}

    def _bump(gname: str, source: str, tool_info: dict):
        key = f"{source}:{gname}"
        g = groups.setdefault(key, {
            "name": gname, "source": source,
            "tool_count": 0, "tokens": 0, "tools": [],
            "name_tokens": 0, "desc_tokens": 0, "schema_tokens": 0,
        })
        g["tool_count"] += 1
        g["tokens"] += tool_info["total_tokens"]
        g["name_tokens"] += tool_info["name_tokens"]
        g["desc_tokens"] += tool_info["desc_tokens"]
        g["schema_tokens"] += tool_info["schema_tokens"]
        g["tools"].append(tool_info)

    # --- Built-in tools ---
    for td in TOOL_DEFINITIONS:
        name = td.get("name", "")
        if not name:
            continue
        info = _decompose(td)
        gname = name_to_group.get(name, "other")
        _bump(gname, "builtin", info)

    # --- MCP tools (grouped by actual server, via authoritative _tool_to_server map) ---
    mcp_mgr = get_request_context().mcp_manager or _mcp_manager
    mcp_tools_list: list[dict] = []
    tool_to_server: dict[str, str] = {}
    if mcp_mgr:
        try:
            mcp_tools_list = mcp_mgr.get_tool_definitions() or []
            mcp_tools_list = _filter_mcp_tools(mcp_tools_list, is_openai=False)
            # Access the manager's reverse map safely.
            tool_to_server = dict(getattr(mcp_mgr, '_tool_to_server', {}) or {})
        except Exception:
            mcp_tools_list = []
            tool_to_server = {}
    for td in mcp_tools_list:
        name = td.get("name", "")
        if not name:
            continue
        info = _decompose(td)
        server = tool_to_server.get(name)
        if not server:
            # Fallback: parse "mcp_<server>_<tool>" prefix (current MCPManager naming)
            if name.startswith("mcp_"):
                rest = name[4:]
                # Take everything up to the first underscore as server name.
                # This is approximate — server names containing underscores will land in "mcp".
                server = rest.split("_", 1)[0] if "_" in rest else rest
            else:
                server = "mcp"
        _bump(server or "mcp", "mcp", info)

    # Sort tools within each group by token cost descending
    group_list = []
    for g in groups.values():
        g["tools"].sort(key=lambda t: t["total_tokens"], reverse=True)
        group_list.append(g)
    group_list.sort(key=lambda g: g["tokens"], reverse=True)

    total_tokens = sum(g["tokens"] for g in group_list)
    total_count = sum(g["tool_count"] for g in group_list)

    # Built-in tool group deferral status
    tcfg = _get_token_config()
    deferred_builtin_set = set(tcfg.get("deferred_tool_groups") or [])
    for g in group_list:
        g["deferred"] = g["source"] == "builtin" and g["name"] in deferred_builtin_set
    deferred_builtin_tokens = sum(g["tokens"] for g in group_list if g.get("deferred"))

    # Deferral status: would MCP be auto-deferred for the agent's current model?
    agent = get_request_context().current_agent or _current_agent
    model = (agent.config.get("model") if agent else "") or ""
    max_ctx = get_model_max_context(model) if model else 0
    mcp_tokens = sum(g["tokens"] for g in group_list if g["source"] == "mcp")
    threshold = int(max_ctx * 0.10) if max_ctx else 0
    deferred = bool(mcp_tools_list) and threshold > 0 and mcp_tokens > threshold

    # Per-purpose tool surface (PROMPT_TOOLS_UNIFICATION_PLAN.md). Lets the
    # admin UI show "what does the model actually see" under each delivery
    # channel. `transform` always yields []. We swallow errors so a broken
    # resolver can't take the whole breakdown view down.
    per_purpose: dict[str, dict] = {}
    for _p in ("interactive", "memory_summary", "transform"):
        try:
            _tools = resolve_active_tools(
                purpose=_p, agent_id=agent_id,
                discovered_tools=set(),
                mcp_manager=mcp_mgr if _p == "interactive" else None,
                is_openai_shape=False,
            )
            per_purpose[_p] = {
                "tool_names": sorted(t.get("name", "") for t in _tools),
                "tool_count": len(_tools),
            }
        except Exception as _e:  # pragma: no cover - defensive
            per_purpose[_p] = {"error": str(_e)[:200]}

    return {
        "groups": group_list,
        "total_tokens": total_tokens,
        "total_count": total_count,
        "builtin_tokens": sum(g["tokens"] for g in group_list if g["source"] == "builtin"),
        "mcp_tokens": mcp_tokens,
        "model": model,
        "max_context": max_ctx,
        "deferred_builtin_groups": sorted(deferred_builtin_set),
        "deferred_builtin_tokens": deferred_builtin_tokens,
        "deferrable_mcp": {
            "deferred": deferred,
            "tokens_saved_if_deferred": mcp_tokens if deferred else 0,
            "threshold": threshold,
        },
        "per_purpose": per_purpose,
    }


def tool_purpose_matrix(agent_id: str | None = None) -> dict:
    """Per-use-case tool-status matrix for the admin UI.

    For every purpose in _VALID_PURPOSES and every TOOL_DISPATCH tool, the
    effective state (resolve_tool_state_for) plus its token cost in that channel:
      - active   → full schema tokens (name + wire description + input_schema)
      - deferred → name-only stub tokens (the tool_search stub the model sees)
      - inactive → 0
    The per-purpose `summary.tokens` counts ONLY the tools actually realized by
    resolve_active_tools for that purpose (so it matches what the model
    receives, not every globally-active tool). `transform` yields [] by design.

    agent_id=None → global matrix (no agent layer). A concrete agent_id folds
    the agent's tool_overrides in.
    """
    def _tok(obj) -> int:
        if obj is None:
            return 0
        if isinstance(obj, str):
            return len(obj) // 4
        try:
            return len(json.dumps(obj)) // 4
        except (TypeError, ValueError):
            return 0

    def _full_tokens(td: dict) -> int:
        name = td.get("name") or (td.get("function", {}) or {}).get("name", "")
        desc = td.get("description") or (td.get("function", {}) or {}).get("description", "")
        if isinstance(desc, (list, tuple)):
            desc = " ".join(str(x) for x in desc)
        schema = td.get("input_schema")
        if schema is None:
            schema = (td.get("function", {}) or {}).get("parameters", {})
        return _tok(name) + _tok(desc) + _tok(schema)

    idx = _TOOL_DEF_INDEX or {}
    # EVERY tool counts. The matrix spans all dispatchable tools PLUS the
    # integration-only pseudo-tools (email/refinement/translation/text_to_speech/
    # code_graph — service configs, not agent-callable). Integration-only tools
    # are never part of any agent channel's surface, so they resolve to inactive
    # for every purpose — but they're still counted, so the invariant
    # total == active + inactive + deferred holds for every column.
    try:
        integ_only = sorted(set((get_tool_config() or {}).keys()) - set(TOOL_DISPATCH.keys()))
    except Exception:
        integ_only = []
    all_tools = sorted(TOOL_DISPATCH.keys()) + integ_only
    integ_set = set(integ_only)
    matrix: dict[str, dict] = {}
    summary: dict[str, dict] = {}
    for purpose in _VALID_PURPOSES:
        # Realized name set the model actually receives for this purpose (no MCP
        # — the matrix scores built-in tools only). Swallow resolver errors so a
        # bad config can't blank the whole view.
        try:
            realized = {t.get("name", "") for t in resolve_active_tools(
                purpose=purpose, agent_id=agent_id,
                discovered_tools=set(), mcp_manager=None, is_openai_shape=False,
            )}
        except Exception:
            realized = set()
        cells: dict[str, dict] = {}
        s_active = s_inactive = s_deferred = s_tokens = 0
        for name in all_tools:
            td = idx.get(name) or {}
            # A tool not in this channel's surface is reported as INACTIVE for
            # this purpose (it isn't shipped on this channel). A tool IS in the
            # surface → its resolved per-purpose state (active/deferred). The cell
            # stays editable client-side: setting a not-in-surface tool to
            # active/deferred pulls it into the channel (the extend pass).
            if name in realized:
                state = resolve_tool_state_for(name, agent_id, purpose)
            else:
                state = "inactive"
            if state == "active":
                tokens = _full_tokens(td)
                s_active += 1
            elif state == "deferred":
                tokens = _tok(name)
                s_deferred += 1
            else:  # inactive — off, or not part of this channel's tool set
                tokens = 0
                s_inactive += 1
            cells[name] = {"state": state, "tokens": tokens}
            s_tokens += tokens
        matrix[purpose] = cells
        summary[purpose] = {
            "active": s_active, "inactive": s_inactive, "deferred": s_deferred,
            "tokens": s_tokens, "realized_count": len(realized),
        }
    return {"purposes": list(_VALID_PURPOSES), "tools": all_tools,
            "matrix": matrix, "summary": summary}


def seed_tool_purpose_states(settings: dict) -> int:
    """ONE-TIME seed of per-purpose `states` from the legacy code base sets, so
    the table becomes the source of truth for purpose membership WITHOUT changing
    observed behaviour on the switch-over (PER_USE_CASE_TOOL_MATRIX).

    For each TOOL_DISPATCH tool and each purpose, write states[purpose]:
      - member of that purpose's OLD base set  → the tool's scalar state
        (active/deferred/inactive — preserves a globally-disabled/deferred tool)
      - NOT a member                            → 'inactive' (not in that channel)
    transform → all inactive (it never carries tools).

    Idempotent + guarded: a record that ALREADY has a `states` dict is left
    untouched (so admin edits are never clobbered). Mutates `settings` in place;
    returns the number of records seeded (for the boot persist gate). The legacy
    base-set helpers (_HELPDESK_TOOLS, _MEMORY_SUMMARY_TOOLS, _minimal_tool_names)
    are read HERE and nowhere else at runtime after seeding.
    """
    # Old base-set membership per purpose, for an unrestricted (global) agent —
    # mirrors the pre-matrix resolve_active_tools branches. Sourced from
    # _purpose_base_members (shared with the resolver's fail-closed fallback,
    # so seed and fallback can never disagree); None = unrestricted = all tools.
    membership = {
        p: (_purpose_base_members(p) if _purpose_base_members(p) is not None
            else set(TOOL_DISPATCH.keys()))
        for p in _VALID_PURPOSES
    }
    changed = 0
    for name in TOOL_DISPATCH:
        rec = settings.get(name)
        if not isinstance(rec, dict):
            rec = empty_tool_setting()
            settings[name] = rec
        if isinstance(rec.get("states"), dict) and rec["states"]:
            continue  # already has a per-purpose map — don't clobber
        scalar = _rec_tool_state(rec, default="active")
        states = {}
        for purpose, members in membership.items():
            if name in members:
                # Preserve the tool's scalar status within its channel (a
                # globally-inactive tool like exa_search stays inactive even
                # where it's a channel member; deferred stays deferred).
                states[purpose] = scalar
            else:
                states[purpose] = "inactive"
        rec["states"] = states
        changed += 1
    return changed


def backfill_purpose_column(settings: dict, purpose: str, members: set[str]) -> int:
    """Idempotently ADD one purpose's `states` cell to every already-seeded tool
    record (the one-time seed skips records that already have a states map, so a
    NEW purpose added after first boot would otherwise be missing from the table
    and fall through to each tool's scalar default — wrongly making everything
    'active' for the new column). For each TOOL_DISPATCH tool that lacks a
    states[purpose] entry, set it: members → the tool's scalar state (so a
    globally-disabled tool stays disabled in its channel), non-members →
    'inactive'. Records that ALREADY carry states[purpose] are left untouched
    (admin edits preserved). Returns the number of cells added."""
    changed = 0
    for name in TOOL_DISPATCH:
        rec = settings.get(name)
        if not isinstance(rec, dict):
            rec = empty_tool_setting()
            settings[name] = rec
        states = rec.get("states")
        if not isinstance(states, dict):
            states = {}
            rec["states"] = states
        if purpose in states:
            continue  # already present (seeded or admin-set) — don't clobber
        if name in members:
            states[purpose] = _rec_tool_state(rec, default="active")
        else:
            states[purpose] = "inactive"
        changed += 1
    return changed


def _global_tool_wire_description_override(name: str) -> str:
    """Admin override for a tool's WIRE description (the schema `description` the
    model actually receives), stored at tool_settings.<name>.wire_description.
    Empty/absent → no override (the code TOOL_DEFINITIONS description stands).
    This is the ONLY editable path to the wire schema; input_schema stays a code
    contract."""
    rec = (_tool_settings or {}).get(name)
    if not isinstance(rec, dict):
        return ""
    return str(rec.get("wire_description") or "").strip()


def _apply_wire_description_override(td: dict, is_openai: bool) -> dict:
    """Return `td` unchanged, or a SHALLOW COPY with its wire description replaced
    by the admin override when one is set. Copying only the overridden dicts keeps
    every other tool dict object-identical to TOOL_DEFINITIONS (KV-prefix stable —
    a tool with no override produces a byte-identical wire entry)."""
    if is_openai:
        name = (td.get("function", {}) or {}).get("name", "")
    else:
        name = td.get("name", "")
    override = _global_tool_wire_description_override(name)
    if not override:
        return td
    if is_openai:
        fn = dict(td.get("function", {}) or {})
        fn["description"] = override
        return {**td, "function": fn}
    return {**td, "description": override}


# Code-Mode write-path steering. The stock descriptions of the write tools say
# "use a RELATIVE filename so the file lands in the session's artifact folder"
# (v9.153.0 — the fix for reports landing in the repo root). In CODE MODE that
# advice INVERTS: relative paths resolve against `working_dir` = the PROJECT ROOT
# (engine/tools/file_tools.py:_cwd_base), so a bare filename drops a helper script
# or report straight into the user's source tree — observed on glm-5.2, which
# wrote analyze_dependencies.py + the HTML report into eval/sql/ next to the SQL
# folders. The system-prompt rule alone did NOT fix it (verified live: the model
# has the rule in its prompt and still wrote `count_sp.py`) — the tool description
# sits right where the path is chosen and wins. So in code mode we REPLACE the
# artifact-folder sentence with the subdirectory rule, per tool.
_CODE_MODE_WRITE_HINT = (
    " IN THIS PROJECT relative paths resolve against the PROJECT ROOT, not an "
    "artifact folder. Do NOT drop generated files into the root and do NOT put "
    "them in the project's own directories. Source code you change or add stays "
    "where the project's existing code lives — never move it. Everything YOU "
    "generate to do your work — helper/analysis scripts, reports, diagrams, "
    "exports, intermediate files — goes under THIS CHAT's output folder "
    "(`chats/<title>_<date>_<id>/`, e.g. `<chat folder>/scripts/analyse.py`, "
    "`<chat folder>/reports/report.html`). The exact folder for this chat is "
    "given to you in the conversation — use it verbatim, never a bare filename."
)
# python_exec runs with cwd = the OUTPUT FOLDER (v9.312.12), so for it the generic
# "relative resolves against the project root" sentence above is wrong — and the
# truth is simpler: just write relatively. Correctness no longer depends on the
# model cooperating with an env var (it demonstrably didn't).
_CODE_MODE_PYEXEC_HINT = (
    " Your script RUNS WITH ITS CWD SET TO THIS CHAT'S OUTPUT FOLDER, so just use "
    "plain relative paths and both directions work: writing "
    "(`open('report.html','w')`) lands in the output folder automatically, and "
    "reading the project's source (`open('q1/Queries/x.sql')`, "
    "`Path('q1').rglob('*.sql')`) reaches it as usual. `$BRAIN_ROOT` (project root) "
    "and `$BRAIN_OUT` (this output folder) hold the absolute paths if you need them."
)
# execute_command KEEPS cwd = project root (its commands are overwhelmingly reads
# across the source tree), so it still has to be told where to write.
_CODE_MODE_SHELL_HINT = (
    " Your command runs with its cwd = the PROJECT ROOT (so it can read source with "
    "relative paths), therefore it must NOT write output relative to that: the "
    "absolute output folder is in the `BRAIN_OUT` environment variable — write "
    "there (`$BRAIN_OUT/report.html`)."
)
# Only the tools that CREATE files. read/list/search are unaffected.
_CODE_MODE_WRITE_TOOLS = {"write_file", "write_document", "python_exec",
                          "execute_command", "render_diagram"}
# Per-tool addenda appended after the shared hint.
_CODE_MODE_TOOL_HINTS = {"python_exec": _CODE_MODE_PYEXEC_HINT,
                         "execute_command": _CODE_MODE_SHELL_HINT}


def _in_code_mode() -> bool:
    """True when this turn runs inside a Code-Mode project (a `working_dir` is
    bound on the request context). Warmup + plain chats have none, so their wire
    stays byte-identical and the warm KV prefix is untouched."""
    try:
        wd = get_request_context().working_dir
    except Exception:
        return False
    return bool(wd)


def _apply_code_mode_write_hint(td: dict, is_openai: bool) -> dict:
    """Append the code-mode subdirectory rule to a write tool's wire description.
    Shallow-copies only the affected tools (same discipline as the admin override)
    so every other tool dict stays object-identical to TOOL_DEFINITIONS."""
    if is_openai:
        fn = dict(td.get("function", {}) or {})
        name = fn.get("name", "")
    else:
        name = td.get("name", "")
    if name not in _CODE_MODE_WRITE_TOOLS:
        return td
    # Shared rule + the per-tool addendum (python_exec and execute_command have
    # DIFFERENT cwds, so one sentence cannot be true for both).
    _hint = _CODE_MODE_WRITE_HINT + _CODE_MODE_TOOL_HINTS.get(name, "")
    if is_openai:
        fn["description"] = (fn.get("description") or "") + _hint
        return {**td, "function": fn}
    return {**td, "description": (td.get("description") or "") + _hint}


def _filter_tools(tool_list: list[dict], allowed: set[str] | None,
                  is_openai: bool = False) -> list[dict]:
    """Filter a tool definition list to only include allowed tools.
    Returns tools sorted by name for prompt cache stability.

    Applies any admin wire-description override (tool_settings.<name>.
    wire_description) — the single seam every purpose + warmup path goes through,
    so an override reaches the model identically everywhere. Only overridden
    dicts are copied; the rest stay object-identical to TOOL_DEFINITIONS.

    In CODE MODE the write tools additionally carry the subdirectory rule (their
    stock "relative → artifact folder" advice points into the project root there).
    Gated on the request context's working_dir, so non-code turns and warmup are
    byte-identical."""
    if allowed is None:
        filtered = list(tool_list)
    elif is_openai:
        filtered = [t for t in tool_list if t["function"]["name"] in allowed]
    else:
        filtered = [t for t in tool_list if t["name"] in allowed]
    # Sort deterministically by tool name for Anthropic prompt cache stability.
    # Consistent ordering prevents cache misses when tool list is assembled in different order.
    if is_openai:
        filtered.sort(key=lambda t: t.get("function", {}).get("name", ""))
    else:
        filtered.sort(key=lambda t: t.get("name", ""))
    out = [_apply_wire_description_override(t, is_openai) for t in filtered]
    if _in_code_mode():
        out = [_apply_code_mode_write_hint(t, is_openai) for t in out]
    return out


# --- Unified tool-list resolver (PROMPT_TOOLS_UNIFICATION_PLAN.md) ---

# Tool sets for non-interactive purposes. `interactive` uses the agent's own
# tool_groups; the others are scoped subsets evaluated against TOOL_DEFINITIONS
# at resolver time (so a tool that isn't registered is silently dropped —
# keeps stale plan references safe).
# Memory-summary tasks file new drawers and read drilldown context.
# mempalace_get_drawer / mempalace_list_drawers were rolled back; if they
# reappear the resolver will pick them up automatically (intersection with
# TOOL_DEFINITIONS happens via _filter_tools).
_MEMORY_SUMMARY_TOOLS = {"mempalace_query", "save_chat_to_memory",
                         "wiki_read", "wiki_write"}

# Fixed read-only tool set for the helpdesk bot (Brainy). It loads the exclusive
# brain-agent-guide skill (use_skill), reads the current session + user context,
# and searches memory — but cannot write, run commands, or fetch the web. This
