# research_minimal — harness-style lean purpose. Tools are discovered
# dynamically by `minimal: True` flag on their TOOL_DEFINITIONS entry; each
# such tool may also carry `minimal_role` (a one-line phrase composed into
# the dynamic system prompt). Add a new tool to the purpose by setting these
# two fields on its definition — no constant to update here. Validated
# 2026-05-14 (Gate-PT-2) on gemma-4-e4b for autonomous research tasks.
# instruction_gen — AI-generation of project instructions (engine/instruction_gen.py).
# A read+research-only purpose: the agent reads the project's reference files +
# queries its wing/KG + may web-search, then WRITES the instruction document as
# its final text (not via a tool). Its tool set is admin-configurable in the
# per-use-case tool matrix (Service-/Tools-Einstellungen), seeded below to the
# read/research tools. No file-write/email/git/python/delegation tools.
_VALID_PURPOSES = ("interactive", "transform", "memory_summary", "research_minimal", "helpdesk", "instruction_gen", "workflow_step")

# Valid `tool_profile` values for a scheduled task. Empty string = "default"
# (resolved to research_minimal at fire time, matching Phase A behavior).
# `research_minimal`: harness-style lean prompt + minimal-flagged tools.
# `interactive`: full agent surface (matches chat). Restored opt-in surface.
# Memory-summary tasks (name starts with `_memory_summary_`) always use the
# memory_summary purpose regardless of this field.
_VALID_TOOL_PROFILES = ("", "research_minimal", "interactive")


def _minimal_tool_names() -> set[str]:
    """Return the set of tool names flagged `minimal: True` in TOOL_DEFINITIONS.
    Single source of truth — read at call time so additions land without a
    server restart (definitions are reloaded by the import system at boot).
    """
    return {t.get("name", "") for t in TOOL_DEFINITIONS if t.get("minimal") and t.get("name")}


def _minimal_tool_blurbs() -> list[tuple[str, str]]:
    """Ordered (name, role) pairs for the research_minimal prompt.

    `minimal_role` is the phrase that follows the tool name (e.g.
    "to find relevant sources"). Builder wraps the name in backticks and
    appends the role plain. Canonical order = alphabetical by tool name.
    Tools without a `minimal_role` are skipped.
    """
    items = [t for t in TOOL_DEFINITIONS
             if t.get("minimal") and t.get("name") and t.get("minimal_role")]
    items.sort(key=lambda t: t.get("name", ""))
    return [(t["name"], t["minimal_role"]) for t in items]


def resolve_active_tools(
    *,
    purpose: str,
    agent_id: str | None = None,
    discovered_tools: set[str] | None = None,
    mcp_manager=None,
    is_openai_shape: bool = False,
    breakdown: dict | None = None,
) -> list[dict]:
    """Single source of truth for what tools the model sees on a given turn.

    If `breakdown` (a dict) is passed, it is filled IN PLACE with the GROUND
    TRUTH of this resolution — no reconstruction from group tables: it records
    `in_prompt` (sorted names actually in the wire array), `deferred` (built-in
    names this turn pushed to tool_search-only), and `excluded` (names hard-
    dropped via exclude_tools). The chat worker passes this through
    build_first_turn_prefix so the per-turn classification modal shows exactly
    what was handed to the model vs. deferred — not a derived guess.

    Returns the wire payload (Anthropic shape by default; OpenAI shape via
    `is_openai_shape=True`). Every caller — chat handler, scheduler, warmup,
    sidecar background_call, settings UI tool-breakdown — goes through this
    function.

    Logic (membership is the PER-USE-CASE TABLE, not hardcoded sets):
      1. purpose=='transform' → [] (contract: transform carries no tools).
      2. Otherwise base_set = every TOOL_DISPATCH tool whose EFFECTIVE
         per-purpose state (resolve_tool_state_for: agent cell → agent scalar →
         global cell → global scalar) is 'active' or 'deferred'. This is the
         single source of truth for which tools a channel sees — the legacy code
         base sets (_HELPDESK_TOOLS / _MEMORY_SUMMARY_TOOLS / minimal-flagged /
         agent.json allowed) only SEED the table once and are NOT read here.
      3. Filter TOOL_DEFINITIONS (or _OPENAI) to the base set.
      4. Subtract 'deferred'-state tools (tool_search-only) unless already in
         discovered_tools; apply per-turn defer_extra/undefer + exclude_tools.
      5. Add MCP tools (interactive only, when mcp_manager passed + not deferred).
      6. Re-sort by name for KV-cache stability.
    """
    if purpose not in _VALID_PURPOSES:
        raise ValueError(f"resolve_active_tools: unknown purpose {purpose!r}")
    if purpose == "transform":
        return []  # contract: transform calls carry no tools, table-independent

    # MEMBERSHIP IS THE TABLE (PER_USE_CASE_TOOL_MATRIX). A tool belongs to this
    # purpose's surface iff its EFFECTIVE per-purpose state (agent cell → agent
    # scalar → global cell → global scalar) is active or deferred. The legacy
    # code base sets (_HELPDESK_TOOLS, _MEMORY_SUMMARY_TOOLS, minimal-flagged,
    # agent.json allowed) are NO LONGER consulted at runtime — they only SEED the
    # initial global `states` once (seed_tool_purpose_states), after which the
    # table fully owns membership. `deferred` tools are in the set but subtracted
    # below (tool_search-only) unless already discovered this turn.
    base_set = {n for n in TOOL_DISPATCH
                if resolve_tool_state_for(n, agent_id, purpose) in ("active", "deferred")}

    defs = TOOL_DEFINITIONS_OPENAI if is_openai_shape else TOOL_DEFINITIONS
    tools = _filter_tools(defs, base_set, is_openai=is_openai_shape)

    def _name_of(t: dict) -> str:
        return (t.get("function", {}) or {}).get("name", "") if is_openai_shape else t.get("name", "")

    # Defer subtraction. Membership came from the table (state ∈ active|deferred);
    # here we pull the `deferred` ones out of the initial prompt (they remain
    # tool_search-discoverable and stay live once discovered this turn). Driven by
    # the same per-purpose state seam, so it matches the matrix UI exactly. Runs
    # uniformly for every purpose — there is no longer a special-cased channel.
    deferred_names: set[str] = set()
    for _n in TOOL_DISPATCH:
        if resolve_tool_state_for(_n, agent_id, purpose) == "deferred":
            deferred_names.add(_n)
    # Per-turn classifier deferral adjustment (non-warmup models only; the
    # worker leaves these unset for warm/local models so their KV prefix is
    # untouched). `defer_extra_tools` pushes un-needed groups out (still
    # tool_search-discoverable — NOT excluded); `undefer_tools` pulls the
    # classifier's needed groups in even if statically deferred. undefer
    # wins over defer_extra so a needed tool is never re-deferred.
    _rc = get_request_context()
    _defer_extra = _rc.defer_extra_tools
    _undefer = _rc.undefer_tools
    if _defer_extra:
        deferred_names |= set(_defer_extra)
    if _undefer:
        deferred_names -= set(_undefer)
    if deferred_names:
        discovered = discovered_tools or set()
        tools = [t for t in tools
                 if _name_of(t) not in deferred_names or _name_of(t) in discovered]

    # Per-turn exclusion. Names on the request context's `exclude_tools` are
    # dropped unconditionally for this turn (even if enabled/discovered). Set
    # by the chat worker; the single mechanism the manual-web-search flow uses
    # to hard-disable the web tools (web_fetch/exa_search/searxng_search) when
    # the user hands in curated sources. Applied to built-in tools here and
    # again after the MCP merge so
    # an excluded MCP tool name is also removed.
    _excluded = get_request_context().exclude_tools
    if _excluded:
        _excluded = set(_excluded)
        tools = [t for t in tools if _name_of(t) not in _excluded]

    # Other code paths below still use _get_token_config for non-tool config
    # (defer_mcp, mcp_tool_filter). Keep for compatibility.
    tcfg = _get_token_config(agent_id)

    # MCP tools — mirror the send_message + warmup paths bytewise.
    if mcp_manager is not None and purpose == "interactive":
        if is_openai_shape:
            mcp_tools = mcp_manager.get_tool_definitions_openai()
            mcp_tools = _filter_mcp_tools(mcp_tools, is_openai=True)
        else:
            mcp_tools = mcp_manager.get_tool_definitions()
            mcp_tools = _filter_mcp_tools(mcp_tools, is_openai=False)
        defer_mcp = tcfg.get("defer_mcp_tools", "auto")
        # Need a concrete model id for the "auto" threshold; thread-local
        # current_agent is the source-of-truth at request time.
        agent_ctx = get_request_context().current_agent or _current_agent
        model = (agent_ctx.config.get("model") if agent_ctx else "") or ""
        should_defer = _should_defer_mcp(defer_mcp, mcp_tools, model,
                                         is_openai=is_openai_shape)
        if should_defer:
            discovered = discovered_tools or set()
            if is_openai_shape:
                mcp_tools = [t for t in mcp_tools
                             if (t.get("function", {}) or {}).get("name", "") in discovered]
            else:
                mcp_tools = [t for t in mcp_tools if t.get("name", "") in discovered]
        tools = list(tools) + list(mcp_tools)
        if _excluded:
            tools = [t for t in tools if _name_of(t) not in _excluded]
        if is_openai_shape:
            tools.sort(key=lambda t: (t.get("function", {}) or {}).get("name", ""))
        else:
            tools.sort(key=lambda t: t.get("name", ""))

    if breakdown is not None:
        # GROUND TRUTH for the inspector. in_prompt = the final wire names.
        # deferred = the names resolution pushed to tool_search-only this turn
        # (built-in deferred_names that did NOT end up in-prompt, i.e. weren't
        # discovered/un-deferred). excluded = hard-dropped names. All read off
        # the actual computation above, never re-derived from group tables.
        _in_prompt = {_name_of(t) for t in tools}
        _discovered = discovered_tools or set()
        breakdown["in_prompt"] = sorted(n for n in _in_prompt if n)
        breakdown["deferred"] = sorted(
            n for n in deferred_names
            if n not in _in_prompt and n not in _discovered)
        breakdown["excluded"] = sorted(_excluded) if _excluded else []

    return tools


def _active_tool_name_set(tools: list[dict], is_openai_shape: bool) -> set[str]:
    """Helper for callers that just need the names that came out of resolve_active_tools."""
    if is_openai_shape:
        return {(t.get("function", {}) or {}).get("name", "") for t in tools}
    return {t.get("name", "") for t in tools}


# --- Tool prompt settings (admin-editable per-tool prose) ---
#
# Each tool name → record with up to 4 prose sections plus an `applies_with`
# all-of gate. Empty strings = section omitted from the rendered prompt; if
# every section is empty, the tool contributes nothing (the model still gets
# the JSON tool schema — only the prose guidance is gated).
#
# Storage: server_config["tool_settings"] (loaded from config.json["tool_settings"]).
# Edited via admin endpoints (Commit 3); migrated from the legacy tools.md
# anchored blocks at startup (Commit 1) — see migrate_tool_settings_from_md.
#
# Section render order (matters for KV-cache stability):
#   1. Description
#   2. When to use
#   3. Warnings
#   4. Examples
_TOOL_SETTING_FIELDS = ("description", "when_to_use", "warnings", "examples")
_TOOL_SETTING_FIELD_TITLES = {
    "description": "Description",
    "when_to_use": "When to use",
    "warnings": "Warnings",
    "examples": "Examples",
}


def empty_tool_setting() -> dict:
    """Default empty tool settings record.

    Defaults: state='active' (the canonical single status field — never the
    legacy enabled/deferred pair), purposes=[] (= "all purposes"). `purposes`
    is the list of purposes (`interactive`, `research_minimal`,
    `memory_summary`, `transform`) where this tool is allowed; empty list
    means no purpose filter applies.
    """
    return ({field: "" for field in _TOOL_SETTING_FIELDS}
            | {"applies_with": [], "state": "active", "purposes": []})


# --- Tool status: single canonical state ('active' | 'inactive' | 'deferred')
# ---
# A tool has exactly ONE status, never two flags at once. On disk the canonical
# field is `state`; the legacy `{enabled, deferred}` boolean pair is read only as
# a fallback for un-migrated records (boot migration rewrites them to `state`).
# enabled/deferred are DERIVED from state everywhere — these two functions are
# the single derivation seam:
#   active   → enabled=True,  deferred=False
#   inactive → enabled=False  (deferred irrelevant)
#   deferred → enabled=True,  deferred=True
TOOL_STATES = ("active", "inactive", "deferred")


def _tool_state_to_flags(state: str) -> dict:
    """Canonical state → the (enabled, deferred) pair it represents."""
    if state == "inactive":
        return {"enabled": False, "deferred": False}
    if state == "deferred":
        return {"enabled": True, "deferred": True}
    return {"enabled": True, "deferred": False}  # active (default)


def _rec_tool_state(rec: dict | None, *, default: str = "active") -> str | None:
    """Resolve a record's status to one of TOOL_STATES.

    Prefers the canonical `state` field. Falls back to the legacy
    (enabled, deferred) booleans for un-migrated records. Returns None only
    when `rec` is None AND no default is wanted (callers pass default to get
    the no-record behaviour). A record that is `{}` (present but empty) is
    treated as the default state, matching the historical enabled-default-True.
    """
    if rec is None:
        return default
    st = rec.get("state")
    if st in TOOL_STATES:
        return st
    # Legacy fallback: derive from the old boolean pair. enabled=False wins →
    # inactive regardless of deferred (the impossible-combo collapse).
    if rec.get("enabled", True) is False:
        return "inactive"
    return "deferred" if rec.get("deferred", False) else "active"


def migrate_tool_settings_to_state(settings: dict) -> int:
    """Forward-migration: collapse legacy {enabled, deferred} booleans on every
    tool_settings record into the canonical `state` field, dropping the old
    keys. Idempotent — a record already carrying a valid `state` (and no legacy
    keys) is left untouched. Mutates `settings` in place; returns the number of
    records rewritten (for the boot persist gate). Integration-only entries (no
    TOOL_DISPATCH) are left alone — their `enabled` is their own integration gate.
    """
    changed = 0
    for name, rec in list((settings or {}).items()):
        if not isinstance(rec, dict):
            continue
        if name not in TOOL_DISPATCH:
            continue  # integration-only pseudo-tool — not part of the state model
        has_legacy = ("enabled" in rec) or ("deferred" in rec)
        has_state = rec.get("state") in TOOL_STATES
        if has_state and not has_legacy:
            continue  # already migrated
        state = _rec_tool_state(rec, default="active")
        rec["state"] = state
        rec.pop("enabled", None)
        rec.pop("deferred", None)
        changed += 1
    return changed


def migrate_agent_tool_overrides_to_state(agent_id: str) -> bool:
    """Forward-migration for one agent's token_config.tool_overrides: collapse
    legacy {enabled, deferred} per-tool override booleans into `state`, dropping
    the old keys. An override with NO status keys (e.g. MCP-filter-only) is left
    as-is. Writes agent.json only when something changed. Returns True if written.
    """
    try:
        cfg_path = os.path.join(AGENTS_DIR, agent_id, "agent.json")
        with open(cfg_path, "r", encoding="utf-8") as f:
            cfg = json.load(f)
    except (OSError, json.JSONDecodeError):
        return False
    overrides = ((cfg.get("token_config") or {}).get("tool_overrides")) or {}
    changed = False
    for name, ovr in list(overrides.items()):
        if not isinstance(ovr, dict):
            continue
        has_legacy = ("enabled" in ovr) or ("deferred" in ovr)
        if not has_legacy:
            continue  # nothing status-y to migrate (or already state-only)
        state = _rec_tool_state(ovr, default="active")
        ovr["state"] = state
        ovr.pop("enabled", None)
        ovr.pop("deferred", None)
        # An override that is now empty would be dead weight — but keep it; the
        # save path drops empties, and a {state} entry is meaningful.
        changed = True
    if not changed:
        return False
    try:
        with open(cfg_path, "w", encoding="utf-8") as f:
            json.dump(cfg, f, indent=2)
        return True
    except OSError:
        return False


def _global_tool_enabled(name: str) -> bool:
    """Bare global enable flag, derived from the tool's canonical state.
    Default (no record) = active = enabled."""
    state = _rec_tool_state((_tool_settings or {}).get(name), default="active")
    return _tool_state_to_flags(state)["enabled"]


def _global_tool_deferred(name: str) -> bool:
    """Bare global defer flag, derived from the tool's canonical state.
    Default (no record) = active = not deferred."""
    state = _rec_tool_state((_tool_settings or {}).get(name), default="active")
    return _tool_state_to_flags(state)["deferred"]


def _global_tool_state(name: str) -> str:
    """The tool's global canonical state. Default 'active' when no record."""
    return _rec_tool_state((_tool_settings or {}).get(name), default="active")


def _global_tool_purposes(name: str) -> list[str]:
    """Bare global purposes list. Default [] (= all purposes)."""
    rec = (_tool_settings or {}).get(name)
    if rec is None:
        return []
    return list(rec.get("purposes") or [])


def _agent_tool_override(agent_id: str | None, name: str) -> dict:
    """Return the agent's per-tool override record for `name`, or {} if none.

    Walks (a) thread-local current_agent if it matches `agent_id`, otherwise
    (b) reads `agents/<id>/agent.json` from disk. The thread-local path is
    fast (zero I/O) and is what runtime call paths hit; the disk path lets
    helpers / probes / endpoints work without a session context.
    """
    if not agent_id:
        return {}
    # Fast path: thread-local agent matches
    agent = get_request_context().current_agent
    if agent and getattr(agent, 'agent_id', None) == agent_id:
        cfg = agent.config.get("token_config", {})
    else:
        # Disk path
        try:
            cfg_path = os.path.join(AGENTS_DIR, agent_id, "agent.json")
            with open(cfg_path, "r", encoding="utf-8") as f:
                agent_cfg = json.load(f)
            cfg = agent_cfg.get("token_config", {}) or {}
        except (OSError, json.JSONDecodeError):
            return {}
    if not isinstance(cfg, dict):
        return {}
    overrides = cfg.get("tool_overrides") or {}
    return overrides.get(name) or {}


def resolve_tool_enabled(name: str, agent_id: str | None = None) -> bool:
    """Resolve a tool's effective enabled flag through the layer hierarchy:

      1. Global (tool_settings.<name>.enabled, default True)
      2. Agent override (token_config.tool_overrides.<name>.enabled, optional)

    Returns the bottom-most layer that has an opinion. Used by both
    `_get_agent_tool_names` (filtering) and the prompt builder.
    """
    return _tool_state_to_flags(resolve_tool_state(name, agent_id))["enabled"]


def resolve_tool_deferred(name: str, agent_id: str | None = None) -> bool:
    """Resolve a tool's effective defer flag (same hierarchy as enabled)."""
    return _tool_state_to_flags(resolve_tool_state(name, agent_id))["deferred"]


def resolve_tool_state(name: str, agent_id: str | None = None) -> str:
    """Resolve a tool's effective canonical state through the layer hierarchy:

      1. Global  (tool_settings.<name>.state, default 'active')
      2. Agent override (token_config.tool_overrides.<name>.state) — when the
         override record carries a status opinion (canonical `state`, or a
         legacy `enabled`/`deferred` key), it REPLACES the global state.
         An override with no status keys = inherit (e.g. an MCP-filter-only
         record). Returns one of TOOL_STATES.
    """
    state = _global_tool_state(name)
    override = _agent_tool_override(agent_id, name)
    if isinstance(override, dict) and (
        "state" in override or "enabled" in override or "deferred" in override
    ):
        # The override has a status opinion — collapse it the same way the
        # global record is collapsed (canonical state wins, else legacy pair).
        state = _rec_tool_state(override, default=state)
    return state


# --- Per-use-case (purpose-aware) tool status -----------------------------
#
# A tool's status can be set independently per delivery channel (purpose).
# Storage is additive on top of the scalar `state`:
#   tool_settings.<name>.states         = {<purpose>: state, ...}   (global)
#   tool_overrides.<name>.states        = {<purpose>: state, ...}   (agent)
# The scalar `state` (and the legacy enabled/deferred pair) stays the
# CATCH-ALL DEFAULT for any purpose NOT listed in `states`. A record with no
# `states` key therefore behaves exactly as before — "that scalar state for
# every purpose" — which keeps the interactive warm-pool KV prefix byte-stable
# when nobody has set a per-purpose cell. `states.<purpose>` is consulted only
# when the key is present.

def _rec_state_for_purpose(rec: dict | None, purpose: str, *, default: str = "active") -> str | None:
    """A record's status for one purpose: prefer states[purpose], else the
    record's scalar state (canonical `state` / legacy pair), else `default`.
    Returns None only when rec is None and default is None."""
    if rec is None:
        return default
    states = rec.get("states")
    if isinstance(states, dict) and states.get(purpose) in TOOL_STATES:
        return states[purpose]
    return _rec_tool_state(rec, default=default)


def _rec_has_purpose_opinion(rec: dict | None, purpose: str) -> bool:
    """True iff `rec` carries an explicit per-purpose status for `purpose`
    (a states[purpose] entry). A bare scalar `state` is NOT a purpose opinion —
    it's the catch-all default. Used to gate the extend/restrict pass so the
    no-override path stays byte-identical."""
    if not isinstance(rec, dict):
        return False
    states = rec.get("states")
    return isinstance(states, dict) and states.get(purpose) in TOOL_STATES


_purpose_base_members_cache: dict[str, set | None] = {}


def _purpose_base_members(purpose: str) -> set | None:
    """The code base set for a RESTRICTED purpose (None = unrestricted).

    Single source for both the one-time boot seed (seed_tool_purpose_states)
    and the resolver's fail-closed fallback below. Cached — the underlying
    sets are module constants, static for the process lifetime."""
    if purpose not in _purpose_base_members_cache:
        _purpose_base_members_cache[purpose] = {
            "interactive": None,                        # unrestricted (legacy)
            "transform": set(),                         # contract: no tools
            "memory_summary": set(_MEMORY_SUMMARY_TOOLS),
            "research_minimal": set(_minimal_tool_names()),
            "helpdesk": set(_HELPDESK_TOOLS),
            "instruction_gen": set(_INSTRUCTION_GEN_TOOLS),
            "workflow_step": set(_WORKFLOW_STEP_TOOLS),
        }.get(purpose)
    return _purpose_base_members_cache[purpose]


def _global_tool_state_for(name: str, purpose: str) -> str:
    """Global per-purpose state: states[purpose] else scalar state (default 'active').

    FAIL-CLOSED fallback (9.314.1): when a record carries NO explicit cell for a
    RESTRICTED purpose (helpdesk, memory_summary, …), membership in that
    purpose's code base set decides — a non-member is 'inactive', never
    default-'active'. Without this, any tool whose matrix cell is missing
    (unseeded install, or a tool registered after the boot seed) would silently
    join Brainy's read-only channel — write/exec tools included. On a seeded
    matrix (every prod boot) this branch never fires, so resolution stays
    byte-identical; 'interactive' keeps the legacy default-active behaviour."""
    rec = (_tool_settings or {}).get(name)
    if not _rec_has_purpose_opinion(rec, purpose):
        members = _purpose_base_members(purpose)
        if members is not None and name not in members:
            return "inactive"
    return _rec_state_for_purpose(rec, purpose, default="active")


def resolve_tool_state_for(name: str, agent_id: str | None, purpose: str) -> str:
    """Effective canonical state for (tool, agent, purpose) through the full
    hierarchy, top wins:
      1. agent  tool_overrides.<name>.states[purpose]
      2. agent  tool_overrides.<name>.state / legacy pair  (scalar opinion)
      3. global tool_settings.<name>.states[purpose]
      4. global tool_settings.<name>.state / legacy pair    (default 'active')

    The agent layer REPLACES the global state only when it carries a status
    opinion for this purpose (per-purpose entry, or any scalar status key).
    """
    state = _global_tool_state_for(name, purpose)
    override = _agent_tool_override(agent_id, name)
    if isinstance(override, dict):
        if _rec_has_purpose_opinion(override, purpose):
            state = override["states"][purpose]
        elif "state" in override or "enabled" in override or "deferred" in override:
            state = _rec_tool_state(override, default=state)
    return state


def _any_purpose_overrides(agent_id: str | None, purpose: str) -> bool:
    """True iff ANY tool carries an explicit per-purpose status for `purpose`
    at the global OR the agent layer. When False, the per-purpose
    extend/restrict + defer passes in resolve_active_tools are a no-op — the
    fast path that keeps the interactive base array byte-identical for warm KV
    prefix stability."""
    for _rec in (_tool_settings or {}).values():
        if _rec_has_purpose_opinion(_rec, purpose):
            return True
    if agent_id:
        agent = get_request_context().current_agent
        if agent and getattr(agent, 'agent_id', None) == agent_id:
            overrides = (agent.config.get("token_config", {}) or {}).get("tool_overrides") or {}
        else:
            try:
                cfg_path = os.path.join(AGENTS_DIR, agent_id, "agent.json")
                with open(cfg_path, "r", encoding="utf-8") as f:
                    overrides = (json.load(f).get("token_config", {}) or {}).get("tool_overrides") or {}
            except (OSError, json.JSONDecodeError):
                overrides = {}
        for _ovr in overrides.values():
            if _rec_has_purpose_opinion(_ovr, purpose):
                return True
    return False


# tool_passes_purpose / tool_is_enabled / tool_is_deferred (the tool
# resolver predicates — NOT TOOL_DISPATCH entries) moved to
# engine/tools/misc_tools.py (refactor E4); re-exported below near
# TOOL_DISPATCH.

def seed_tool_settings_purposes(settings: dict) -> dict:
    """Ensure every tool in TOOL_DISPATCH has a `purposes` field on its
    settings record, seeded from current resolver behavior:
      - 'interactive' (every tool — was the legacy default)
      - 'research_minimal' if the tool has `minimal: True` in TOOL_DEFINITIONS
      - 'memory_summary' if the tool is in _MEMORY_SUMMARY_TOOLS
      - 'transform' is never auto-seeded (transform calls supply their own
        prompt + tool list explicitly; per design this purpose returns [])

    Idempotent: leaves any non-default value alone (admin edits via the
    UI persist `purposes` explicitly). Returns the mutated `settings`
    dict for chaining.
    """
    minimal_set = _minimal_tool_names()
    for name in TOOL_DISPATCH.keys():
        rec = settings.setdefault(name, empty_tool_setting())
        # Only seed when the field is missing or empty — admin edits win.
        if "purposes" not in rec or not rec.get("purposes"):
            seeded: list[str] = ["interactive"]
            if name in minimal_set:
                seeded.append("research_minimal")
            if name in _MEMORY_SUMMARY_TOOLS:
                seeded.append("memory_summary")
            rec["purposes"] = seeded
    return settings


def migrate_agent_tool_overrides(agent_id: str) -> bool:
    """One-shot per-agent migration: translate legacy tool_groups /
    extra_tools / deferred_tool_groups fields on `agent.json` into the new
    `tool_overrides` dict. Idempotent: if the agent already has any
    `tool_overrides` entries OR has no legacy fields set, this is a no-op.

    Translation rules:
      - tool_groups (whitelist of allowed groups): tools NOT in any allowed
        group get `enabled: false`. Preserves the agent's curated subset.
      - extra_tools (additional tool names beyond groups): added to the
        allowed set before the negative filter (so they get `enabled: true`
        implicitly via not being negative-filtered).
      - deferred_tool_groups: every tool in those groups gets `deferred: true`.

    Returns True if the agent was migrated, False if no change needed.
    Persists the updated agent.json on success.
    """
    try:
        agent_dir = os.path.join(AGENTS_DIR, agent_id)
        cfg_path = os.path.join(agent_dir, "agent.json")
        if not os.path.exists(cfg_path):
            return False
        with open(cfg_path, "r", encoding="utf-8") as f:
            agent_cfg = json.load(f)
    except (OSError, json.JSONDecodeError):
        return False
    tcfg = (agent_cfg.get("token_config") or {}) if isinstance(agent_cfg.get("token_config"), dict) else {}
    existing_overrides = tcfg.get("tool_overrides") or {}
    if existing_overrides:
        return False  # Already has overrides — admin or prior migration touched it.
    tool_groups = tcfg.get("tool_groups")
    extra_tools = tcfg.get("extra_tools")
    deferred_tool_groups = tcfg.get("deferred_tool_groups")
    if not tool_groups and not extra_tools and not deferred_tool_groups:
        return False  # No legacy fields to migrate.
    overrides: dict[str, dict] = {}
    # tool_groups → negative-filter (tools not in allowed set get enabled=false)
    if tool_groups:
        allowed: set[str] = set()
        for g in tool_groups:
            allowed.update(TOOL_GROUPS.get(g, set()))
        if extra_tools:
            allowed.update(extra_tools)
        for name in TOOL_DISPATCH.keys():
            if name not in allowed:
                overrides.setdefault(name, {})["enabled"] = False
    # deferred_tool_groups → mark every tool in those groups deferred=true
    if deferred_tool_groups:
        deferred_names: set[str] = set()
        for dg in deferred_tool_groups:
            deferred_names.update(TOOL_GROUPS.get(dg, set()))
        for name in deferred_names:
            overrides.setdefault(name, {})["deferred"] = True
    # Persist
    if not overrides:
        return False
    tcfg["tool_overrides"] = overrides
    agent_cfg["token_config"] = tcfg
    try:
        with open(cfg_path, "w", encoding="utf-8") as f:
            json.dump(agent_cfg, f, indent=2)
    except OSError:
        return False
    return True


def migrate_tool_settings_from_md(tools_md_path: str) -> dict:
    """One-shot migration: parse legacy tools.md anchored blocks into the new
    per-tool settings shape. Each anchor's body becomes the leading tool's
    `description`; multi-anchor blocks attach to the first listed tool with
    the rest going into `applies_with`.

    Returns a dict suitable for `server_config["tool_settings"]`. Caller
    decides whether to persist (only on first migration, when config.json
    has no `tool_settings` key yet).
    """
    settings: dict[str, dict] = {}
    try:
        st = os.stat(tools_md_path)  # noqa: F841 — just exists-check
    except OSError:
        return settings
    try:
        with open(tools_md_path, "r", encoding="utf-8") as f:
            text = f.read()
    except OSError:
        return settings
    import re as _re
    parts = _re.split(r"<!--\s*@anchor:([^>]+?)\s*-->", text)
    for i in range(1, len(parts), 2):
        anchor = parts[i].strip()
        body = parts[i + 1] if (i + 1) < len(parts) else ""
        names = [n.strip() for n in anchor.split(",") if n.strip()]
        if not names:
            continue
        leader = names[0]
        applies_with = names[1:]
        rec = empty_tool_setting()
        rec["description"] = body.lstrip("\n").rstrip()
        rec["applies_with"] = applies_with
        settings[leader] = rec
    return settings


# Live runtime state, populated by server.py at startup from config.json
# tool_settings (and refreshed when admin saves via /v1/tools/settings).
# Keyed by leading tool name; record shape per `empty_tool_setting()`.
_tool_settings: dict[str, dict] = {}


def _render_tool_descriptions(active_tool_names: set[str]) -> str:
    """Render per-tool prompt prose for the active tool set.

    For each leading tool present in `active_tool_names` whose settings record
    has at least one non-empty section AND whose `applies_with` requirement is
    satisfied (every name in the list also present), emit a `## name` heading
    followed by `### Description / When to use / Warnings / Examples`
    subsections (only the non-empty ones, fixed order — KV-cache stable).

    Returns "" when nothing applies (typical for `transform` / most
    `memory_summary` calls and any agent whose active tools have all-empty
    descriptions). When one or more apply, the returned string is the text
    only — no leading header — so the caller can decide how to delimit it.
    """
    if not active_tool_names or not _tool_settings:
        return ""
    out_parts: list[str] = []
    # Iterate by sorted tool name so the rendered order is deterministic
    # (KV-prefix stability across turns even if admin edits one record).
    for name in sorted(_tool_settings.keys()):
        if name not in active_tool_names:
            continue
        rec = _tool_settings[name] or {}
        # Defensive: a disabled tool should never reach the renderer because
        # _get_agent_tool_names filters it out; double-check here so a stale
        # active-set still doesn't leak its prose. Derived from canonical state.
        if _rec_tool_state(rec) == "inactive":
            continue
        applies_with = rec.get("applies_with") or []
        if applies_with and not all(req in active_tool_names for req in applies_with):
            continue
        sections: list[str] = []
        for field in _TOOL_SETTING_FIELDS:
            body = (rec.get(field) or "").strip()
            if not body:
                continue
            sections.append(f"### {_TOOL_SETTING_FIELD_TITLES[field]}\n{body}")
        if not sections:
            continue
        out_parts.append(f"## {name}\n" + "\n\n".join(sections))
    return "\n\n".join(out_parts).rstrip() + ("\n" if out_parts else "")


# --- Tool Execution ---

# _ok / _err moved to engine/tool_exec.py (refactor C2); re-exported at the
# bottom of this module so bare in-brain `_ok(...)`/`_err(...)` calls and
# `brain._ok` resolve unchanged.


def extract_attachment_text(path: str) -> tuple[str, str]:
    """Extract plain text from an attachment, sharing tool_read_document's
    parser dispatch. Returns `(text, kind)` where `kind` is one of:
      "text"     — extracted; scan may proceed
      "archive"  — .zip / .epub / .msg — accepted gap, do not scan
      "media"    — image / audio / video — accepted gap, do not scan
      "unsupported" — extension we can't extract (no scan possible)

    Used by the upload-time PII scanner (POST /v1/attachments/scan).
    Pure side-effect-free wrapper around the existing parsers — no caching,
    no anonymisation, no thread-local reads. Caller decides what to do
    with the text.
    """
    ext = os.path.splitext(path)[1].lower()
    # Images are NO LONGER an accepted gap. A photographed ID card is a .jpg,
    # and skipping it meant the single most PII-dense attachment type reached
    # the model completely UNSCANNED.
    #
    # We scan BOTH readings — deterministic AND model — concatenated. For a
    # DETECTOR (unlike a citation, where an invented name would be a lie) recall
    # is what counts: a scan that misses a real passport number is a data breach,
    # a scan that flags one name too many costs the user one confirmation click.
    # Neither reader alone is sufficient, measured on the real scans:
    #   - tesseract returns character soup on a photographed passport
    #     ("+ rer KEES 045584 FE RRS STE ZZ") — it misses the actual name, and
    #     its garbage even trips a false detector hit on its own.
    #   - the model reads the name and the number, but can invent one.
    # A false positive here is CHEAP (the user confirms), a false negative is
    # not. So: union of both, and let the detectors decide.
    if ext in (".png", ".jpg", ".jpeg", ".gif", ".webp", ".bmp"):
        parts = []
        try:
            from engine.doc_convert import tesseract_read, _extract_image_ocr
            r = tesseract_read(path)
            if r and (r.get("text") or "").strip():
                parts.append(r["text"])
            model_text, _backend, _err = _extract_image_ocr(path)
            if model_text:
                parts.append(model_text)
        except Exception:
            pass
        if parts:
            return "\n\n".join(parts), "text"
        return "", "media"
    if ext in (".svg",
               ".mp3", ".wav", ".ogg", ".flac", ".m4a",
               ".mp4", ".mov", ".webm", ".mkv", ".avi"):
        return "", "media"
    if ext in (".zip", ".epub", ".msg"):
        return "", "archive"
    try:
        # Binary/tabular doc types share the one unified extractor
        # (markitdown-first → per-format fallback). caps=False = full text so
        # the scanner sees every cell/row. (.msg/.epub/.zip are archive-
        # skipped above, so they never reach here.)
        from engine.doc_convert import _do_extract, SUPPORTED_EXTS
        if ext in SUPPORTED_EXTS:
            kwargs: dict = {"caps": False}
            if ext == ".pdf":
                kwargs["emit_meta"] = True
                kwargs["page_marker"] = "--- Page"
            text, _backend, err = _do_extract(path, **kwargs)
            if err:
                return "", "unsupported"
            return text, "text"
        # Plain text fallback (.txt .md .log .html .htm .json + unknown).
        with open(path, "r", errors="replace") as f:
            return f.read(), "text"
    except Exception:
        return "", "unsupported"


# `_classification_gate_tool_text`, `_classification_effective_action`, and
# `classification_pick_model_for_background` were extracted to
# engine/classification.py (next to the detector). Re-imported below the
# brain-side classification helpers they depend on (see the alias import
# near `_classification_action_level`). brain.X / engine.X still resolve.


def _review_anon_override(text: str, source: str) -> str | None:
    """Return a user-reviewed, pre-anonymised version of `text` if one exists.

    INVARIANT-CRITICAL (see handlers/data_review): this only ever returns a
    stored `anon_text` when ALL hold — a saved review exists for the current
    user, its status is 'anonymised', and its content hash matches `text`. In
    every other case it returns None and the caller falls back to today's
    behaviour exactly. It NEVER introduces anonymisation where the caller wasn't
    already going to anonymise; callers guard their own "should I anonymise at
    all" decision and only consult this for WHICH anonymised text to use.

    Matching is by content hash so a renamed/copied file still reuses its
    review. Best-effort; never raises.
    """
    if not text:
        return None
    try:
        uid = get_request_context().current_user_id or ""
    except Exception:
        uid = ""
    if not uid:
        return None
    try:
        from engine import doc_review
        from server_lib.db import DataReviewDB
        chash = doc_review.content_hash(text)
        row = DataReviewDB.get_by_hash(chash, uid, admin=False)
        if (row and row.get("status") == "anonymised"
                and row.get("anon_text")
                and row.get("content_hash") == chash):
            return row["anon_text"]
    except Exception as e:
        print(f"[data_review] anon override lookup failed: {e}", flush=True)
    return None


def gdpr_bind_mapping(mapping_id: str) -> bool:
    """M1 — bind `mapping_id` onto the CURRENT request context, rehydrating the
    mapping from `pseudonym_maps` when the in-memory registry no longer holds it.

    This is the single entry point every NON-interactive turn (scheduler,
    background task, delegate, fan-out leaf) uses to join the parent session's
    fake world. Everything GDPR hangs off `_gdpr_mapping_id`: the tool-result
    seam (`_gdpr_anon_tool_text`), the args de-anonymiser
    (`_gdpr_deanon_tool_args`) and the egress gate (`_gdpr_guard_web_args`) all
    read it and no-op when it's empty — which is exactly why a background turn
    without it ran completely unprotected (G1).

    The rehydration is NOT optional bookkeeping. The interactive worker calls
    `pseudonymizer.close_mapping()` in its `finally`, dropping the mapping from
    the in-memory registry the moment the spawning turn ends — while a detached
    background task may still run for another hour. A sub-turn that merely
    inherited the ID would then find `get_mapping()` → None and silently fall
    back to "no mapping active", i.e. re-open G1 through the back door on
    exactly the long fan-outs this fix exists for. The encrypted row in
    chats.db outlives `close_mapping`, so we reload from it.

    Returns True when a usable mapping is now bound. Never raises: on failure
    the context is left WITHOUT a mapping, which is the safe direction for the
    seams (they anonymise nothing) but NOT for egress — callers that gate on
    this must treat False as "no protection available" (see the fail-closed
    check in `_gdpr_guard_egress_args`).
    """
    if not mapping_id:
        return False
    try:
        import pseudonymizer as _ps
        m = _ps.get_mapping(mapping_id)
        if m is None:
            m = _ps.load_mapping(mapping_id)
            if m is not None:
                _ps.restore_mapping_to_registry(m)
        if m is None:
            print(f"[gdpr] bind FAILED mapping={mapping_id[:12]} — not in "
                  f"registry and not persisted; turn runs UNMAPPED", flush=True)
            return False
        get_request_context()._gdpr_mapping_id = mapping_id
        return True
    except Exception as e:
        print(f"[gdpr] bind FAILED mapping={mapping_id[:12]}: {e}", flush=True)
        return False


def gdpr_persist_mapping(mapping_id: str, session_id: str, turn_id: str = "") -> None:
    """Persist a mapping a NON-interactive turn extended (M1).

    A sub-turn that reads a new document mints new fakes into the SHARED parent
    mapping. Without a save, those tokens die with the sub-turn's registry entry
    and the parent's next turn can neither reverse them (the delivered result
    would keep raw tokens) nor reuse them (the same value would get a SECOND
    fake — the F1 split-brain the entity layer exists to prevent).

    `save_mapping` is idempotent per mapping_id, so re-saving the shared mapping
    is safe. Best-effort — never raises."""
    if not (mapping_id and session_id):
        return
    try:
        import pseudonymizer as _ps
        m = _ps.get_mapping(mapping_id)
        if m is not None:
            _ps.save_mapping(m, session_id=session_id, turn_id=turn_id or "background")
    except Exception as e:
        print(f"[gdpr] persist failed mapping={mapping_id[:12]}: {e}", flush=True)


def _gdpr_anon_tool_text(text: str, source: str) -> str:
    """APPLY the active transparent-anonymisation mapping to text returned
    from a read-style tool — decision-driven, no fresh detection
    (GDPR_ALL_CHECKS_PRE_DIALOG_PLAN §C).

    Reads `get_request_context()._gdpr_mapping_id` (set per-turn by the chat
    worker / `_apply_bg_context`). No-op when no mapping is active — returns
    text unchanged.

    Detection happened ONCE, pre-dialog (upload-time attachment scan incl.
    the MRZ pass); the mapping holds exactly the values the user CONFIRMED.
    This seam rewrites their occurrences in tool output: fuzzy entity sweep
    (garble / reordered / mixed-case forms of confirmed names — registers
    what it replaced so the args-deanon roundtrip closes) plus the
    word-bounded exact sweep over ALL mapped values. An FP-marked value is
    absent from the mapping and stays in the clear. The same mapping feeds
    `StreamingDeanonymizer`, so every applied token is reversed before the
    user sees the reply.

    When anything was applied, emits an `anonymise_read` synthetic tool-call
    pair on the session's live stream so the chat history shows what got
    pseudonymised mid-turn. Persisted with `synthetic=True`.

    Also runs the classification gate first — if content is classified
    above the per-level threshold AND the active model is non-local, the
    tool read is refused with ClassificationBlockedError before the mapping
    is applied.
    """
    if not text:
        return text
    # Classification gate — runs BEFORE pseudonymisation. Raises
    # ClassificationBlockedError when policy says block; tool dispatcher
    # turns the raise into a JSON tool-error the LLM sees verbatim.
    _classification_gate_tool_text(text, source)
    try:
        mapping_id = get_request_context()._gdpr_mapping_id or ""
    except Exception:
        mapping_id = ""
    if not mapping_id:
        return text
    try:
        import pseudonymizer as _ps
        mapping = _ps.get_mapping(mapping_id)
        if mapping is None:
            return text
        # Reviewed-anonymisation reuse: if the user has already reviewed +
        # anonymised THIS exact content (matched by hash), ship their approved
        # `anon_text` verbatim instead of a fresh scan. We merge the review's
        # saved de-anon entries into the active per-turn mapping so the reply
        # de-anonymiser can still reverse the tokens. Guarded so a non-reviewed
        # file behaves exactly as before (override returns None → fall through).
        _override = _review_anon_override(text, source)
        if _override is not None and _override != text:
            try:
                _row = None
                from server_lib.db import DataReviewDB as _DRB
                from engine import doc_review as _dr
                _uid = get_request_context().current_user_id or ""
                _row = _DRB.get_by_hash(_dr.content_hash(text), _uid, admin=False)
                _rmid = (_row or {}).get("anon_mapping_id") or ""
                if _rmid:
                    _rm = _ps.load_mapping(_rmid)
                    if _rm:
                        for _orig, _fake in _rm.forward.items():
                            if _fake not in mapping.reverse:
                                mapping.forward.setdefault(_orig, _fake)
                                mapping.reverse[_fake] = _orig
                                mapping.categories.setdefault(
                                    _orig, _rm.categories.get(_orig, "unknown"))
            except Exception as _e:
                print(f"[data_review] reuse merge failed: {_e}", flush=True)
            return _override
        _tokens_before = len(mapping.forward)
        # Apply-only: fuzzy entity sweep first (conservative entity_attach,
        # renders whole forms, registers what it replaced), then the
        # word-bounded exact sweep over ALL mapped values (categories=None —
        # a confirmed IBAN/ID in a re-read attachment must rewrite too, not
        # just the entity-derived categories). No _pii_scan_text, no fresh
        # detection mints.
        out, _fuzzy = _ps.apply_entity_variants(text, mapping=mapping)
        out, _swept = _ps.apply_known_values(out, mapping=mapping,
                                             categories=None)
        _swept += _fuzzy
        if not _swept:
            return text
        _tokens_added = len(mapping.forward) - _tokens_before
        # Surface a synthetic anonymise_read row so the UI shows what
        # happened. Best-effort — never block the tool return.
        try:
            sid = get_request_context().current_session_id or ""
            if sid:
                from handlers.chat import emit_gdpr_tool_event_for_session
                _tuid = f"anon_read_{mapping_id[:8]}_{int(time.time()*1000) % 1_000_000}"
                emit_gdpr_tool_event_for_session(
                    sid,
                    kind="anonymise_read",
                    tool_use_id=_tuid,
                    args={"source": source or "tool_output"},
                    result={
                        # Apply-only seam: no fresh detection — `applied` is
                        # the number of rewritten occurrences, tokens_minted
                        # counts derived registrations (fuzzy variants).
                        "applied": _swept,
                        "tokens_minted": _tokens_added,
                        "known_values_swept": _swept,
                        "source": source or "tool_output",
                        "mapping_id": mapping_id,
                    },
                    status="ok",
                    duration_ms=0,
                )
        except Exception:
            pass
        return out
    except Exception:
        # Fail-safe: never leak PII because of a scanner crash. On error,
        # caller surfaces an error; here we conservatively return the
        # original text (the only alternative — return nothing — would
        # silently hide content). The recovery-modal path in the worker
        # already covered the "fail-closed" stance for the user message.
        return text


# ── Web-Egress-Gate (L4 Phase 1, v9.334.0) ──────────────────────────────────
# Guards the args of every web-reaching tool (WEB_SEARCH_TOOLS) in sessions
# with an active transparent-anonymisation mapping. Called from the ONE live
# dispatch choke point (engine/llm_loop.py:dispatch_tool), so interactive,
# background and scheduler turns are all covered. Without this gate the
# combination "auto-anonymise + contact=ignore" ships the real NAME verbatim
# to external search engines (see PII_ANALYSIS_PARITY_HANDOVER.md §5).

# Opaque-token shape minted by pseudonymizer (tolerant of LLM mangling —
# mirrors pseudonymizer's reverse regex).
_PII_WEB_TOKEN_RE = re.compile(r"<\s*\w+_\d+_\w+\s*>")

# Categories the gate does NOT act on. The gate asks "what IS PII", not "what
# is actionable" — the session config may set contact=ignore, which would make
# a findings-driven gate blind to the NAME, the most identifying value.
# business_id (organisation) + network pass so technical queries ("Samsung
# Galaxy S23 EXIF", "ICAO 9303 check digit") never trip the gate — over half
# the queries in the reference chat (58e3c521438a) were technical.
_WEB_GATE_PASS_CATEGORIES = {"business_id", "network"}

_WEB_EGRESS_MODES = ("refuse", "ask", "block_group", "allow")


def _web_gate_strings(obj, out=None) -> list:
    """Collect every string in args, recursively through lists/dicts."""
    if out is None:
        out = []
    if isinstance(obj, str):
        out.append(obj)
    elif isinstance(obj, dict):
        for v in obj.values():
            _web_gate_strings(v, out)
    elif isinstance(obj, (list, tuple)):
        for v in obj:
            _web_gate_strings(v, out)
    return out


def _web_gate_value_variants(value: str) -> set:
    """Normalised surface forms of a protected value for substring matching
    against outgoing web args — lowercase, plus URL-slug separators
    (space → -/_/+/%20; the reference chat leaked the name in a URL SLUG:
    bizapedia.com/people/bonnie-stark.html). For multi-word values the
    first+last token pair is added in both orders so "Bonnie M Stark"
    still catches the slug "bonnie-stark". Values <4 chars are skipped
    (substring noise on house numbers / short IDs)."""
    v = re.sub(r"\s+", " ", (value or "").strip().lower())
    if len(v) < 4:
        return set()
    out = {v}
    if " " in v:
        for sep in ("-", "_", "+", "%20"):
            out.add(v.replace(" ", sep))
        toks = [t for t in re.split(r"[\s,]+", v) if len(t) >= 3]
        if len(toks) >= 2:
            for a, b in ((toks[0], toks[-1]), (toks[-1], toks[0])):
                for sep in ("-", "_", "+", "%20"):
                    out.add(f"{a}{sep}{b}")
    return out


def _web_gate_refusal(blocked_kinds: list, *, fakes: bool,
                      reason: str = "") -> str:
    """Structured, handlungsleitender Tool-Error. Contains value KINDS only —
    the error string goes back to the model, never the values themselves.
    `reason` (ask mode, L4 Phase 2): 'denied' = the user refused/revoked the
    release for at least one value; 'no_consent' = consent was impossible
    (non-interactive turn, timeout, cancel)."""
    if fakes:
        hint = (
            "Die Query enthält pseudonymisierte Werte (Platzhalter/Shape-Fakes). "
            "Eine Websuche damit wäre semantisch leer oder träfe echte FREMDE "
            "Personen (Fake-Namen sind reale Namen) — deren Daten würden die "
            "Analyse vergiften. Suche NIE mit diesen Werten. Optionen: "
            "(1) Die Prüfung im Bericht als 'nicht prüfbar (Datenschutz)' "
            "ausweisen — NIE als 'keine Treffer'. "
            "(2) Die Query ohne den geschützten Wert umformulieren, falls "
            "sinnvoll. Wiederhole den Call NICHT unverändert.")
    elif reason == "denied":
        hint = (
            "Der Nutzer hat die Web-Freigabe für mindestens einen dieser Werte "
            "verweigert oder widerrufen. Respektiere die Entscheidung: "
            "(1) Die Prüfung im Bericht als 'nicht prüfbar (Datenschutz — "
            "Freigabe verweigert)' ausweisen — NIE als 'keine Treffer'. "
            "(2) Die Query ohne den geschützten Wert umformulieren, falls "
            "sinnvoll. Frage NICHT erneut nach einer Freigabe und wiederhole "
            "den Call NICHT unverändert.")
    elif reason == "no_consent":
        hint = (
            "Geschützter Wert in Web-Query; eine Nutzer-Freigabe war nicht "
            "möglich (keine Antwort oder nicht-interaktiver Lauf). Optionen: "
            "(1) Die Prüfung im Bericht als 'nicht prüfbar (Datenschutz)' "
            "ausweisen — NIE als 'keine Treffer'. "
            "(2) Die Query ohne den geschützten Wert umformulieren, falls "
            "sinnvoll. Wiederhole den Call NICHT unverändert.")
    else:
        hint = (
            "Geschützter Wert in Web-Query. Optionen: "
            "(1) Die Prüfung im Bericht als 'nicht prüfbar (Datenschutz)' "
            "ausweisen — NIE als 'keine Treffer'. "
            "(2) Die Query ohne den geschützten Wert umformulieren, falls "
            "sinnvoll. Wiederhole den Call NICHT unverändert.")
    seen, blocked = set(), []
    for k in blocked_kinds:
        if k not in seen:
            seen.add(k)
            blocked.append({"value_kind": k, "released": False})
    return json.dumps({
        "error": "web_query_blocked_pii",
        "blocked": blocked,
        "hint": hint,
    }, ensure_ascii=False)


def _web_release_hash(value: str) -> str:
    """Namespaced value_hash for web-egress consent ledger rows (L4 Phase 2).
    sha256('web|' + normalized value) — value-only (no rule_id: the same value
    re-detected under a different rule must hit the same consent) and
    NAMESPACED so a consent row can never shadow the value's 'anonymise' row
    in get_session_pii_decisions (latest-per-hash wins there, and the wire
    rewrite depends on that row's fake_value)."""
    import hashlib
    norm = re.sub(r"\s+", " ", (value or "").strip().lower())
    return hashlib.sha256(f"web|{norm}".encode("utf-8")).hexdigest()


_WEB_CONSENT_TIMEOUT_S = 300
_WEB_CONSENT_OPT_YES = "Freigeben (für diese Sitzung)"
_WEB_CONSENT_OPT_NO = "Nicht freigeben"


def _web_consent_ask(candidates: dict) -> tuple[set, set, str]:
    """Blocking per-VALUE consent dialog (L4 Phase 2, step (a)).

    ONE AskUserQuestion-style batch covers every protected value of this call —
    consent is per value and session-sticky, so the reference chat's ~15 person
    queries would cost ONE dialog, not fifteen. `candidates` is
    norm(value) → {value, rule_id, fakes}. Returns (granted_norms,
    denied_norms, failure): failure '' when the dialog was decided, else
    'no_consent' (non-interactive turn, timeout, cancel, or already asked
    unanswered this turn). Grants/denials are persisted as
    release_web/deny_web ledger rows (visible + revocable in the GDPR history
    modal); on failure nothing is recorded, so a later turn asks again.

    Uses the ask_user blocking machinery (_ask_user_register + Event, answer
    via POST /v1/chat/answer). Safe here: dispatch runs single-threaded on the
    worker thread, so no ask_user slot can be pending concurrently — and the
    event only reaches the client because run_turn installs
    make_artifact_event_callback (the v9.101.12 failure mode otherwise).
    """
    ctx = get_request_context()
    sid = ctx.current_session_id or ""
    cb = ctx.event_callback
    if not sid or cb is None or ctx.current_bg_task:
        return set(), set(), "no_consent"
    # One unanswered dialog per turn: the model typically retries a refused
    # call immediately — values that already timed out this turn refuse
    # directly instead of re-opening the modal.
    asked = ctx._dynamic.setdefault("_web_consent_asked", set())
    fresh = {k: v for k, v in candidates.items() if k not in asked}
    if not fresh:
        return set(), set(), "no_consent"

    label_map = {}   # question text → candidate key
    questions = []
    for key, slot in sorted(fresh.items()):
        label = PII_RULE_LABELS.get(slot["rule_id"]) or slot["rule_id"] or "Wert"
        q = f"„{slot['value']}“ ({label}) für die Web-Recherche freigeben?"
        if q in label_map:  # question text is the answer key — must be unique
            q = f"{q} ({len(label_map) + 1})"
        label_map[q] = key
        questions.append({"question": q,
                          "options": [_WEB_CONSENT_OPT_YES, _WEB_CONSENT_OPT_NO]})
    payload = {
        "session_id": sid,
        "questions": questions,
        "context_summary": (
            "Datenschutz: Die Web-Recherche möchte geschützte Werte dieser "
            "Sitzung verwenden. Freigaben gelten nur für diese Sitzung, werden "
            "protokolliert und sind im Datenschutz-Verlauf (Schild-Symbol) "
            "widerrufbar. Nicht freigegebene Werte verlassen den Rechner "
            "nicht — die Prüfung wird dann als 'nicht prüfbar (Datenschutz)' "
            "ausgewiesen."),
        "timeout_seconds": _WEB_CONSENT_TIMEOUT_S,
    }
    if len(questions) == 1:
        payload["question"] = questions[0]["question"]
        payload["options"] = questions[0]["options"]

    event = _ask_user_register(sid)
    answers = {}
    try:
        try:
            cb("user_input_needed", payload)
        except Exception:
            return set(), set(), "no_consent"
        from engine.tools.ask_tools import _wait_answer_or_cancel
        got, cancelled = _wait_answer_or_cancel(event, _WEB_CONSENT_TIMEOUT_S)
        if not got:
            if not cancelled:
                asked.update(fresh.keys())
            return set(), set(), "no_consent"
        with _ask_user_lock:
            slot = _ask_user_pending.get(sid) or {}
            got_answers = slot.get("answers")
            single = slot.get("answer")
        if isinstance(got_answers, dict):
            answers.update(got_answers)
        if single is not None and len(questions) == 1:
            answers.setdefault(questions[0]["question"], single)
    finally:
        _ask_user_clear(sid)

    granted, denied = set(), set()
    for q, key in label_map.items():
        ans = str(answers.get(q, "") or "").strip().lower()
        if not ans:
            continue  # unanswered → neither grant nor sticky denial
        if ans.startswith("freigeben") or ans in ("ja", "yes", "y"):
            granted.add(key)
        else:
            denied.add(key)
    try:
        cb("user_input_received", {"session_id": sid, "answers": answers})
    except Exception:
        pass
    # Persist session-sticky consent. A failed write is logged, not fatal:
    # the user's click still governs THIS call; the next turn just asks again.
    try:
        from server_lib.db import ChatDB
        for action, keys in (("release_web", granted), ("deny_web", denied)):
            if keys:
                ChatDB.record_pii_decisions(
                    sid, ctx.current_user_id or "", "", action,
                    [{"rule_id": fresh[k]["rule_id"], "value": fresh[k]["value"],
                      "value_hash": _web_release_hash(fresh[k]["value"]),
                      "source": "web_egress_gate",
                      "disposition": "web-consent"} for k in keys])
    except Exception as e:
        print(f"[web_egress_gate] consent ledger write failed: {e}", flush=True)
    return granted, denied, ""


def _web_release_translate_args(args, pairs: list):
    """Fake→Original rewrite of a web-tool's args for RELEASED values only
    (L4 Phase 2, step (c)). The model keeps thinking in fakes — only the
    OUTGOING request carries the real value; the L3b result seam re-anonymises
    the response on the way back (step (d)), so the model never sees the
    original. Returns a NEW structure — the caller uses it for dispatch only,
    wire/history keep the fakes.

    Slug/case-aware: the model may write the fake as a URL slug
    ("sam-mitchell") — each fake surface form maps to the ALIGNED original
    form ("bonnie-stark"), mirroring _web_gate_value_variants."""
    reps = []
    for fake, orig in pairs:
        f = re.sub(r"\s+", " ", (fake or "").strip())
        o = re.sub(r"\s+", " ", (orig or "").strip())
        if not f or not o:
            continue
        reps.append((f, o))
        if " " in f and " " in o:
            for sep in ("-", "_", "+", "%20"):
                reps.append((f.lower().replace(" ", sep),
                             o.lower().replace(" ", sep)))
            ft = [t for t in re.split(r"[\s,]+", f.lower()) if len(t) >= 3]
            ot = [t for t in re.split(r"[\s,]+", o.lower()) if len(t) >= 3]
            if len(ft) >= 2 and len(ot) >= 2:
                for sep in ("-", "_", "+", "%20"):
                    reps.append((f"{ft[0]}{sep}{ft[-1]}",
                                 f"{ot[0]}{sep}{ot[-1]}"))
                    reps.append((f"{ft[-1]}{sep}{ft[0]}",
                                 f"{ot[-1]}{sep}{ot[0]}"))
    ordered, seen = [], set()
    for f, o in sorted(reps, key=lambda p: -len(p[0])):
        if f.lower() in seen:
            continue  # longest fake form wins; no prefix shadowing
        seen.add(f.lower())
        ordered.append((f, o))

    def _tx(node):
        if isinstance(node, str):
            out = node
            for f, o in ordered:
                out = re.sub(re.escape(f), lambda m, _o=o: _o, out,
                             flags=re.IGNORECASE)
            return out
        if isinstance(node, dict):
            return {k: _tx(v) for k, v in node.items()}
        if isinstance(node, list):
            return [_tx(v) for v in node]
        if isinstance(node, tuple):
            return tuple(_tx(v) for v in node)
        return node

    return _tx(args)


def _gdpr_guard_web_args(tool_name: str, args: dict) -> tuple[str | None, dict]:
    """EGRESS gate: refuse a call that would hand protected session values
    (originals), pseudonyms/tokens (fakes) or fresh person-PII to a third party.

    Name kept for its L4 lineage, but the scope is no longer just the web
    (M2/G7): it guards every tool in `EGRESS_TOOLS` — the web tools PLUS
    email_send/email_reply (the account's SMTP/EWS server), generate_image (api.mistral.ai,
    always, even from a local session) and every MCP tool (arbitrary, possibly
    remote server). See `_is_egress_tool`.

    Returns (refusal, args): `refusal` is an error-JSON string to send back to
    the model (blocked) or None (proceed); `args` is the structure to DISPATCH
    — identical to the input except in ask mode, where released fakes are
    translated back to their originals for the outgoing request only (the
    returned copy must never be persisted; wire/history keep the fakes).
    NEVER raises. Inactive when no anonymisation mapping is active on the
    current request context — non-anonymising sessions are untouched.

    Primary check is against the KNOWN protected values of the session
    (mapping.forward/reverse + pii_decisions ledger), NOT the scanner's
    actionable findings — see _WEB_GATE_PASS_CATEGORIES. A fresh scan with a
    gate-own category policy catches third-person PII never minted before.

    Modes (config.json → gdpr_scanner.web_egress, default 'refuse'):
      refuse / block_group — block originals + fakes (block_group additionally
        hides the web group via exclude_tools at turn setup; this dispatch-side
        refusal stays as defense in depth for paths that skip the worker).
      ask — L4 Phase 2: per-VALUE consent. Released values pass (fakes of
        released originals are translated for the outgoing request); denied
        values refuse without a new dialog; unknown values open ONE consent
        dialog per call (session-sticky outcome in the release_web/deny_web
        ledger, revocable in the GDPR history modal). Non-interactive turns
        (background/scheduler) can't ask → refuse.
      allow — originals pass (audited), fakes are STILL refused (a fake search
        is never useful — it poisons evidence with strangers' data).
    """
    try:
        # M2 (G7): every EGRESS tool, not just the web ones — email_send/reply,
        # generate_image and any MCP tool leave the machine just as irreversibly.
        if not _is_egress_tool(tool_name):
            return None, args
        try:
            mapping_id = get_request_context()._gdpr_mapping_id or ""
        except Exception:
            mapping_id = ""
        if not mapping_id:
            # ── M10(b) / G13: AD-HOC-EGRESS-SCHUTZ OHNE PROJEKT ────────────
            # Der Schutz hing bisher am Projekt-Preset — die Arbeit tut das
            # nicht: die MEHRHEIT der realen KYC-/DD-/Compliance-Chats lief
            # PROJEKTLOS (587a737dc21d, 1a830369e762, 088683fc47bc, …). Kein
            # Preset → kein Turn-1-Auto-Anonymise → kein Mapping → und damit
            # war dieser Gate KOMPLETT AUS: der Klarname ging in Turn 1 an die
            # Suchmaschine, bevor irgendein Schutz greifen konnte.
            #
            # Ohne Mapping gibt es nichts zu über-/rückübersetzen — der
            # FRISCH-SCAN (§3) braucht aber gar keins. Er läuft daher auch
            # hier und refust/fragt bei Personen-PII. Die AUTO-ANONYMISIERUNG
            # bleibt unverändert Modal-/Sticky-gesteuert (M10 ändert NICHT,
            # wann pseudonymisiert wird — nur, wann der EGRESS gegated ist).
            try:
                if not (_get_gdpr_scanner_config() or {}).get("enabled"):
                    return None, args
            except Exception:
                return None, args
        # ab hier: Mapping aktiv ODER Scanner aktiv (Ad-hoc-Schutz)
    except Exception:
        return None, args
    try:
        import pseudonymizer as _ps
        mapping = _ps.get_mapping(mapping_id) if mapping_id else None
        cfg = _get_gdpr_scanner_config()
        mode = cfg.get("web_egress") or "refuse"
        if mode not in _WEB_EGRESS_MODES:
            mode = "refuse"

        raw_haystack = "\n".join(_web_gate_strings(args))
        if not raw_haystack.strip():
            return None, args
        haystack = raw_haystack.lower()

        known_fakes = {}   # fake value → (original or "", rule_id)
        known_origs = {}   # original value → rule_id
        if mapping is not None:
            for orig, fake in mapping.forward.items():
                rid = mapping.categories.get(orig, "unknown")
                known_origs[orig] = rid
                known_fakes[fake] = (orig, rid)
        # Ledger: every value the session EVER decided on (survives restarts
        # and mapping rehydration gaps). FP values are NOT protected — they
        # also suppress fresh-scan re-detection below (the user already said
        # "this is not PII"; the gate must not overrule that per web call).
        fp_norms: set = set()
        sid = ""
        try:
            from server_lib.db import ChatDB
            sid = get_request_context().current_session_id or ""
            if sid:
                for rec in (ChatDB.get_session_pii_decisions(sid) or {}).values():
                    if rec.get("false_positive"):
                        v = re.sub(r"\s+", " ", (rec.get("value") or "").strip().lower())
                        if v:
                            fp_norms.add(v)
                        continue
                    if rec.get("value"):
                        known_origs.setdefault(rec["value"], rec.get("rule_id") or "unknown")
                    if rec.get("fake_value"):
                        known_fakes.setdefault(
                            rec["fake_value"],
                            (rec.get("value") or "", rec.get("rule_id") or "unknown"))
        except Exception:
            pass  # mapping-only coverage is still correct

        # ── Web-release consent state (ask mode, L4 Phase 2) ─────────────
        released_sets: list = []   # variant-sets of released values
        denied_sets: list = []
        if mode == "ask" and sid:
            try:
                from server_lib.db import ChatDB
                for rec in (ChatDB.get_session_web_releases(sid) or {}).values():
                    vset = _web_gate_value_variants(rec.get("value") or "")
                    if not vset:
                        continue
                    (released_sets if rec.get("status") == "released"
                     else denied_sets).append(vset)
            except Exception:
                pass  # no consent state → everything unreleased (conservative)

        def _consent_status(value):
            """'released'/'denied'/None via variant intersection — released
            'Bonnie M Stark' also covers the registered variant 'Bonnie Stark'
            (both contain the first+last slug 'bonnie-stark'). Deny wins when
            two DIFFERENT consents overlap (conservative); for the SAME value
            latest-row-wins already resolved it in the ledger."""
            vset = _web_gate_value_variants(value)
            if not vset:
                return None
            for dset in denied_sets:
                if vset & dset:
                    return "denied"
            for rset in released_sets:
                if vset & rset:
                    return "released"
            return None

        consent: dict = {}   # norm(value) → {value, rule_id, fakes:set}

        def _want_consent(value, rid, fake=None):
            key = re.sub(r"\s+", " ", value.strip().lower())
            slot = consent.setdefault(
                key, {"value": value, "rule_id": rid, "fakes": set()})
            if fake:
                slot["fakes"].add(fake)

        # ── 1) Fakes / opaque tokens ──────────────────────────────────────
        # Default: ALWAYS refuse, every mode (a fake search is semantically
        # empty or hits real strangers). Ask-mode exception (Phase 2, step c):
        # a fake whose ORIGINAL the user released is translated back for the
        # outgoing request instead.
        fake_kinds: list = []
        denied_kinds: list = []
        released_kinds: list = []
        policy_released_kinds: list = []
        translate_pairs: list = []   # (fake, original) — released only
        for fake, (orig, rid) in known_fakes.items():
            if not any(v in haystack for v in _web_gate_value_variants(fake)):
                continue
            # ── M5 (G3): AUTO-RELEASE per stehendem Policy-Consent ──────────
            # Trägt der Fake einen Wert, dessen KATEGORIE die Policy ohnehin
            # passieren lässt (business_id/organisation, network), dann wird er
            # für den ausgehenden Request hin-übersetzt statt refused.
            #
            # Warum das nötig ist (G3 — die Komposition tötete den Use-Case):
            # der Gate liess `organisation` beim Frisch-Scan durch (§3), aber
            # sobald M4 den Firmennamen FAKT, kennt das Modell nur noch den
            # Fake — und Fakes refusten in JEDEM Modus. Jede Einzelkomponente
            # war korrekt, die Komposition machte Firmen-Recherche UNMÖGLICH:
            # der Wert, den die Policy passieren liesse, konnte den Gate nie
            # erreichen. Adverse-Media-, Sanktions- und Registry-Screening über
            # Firmen IST aber der Zweck der betroffenen Projekte.
            #
            # Sicherheit: das Modell sieht das Original NIE — die Übersetzung
            # lebt nur in der Dispatch-Kopie der Args (_web_release_translate_args),
            # und die Ergebnisse kommen durch den L3b-Seam re-anonymisiert
            # zurück. Die Suchmaschine bekommt den Firmennamen, den die Policy
            # ihr ohnehin zugesteht. PERSONEN-Fakes sind unberührt: ihre
            # Kategorie (contact/personal) steht nicht in den Pass-Kategorien,
            # sie refusen weiter in jedem Modus (Regressionstest hält das fest).
            # Der Auto-Release gilt in JEDEM Modus (auch `ask`): die Policy hat
            # für diese Kategorie bereits generell zugestimmt — die Nutzerin
            # jeden Firmennamen einzeln freiklicken zu lassen, wäre eine
            # Rückfrage ohne Entscheidungsgehalt.
            if (orig
                    and PII_RULE_CATEGORIES.get(rid) in _WEB_GATE_PASS_CATEGORIES):
                translate_pairs.append((fake, orig))
                policy_released_kinds.append(rid)
                continue
            if mode == "ask" and orig:
                st = _consent_status(orig)
                if st == "released":
                    translate_pairs.append((fake, orig))
                    released_kinds.append(rid)
                    continue
                if st == "denied":
                    denied_kinds.append(rid)
                    continue
                _want_consent(orig, rid, fake=fake)
                continue
            fake_kinds.append(rid)
        # Opaque tokens not covered above (foreign mapping / LLM-mangled) can
        # never be translated → refuse in every mode.
        for tok in set(_PII_WEB_TOKEN_RE.findall(raw_haystack)):
            if tok not in known_fakes:
                fake_kinds.append("pseudonym_token")
                break
        if fake_kinds:
            _web_gate_audit(tool_name, fake_kinds, mode, kind="fake")
            return _web_gate_refusal(fake_kinds, fakes=True), args

        # ── 2) Known originals → policy decides ──────────────────────────
        orig_kinds: list = []
        for orig, rid in known_origs.items():
            if not any(v in haystack for v in _web_gate_value_variants(orig)):
                continue
            # M5: Pass-Kategorie (Firma/Netz) → stehender Policy-Consent, weder
            # Refusal noch Rückfrage. Spiegelt die Fake-Seite oben; ohne das
            # würde der ECHTE Firmenname (den die Policy zulässt) refused,
            # sobald er je gemappt wurde.
            if PII_RULE_CATEGORIES.get(rid) in _WEB_GATE_PASS_CATEGORIES:
                policy_released_kinds.append(rid)
                continue
            if mode == "ask":
                st = _consent_status(orig)
                if st == "released":
                    released_kinds.append(rid)
                elif st == "denied":
                    denied_kinds.append(rid)
                else:
                    _want_consent(orig, rid)
            else:
                orig_kinds.append(rid)

        # ── 3) Fresh PII (third persons, never-minted values) ────────────
        # Gate-own category policy: "what IS PII", ignoring the session's
        # per-category actions (contact=ignore must not blind the gate to
        # names). Pass-categories stay ignore so technical queries never
        # trip; rule_overrides are dropped for the same reason.
        #
        # BEKANNTE FAKES WERDEN VORHER MASKIERT (M5): Fakes sind shape-
        # preserving und sehen aus wie echte Werte — der Frisch-Scan
        # klassifiziert sie sonst als FRISCHE PII und schickt sie in den
        # Consent-Dialog. Gemessen: der Org-Fake 'Marbach Textil' wurde als
        # PERSONEN-Name (rule=name, category=contact) wiedererkannt und der
        # Auto-Release damit im ask-Modus wieder zunichte gemacht. Über die
        # Fakes ist in §1 bereits entschieden; sie hier erneut zu bewerten wäre
        # eine Doppel-Bewertung mit der falschen Kategorie. Maskiert wird
        # LÄNGENTREU, damit die Offsets des Scans gültig bleiben.
        scan_text_in = raw_haystack
        try:
            for _fk in sorted(known_fakes, key=len, reverse=True):
                if _fk and len(_fk) >= 4 and _fk in scan_text_in:
                    scan_text_in = scan_text_in.replace(_fk, "\x00" * len(_fk))
        except Exception:
            scan_text_in = raw_haystack
        try:
            gate_cfg = dict(cfg)
            gate_cfg["categories"] = {
                cat: {"action": ("ignore" if cat in _WEB_GATE_PASS_CATEGORIES
                                 else "warn")}
                for cat in cfg.get("categories", {})}
            gate_cfg["rule_overrides"] = {}
            for f in _pii_scan_text(scan_text_in, cfg=gate_cfg):
                if f.get("category") in _WEB_GATE_PASS_CATEGORIES:
                    continue
                matched_raw = raw_haystack[
                    f.get("start", 0):f.get("end", 0)].strip()
                matched = re.sub(r"\s+", " ", matched_raw.lower())
                if matched and matched in fp_norms:
                    continue  # user-declared false positive
                rid = f.get("rule_id") or "unknown"
                if mode == "ask" and matched_raw:
                    st = _consent_status(matched_raw)
                    if st == "released":
                        released_kinds.append(rid)
                    elif st == "denied":
                        denied_kinds.append(rid)
                    else:
                        _want_consent(matched_raw, rid)
                else:
                    orig_kinds.append(rid)
        except Exception:
            pass

        # ── ask mode (L4 Phase 2): consent → translate → execute ─────────
        if mode == "ask":
            if denied_kinds:
                _web_gate_audit(tool_name, denied_kinds, mode, kind="denied")
                return _web_gate_refusal(
                    denied_kinds, fakes=False, reason="denied"), args
            if consent:
                granted, denied, failure = _web_consent_ask(consent)
                if failure:
                    kinds = [c["rule_id"] for c in consent.values()]
                    _web_gate_audit(tool_name, kinds, mode, kind="original")
                    return _web_gate_refusal(
                        kinds, fakes=False, reason=failure), args
                if denied:
                    kinds = [consent[k]["rule_id"] for k in denied]
                    _web_gate_audit(tool_name, kinds, mode, kind="denied")
                    return _web_gate_refusal(
                        kinds, fakes=False, reason="denied"), args
                leftover = set(consent) - granted
                if leftover:  # unanswered questions → not released
                    kinds = [consent[k]["rule_id"] for k in leftover]
                    _web_gate_audit(tool_name, kinds, mode, kind="original")
                    return _web_gate_refusal(
                        kinds, fakes=False, reason="no_consent"), args
                for k in granted:
                    slot = consent[k]
                    released_kinds.append(slot["rule_id"])
                    for fake in slot["fakes"]:
                        translate_pairs.append((fake, slot["value"]))
            if translate_pairs:
                args = _web_release_translate_args(args, translate_pairs)
            if released_kinds:
                _web_gate_audit(tool_name, released_kinds, mode,
                                kind="released")
            if policy_released_kinds:
                _web_gate_audit(tool_name, policy_released_kinds, mode,
                                kind="policy_released")
            return None, args

        # ── non-ask modes (Phase-1 semantics) ────────────────────────────
        # M5: der Auto-Release gilt in JEDEM Modus — die Hin-Übersetzung muss
        # daher auch hier laufen (vorher hing sie im ask-only-Zweig fest).
        # WICHTIG: nur auf den DURCHLASS-Pfaden übersetzen. Ein Refusal darf
        # die übersetzten (= echten) Args NICHT zurückgeben — der Aufrufer
        # verwirft sie zwar, aber ein Security-Gate reicht Klarwerte nicht auf
        # einem Pfad heraus, auf dem es gerade "nein" sagt.
        if orig_kinds and mode != "allow":
            _web_gate_audit(tool_name, orig_kinds, mode, kind="original")
            return _web_gate_refusal(orig_kinds, fakes=False), args
        if translate_pairs:
            args = _web_release_translate_args(args, translate_pairs)
        if policy_released_kinds:
            _web_gate_audit(tool_name, policy_released_kinds, mode,
                            kind="policy_released")
        if orig_kinds:   # mode == "allow"
            _web_gate_audit(tool_name, orig_kinds, mode, kind="allowed")
        return None, args
    except Exception as e:
        # Fail CLOSED: a mapping is active (checked above), so an unexpected
        # gate crash must not silently open the egress path (CLAUDE.md rule 12).
        print(f"[web_egress_gate] gate error, failing closed: {e}", flush=True)
        return json.dumps({
            "error": "web_query_blocked_pii",
            "blocked": [{"value_kind": "gate_error", "released": False}],
            "hint": "Interner Fehler im Web-Egress-Gate — Web-Zugriff für "
                    "diesen Call vorsorglich verweigert. Weise die Prüfung im "
                    "Bericht als 'nicht prüfbar (Datenschutz)' aus.",
        }, ensure_ascii=False), args


def _gdpr_scan_cloud_egress(text: str, *, tool_name: str) -> str | None:
    """M2 (G7): PII check for tools that reach the cloud REGARDLESS of the
    session model — today `generate_image` (always api.mistral.ai).

    Every other guard in the system is conditioned on an active anonymisation
    mapping, which is a proxy for "this session talks to a cloud model". That
    proxy is FALSE for these tools: they egress from a LOCAL session too, where
    anonymisation never ran and there is no mapping to gate on. Session
    5175bf8fdf70 posted a family tree (incl. deceased status) to Mistral from a
    local session for exactly this reason.

    Returns a refusal string (to hand back to the model) or None to proceed.
    Independent of the mapping; driven by the scanner's own confidence
    disposition, so an admin who set the category to `ignore` is still obeyed.

    NEVER raises — a scanner bug must not take image generation down; it falls
    open (returns None), consistent with every other scan seam.
    """
    if not text:
        return None
    try:
        cfg = _get_gdpr_scanner_config()
        if not cfg.get("enabled", True):
            return None
        findings = _pii_scan_text(text, cfg=cfg)
        if not findings:
            return None
        # Same confidence-band logic the background gate uses: 'ignore' → nothing
        # to enforce. We do NOT re-implement a policy here.
        if _pii_worst_disposition(findings, cfg) == "ignore":
            return None
        kinds = sorted({(f.get("rule_id") or "unknown") for f in findings})
    except Exception:
        return None

    try:
        _ctx = get_request_context()
        _d = _ctx._gdpr_degradation
        if _d is None:
            _d = {}
            _ctx._gdpr_degradation = _d
        _d["cloud_egress_blocked"] = int(_d.get("cloud_egress_blocked", 0)) + 1
    except Exception:
        pass
    try:
        if _audit_log:
            _audit_log.log_action(
                agent=(get_request_context().current_agent.agent_id
                       if get_request_context().current_agent else "main"),
                action_type="pii_blocked",
                tool_name=tool_name,
                args_summary=f"kinds={','.join(kinds)}",
                result_summary="cloud egress refused (tool always hits the cloud)",
                result_status="blocked",
                session_id=(get_request_context().current_session_id or None),
                source="tool",
            )
    except Exception:
        pass

    return json.dumps({
        "error": "cloud_egress_blocked_pii",
        "tool": tool_name,
        "value_kinds": kinds,
        "hint": (
            f"'{tool_name}' sendet den Prompt IMMER an einen Cloud-Dienst "
            "(api.mistral.ai) — auch aus einer lokalen Sitzung. Der Prompt "
            "enthält personenbezogene Daten und wurde deshalb NICHT gesendet. "
            "Formuliere den Prompt ohne personenbezogene Werte (Platzhalter wie "
            "'Person A' statt echter Namen) und rufe das Tool erneut auf."),
    }, ensure_ascii=False)


def _web_gate_audit(tool_name: str, kinds: list, mode: str, *, kind: str) -> None:
    """Audit row per gate decision — kinds only, never values.
    kind: fake/original (refused) · denied (user refused/revoked the release)
    · allowed (allow mode) · released (ask mode, user-released values left the
    machine — possibly translated fake→original) · policy_released (M5: the
    category is one the policy passes anyway — auto-translated fake→original
    for the outgoing request, no dialog)."""
    # L7b: tally the decision on the request context so the worker can surface
    # a per-turn "Datenschutz"-strip (metadata.gdpr_degradation) explaining
    # WHY the output differs. Counts only, never values.
    _PASSED = ("allowed", "released", "policy_released")
    try:
        _ctx = get_request_context()
        _d = _ctx._gdpr_degradation
        if _d is None:
            _d = {}
            _ctx._gdpr_degradation = _d
        _key = ("web_released" if kind == "released"
                else "web_policy_released" if kind == "policy_released"
                else "web_allowed" if kind == "allowed"
                else "web_denied" if kind == "denied"
                else "web_blocked")
        _d[_key] = int(_d.get(_key, 0)) + 1
    except Exception:
        pass
    if not _audit_log:
        return
    try:
        _audit_log.log_action(
            agent=(get_request_context().current_agent.agent_id
                   if get_request_context().current_agent else "main"),
            action_type=("pii_web_egress" if kind in _PASSED
                         else "pii_web_blocked"),
            tool_name=tool_name,
            args_summary=f"kinds={sorted(set(kinds))} mode={mode} match={kind}",
            result_summary="",
            result_status=("warning" if kind in _PASSED
                           else "blocked"),
            session_id=get_request_context().current_session_id or None,
            source="web_egress_gate",
        )
    except Exception:
        pass


# ── Args-Deanonymisierung am Dispatch (L3a, Dispatch-Symmetrie) ─────────────
# The model thinks in fakes, the tools work on raw data — neither must know
# about the other. For LOCALLY-executing tools the pseudonyms/tokens in the
# args are translated back to the real values right before execution (the
# results re-anonymise on the way back through _gdpr_anon_tool_text). This is
# what makes mempalace_query find drawers again, read_document open paths
# whose filename contains the real name, and python_exec run value-literals
# against the real bytes (failure class F3 in PII_ANALYSIS_PARITY_HANDOVER.md).
#
# THE most important invariant of L3: WEB TOOLS ARE NEVER IN THIS SET.
# Deanonymising a web-tool arg would be silent egress of the protected value
# — exactly what the web-egress gate (_gdpr_guard_web_args, L4) exists to
# prevent. Guarded by tests/test_dispatch_symmetry.py.
GDPR_ARGS_DEANON_TOOLS = frozenset({
    "mempalace_query", "mempalace_kg_query", "mempalace_kg_search",
    "mempalace_kg_neighbors",
    "read_document", "read_file", "list_directory", "search_files",
    "execute_command", "python_exec",
    "ocr_inspect", "ocr_extract", "ocr_region", "ocr_fields", "ocr_tables",
    "xlsx_inspect", "xlsx_query", "xlsx_create", "xlsx_edit", "xlsx_diff",
    "text_diff", "data_query", "db_query", "rest_query",
    "mrz_verify", "doc_dates_check", "identity_consistency",
    # M3 (G9) — the LLM Wiki is LOCAL storage, so what lands on disk must be the
    # REAL values, not the model's fakes.
    #
    # Without this, `wiki_write` persisted whatever the model typed — i.e. FAKES —
    # into the wiki and mirrored them into the MemPalace wings. The mapping is
    # per-SESSION, so session B later read session A's fakes as if they were facts:
    # not reversible (B's mapping doesn't know those tokens) and not consistent
    # with B's own fakes for the same real person. That is permanent memory
    # poisoning, and it gets worse with every session.
    #
    # Writing real values also makes the READ side trivially correct: wiki_read's
    # result seam (below) pseudonymises on the way back out, exactly like
    # read_document. Local storage holds truth; the wire holds fakes.
    "wiki_write",
    # M3 (G10): the lossless-context DAG stores ORIGINAL text, so a recall must be
    # able to look up the real value — and its result is re-anonymised by the seam.
    "context_search", "context_detail", "context_recall",
    # M7 / decision 2: the diagram renderer runs LOCALLY (no egress), so the
    # rendered image should carry REAL values — matching the .docx/.html written
    # beside it, which the after-file-write reverse already restores. Otherwise the
    # delivered report has real text and fake diagrams: self-contradictory, with no
    # warning. Cheapest correct fix — no lint, no warning strip; the artifact is
    # just right.
    "render_diagram",
})

# execute_command/python_exec hardening — DENY BY DEFAULT (M2/G7).
#
# These two tools get real values injected into their args (that's the point of
# L3a: `grep <real name> file.csv` must work). But a shell command or script can
# also reach the network itself, and then the de-anonymisation IS the leak — a
# side door around the egress gate.
#
# This used to be an ALLOW-list-by-omission: deanonymise unless one of ~15 network
# markers appeared. That is structurally lost against a creative agent, and the
# misses were not hypothetical — session b4edbc9dc8e7 has the model reaching for
# `mail -s "IBAN <fake>" <EMAIL_1_8d62>` and `sendmail … <<< …`. Neither `mail`
# nor `sendmail` nor `msmtp` nor `osascript` (drives Apple Mail/Messages) nor `gh`
# was in the blocklist. Back then it failed on zsh syntax; with L3a's args-deanon
# in place it would have sent a REAL IBAN to a stranger.
#
# Inverted: a string is de-anonymised ONLY if it looks recognisably LOCAL. Anything
# we cannot positively vouch for keeps its fakes — which can never leak, and at
# worst means a tool sees a pseudonym (it may miss data; it cannot exfiltrate).
#
# The old blocklist is KEPT as a fast, loud reject (a positive network signal is
# worth logging distinctly from "unrecognised"), but it is no longer the decision.
_DEANON_NETWORK_MARKER_RE = re.compile(
    r"https?://|\b(?:curl|wget|nc|ncat|socat|ssh|scp|sftp|rsync|telnet|ftp"
    r"|nslookup|dig|ping|host)\b"
    r"|urllib|requests\.|http\.client|socket\.|aiohttp|httpx"
    # M2: the mail/automation side doors the blocklist never had. b4edbc9dc8e7
    # had the model reaching for `mail -s …` and `sendmail`; neither was listed.
    r"|smtplib|\b(?:sendmail|mail|mailx|msmtp|mutt|osascript|gh|scutil)\b"
    r"|\bopen\s+-a\b"                       # macOS `open -a Mail` (not py open())
    r"|smtp\.|imaplib|poplib|paramiko|ftplib|telnetlib|webbrowser"
    # Indirect execution — a python_exec script's only remaining way out is to
    # shell out or to resolve a module dynamically. Both are denied.
    r"|subprocess|os\.system|os\.popen|os\.exec|commands\.|pty\.|multiprocessing"
    r"|__import__|importlib|\beval\b|\bexec\b|compile\s*\("
    r"|/dev/tcp|/dev/udp"                   # bash network redirection
    , re.IGNORECASE)

# A command/script is de-anonymised only when EVERY token we can see is one of
# these — i.e. it is unambiguously a local data operation. Deliberately narrow:
# the cost of a false negative is "the tool sees a pseudonym"; the cost of a
# false positive is a silent, irreversible leak. Widen only with a concrete,
# reviewed use case.
_DEANON_LOCAL_SAFE_RE = re.compile(
    r"^[\s\w\-./\\:~'\"=,;|()\[\]{}*+@#%^&!?$<>\n\r]*$"
)

# Commands/functions that read or transform LOCAL data. A string qualifies as
# local-safe only if it contains no network marker AND its executable-looking
# tokens are all in here (or it has none at all — e.g. a bare path or a value).
_DEANON_LOCAL_COMMANDS = frozenset({
    # shell: read/search/transform
    "cat", "head", "tail", "less", "more", "grep", "egrep", "fgrep", "rg",
    "awk", "sed", "cut", "sort", "uniq", "wc", "tr", "tee", "xargs", "find",
    "ls", "stat", "file", "du", "df", "basename", "dirname", "realpath",
    "echo", "printf", "test", "diff", "cmp", "md5", "shasum", "sha256sum",
    "jq", "yq", "column", "paste", "join", "comm", "split", "nl", "rev",
    "cp", "mv", "mkdir", "touch", "chmod", "ln", "pwd", "cd", "true", "false",
    "unzip", "zip", "tar", "gzip", "gunzip", "zcat", "iconv", "base64",
    # python: local data work
    "python", "python3", "pandas", "pd", "numpy", "np", "json", "csv", "re",
    "openpyxl", "pathlib", "os", "sys", "math", "statistics", "collections",
    "datetime", "itertools", "print", "open", "len", "str", "int", "float",
    "list", "dict", "set", "sorted", "sum", "min", "max", "range", "enumerate",
    "zip", "map", "filter", "abs", "round", "type", "isinstance", "repr",
})

# Python `import X` / `from X import …` — the MODULE is what matters, not the
# `import` keyword. Checked first so the shell-token pass below skips these lines.
_DEANON_IMPORT_RE = re.compile(
    r"^\s*(?:import|from)\s+([A-Za-z_][\w.]*)", re.MULTILINE)

# Tokens in COMMAND position: start of a line/string, or right after a shell
# separator (`;` `|` `&&`). An assignment (`df = …`) is not a command, so a token
# followed by `=` (but not `==`) is skipped.
#
# `\b` after the capture is load-bearing: without it the engine BACKTRACKS to a
# shorter token to satisfy the negative lookahead — `df = …` matched as `d`, which
# isn't in the allowlist, so every pandas script was wrongly denied.
_DEANON_CMD_TOKEN_RE = re.compile(
    r"(?:^|[\n;|&])\s*([A-Za-z_][\w.-]*)\b(?!\s*=[^=])", re.MULTILINE)


def _deanon_string_is_local_safe(s: str, *, tool_name: str = "") -> bool:
    """M2 (G7): may this execute_command/python_exec string receive REAL values?

    Deny-by-default. The two tools need DIFFERENT tests, because the thing that
    can exfiltrate is different:

    * **python_exec** — a Python script. The only way out is a networked
      module/call, so the test is: no network marker anywhere, and every `import`
      is a known-local module. Trying to allowlist "command tokens" in Python is a
      category error (`df = …`, `for r in …`, `print(…)` are not commands) and was
      denying every pandas/openpyxl analysis — i.e. trading this wave's leak fix
      for a silent quality regression, which is precisely what the wave exists to
      prevent.

    * **execute_command** — a shell line. Here the executable IS the risk, so the
      command-position tokens must all be known-local (`grep`, `awk`, `cat`, …).
      An unrecognised binary could be anything.

    Unrecognised → False → the string keeps its fakes (safe direction: the tool may
    miss data, it cannot leak).
    """
    if not s or not isinstance(s, str):
        return False
    # Applies to BOTH: any positive network signal is an immediate no.
    if _DEANON_NETWORK_MARKER_RE.search(s):
        return False
    # Every imported module must be a known-local one (both tools: a shell line
    # can carry `python3 -c "import smtplib"`).
    for m in _DEANON_IMPORT_RE.finditer(s):
        if m.group(1).split(".", 1)[0].lower() not in _DEANON_LOCAL_COMMANDS:
            return False

    if tool_name == "python_exec":
        # Script body: the import check above + the network markers are the test.
        # No command-token pass (see docstring).
        return True

    # execute_command (and anything unknown): the stricter shell test.
    if not _DEANON_LOCAL_SAFE_RE.match(s):
        return False  # exotic characters (backticks, $(), unicode pipes …)
    for m in _DEANON_CMD_TOKEN_RE.finditer(s):
        tok = (m.group(1) or "").strip()
        if not tok:
            continue
        head = tok.split(".", 1)[0].lower()
        if head in ("import", "from"):
            continue  # handled by _DEANON_IMPORT_RE above
        if head not in _DEANON_LOCAL_COMMANDS:
            return False
    return True


def _gdpr_deanon_tool_args(tool_name: str, args: dict):
    """L3a: translate pseudonyms in tool args back to real values for the
    whitelisted LOCALLY-executing tools. Returns a NEW args structure (the
    caller's dict — and thus the wire/history — keeps the model's fakes).

    No-op (returns `args` unchanged) when the tool is not whitelisted, no
    anonymisation mapping is active, or anything fails — fail direction is
    "tool runs with fakes" (may miss data, can never leak).
    """
    try:
        if tool_name not in GDPR_ARGS_DEANON_TOOLS or not isinstance(args, dict):
            return args
        try:
            mapping_id = get_request_context()._gdpr_mapping_id or ""
        except Exception:
            mapping_id = ""
        if not mapping_id:
            return args
        import pseudonymizer as _ps
        mapping = _ps.get_mapping(mapping_id)
        if mapping is None or not mapping.reverse:
            return args
        # M2 (G7): shell/script args are DENY-BY-DEFAULT — a string only receives
        # real values when it is recognisably a local data operation. See
        # `_deanon_string_is_local_safe`.
        guard_network = tool_name in ("execute_command", "python_exec")

        def _walk(v):
            if isinstance(v, str):
                if guard_network and not _deanon_string_is_local_safe(
                        v, tool_name=tool_name):
                    return v
                out, n = _ps.deanonymize_text(v, mapping=mapping)
                return out if n else v
            if isinstance(v, list):
                return [_walk(x) for x in v]
            if isinstance(v, dict):
                return {k: _walk(x) for k, x in v.items()}
            return v

        return _walk(args)
    except Exception as e:
        print(f"[args_deanon] failed for {tool_name}, running with fakes: {e}",
              flush=True)
        return args


# L5b: attachment types worth an MRZ-targeted OCR pass (photographed/scanned
# ID documents arrive as images or scan-PDFs; _load_pages handles both).
_MRZ_SEED_EXTS = (".png", ".jpg", ".jpeg", ".tif", ".tiff", ".bmp",
                  ".webp", ".gif", ".pdf")


def _gdpr_seed_entities_from_attachments(paths: list[str], mapping) -> int:
    """L5b — MRZ entity seed. For each image/PDF attached THIS turn, run the
    MRZ-targeted OCR pass (doc_checks._ocr_mrz_strip: char-whitelist
    tesseract — the generic OCR yields zero parseable MRZ data lines on
    photos) and, when the parse carries at least one VERIFYING ICAO-9303
    checksum, seed the pseudonymizer entity map: name + standard variants,
    document number (bare + 10-char check-digit form), DOB surface forms.
    Runs BEFORE the turn's text scan so the OCR preamble block (L5a) and
    every later read_document/tool result render onto ONE consistent fake
    identity — incl. OCR-garble forms that only the fuzzy entity attach
    catches. Returns the number of documents that seeded anything; never
    raises (a failed seed just means scan-only anonymisation, as before).
    """
    parses: list[tuple[int, str, dict]] = []
    for p in paths or []:
        try:
            if os.path.splitext(p)[1].lower() not in _MRZ_SEED_EXTS:
                continue
            from engine.tools.doc_checks import _ocr_mrz_strip, parse_mrz
            strip = _ocr_mrz_strip(p)
            parsed = parse_mrz(strip) if strip.strip() else None
            if not parsed:
                continue
            checks = parsed.get("checks") or {}
            n_ok = sum(1 for v in checks.values() if v)
            if not n_ok:
                continue  # no verifying checksum → don't trust the read
            parses.append((n_ok, p, parsed))
        except Exception as e:
            print(f"[mrz_seed] skipped {os.path.basename(p)}: {e}", flush=True)
            continue
    # Best-verified read FIRST: the entity must come from the cleanest scan,
    # never from a garbled photo of the same document (measured on the
    # reference set: sorted-by-filename order let a 1-checksum photo seed
    # 'BONNTIMARTI' before the 5-checksum CF scan — same failure class the
    # L2 text-order seeding fixed). A second read of an already-seeded
    # document NUMBER may enrich but never create an entity.
    parses.sort(key=lambda t: -t[0])
    seeded = 0
    seen_numbers: set[str] = set()
    for _n_ok, p, parsed in parses:
        try:
            num = (parsed.get("document_number") or "").strip()
            import pseudonymizer as _ps
            res = _ps.seed_identity_from_mrz(
                mapping, parsed,
                allow_new_entity=num not in seen_numbers)
            if num and (parsed.get("checks") or {}).get("document_number"):
                seen_numbers.add(num)
            if any(res.values()):
                seeded += 1
                if _audit_log:
                    try:
                        _audit_log.log_action(
                            agent=(get_request_context().current_agent.agent_id
                                   if get_request_context().current_agent
                                   else "main"),
                            action_type="pii_mrz_seed",
                            tool_name="",
                            # kinds + extension only — an attachment FILENAME
                            # often carries the real name (audit rows never
                            # hold values, same rule as the web gate).
                            args_summary=(
                                f"file=*{os.path.splitext(p)[1].lower()} "
                                f"seeded="
                                f"{sorted(k for k, v in res.items() if v)}"),
                            result_summary="",
                            result_status="success",
                            session_id=(get_request_context().current_session_id
                                        or None),
                            source="mrz_entity_seed",
                        )
                    except Exception:
                        pass
        except Exception as e:
            print(f"[mrz_seed] skipped {os.path.basename(p)}: {e}", flush=True)
            continue
    return seeded


def _mrz_findings_from_parse(parsed: dict) -> list[dict]:
    """Turn a checksum-plausible MRZ parse into ORDINARY, markable findings
    for the pre-send dialog (GDPR_ALL_CHECKS_PRE_DIALOG_PLAN §A): synthetic
    rule_ids `mrz_name` / `mrz_passport` / `mrz_dob` carrying the real
    surface value, rendered in the dialog with an FP checkbox like any
    scanner finding. Detection only — nothing is minted here; the worker
    mints from the CONFIRMED decision set (`pseudonymizer.seed_from_decision`).

    Per-field honesty gates mirror `seed_identity_from_mrz` exactly (name
    needs ≥2 verifying checksums, number/DOB their own checksum) so the
    dialog surfaces precisely what the seed would have trusted."""
    if not parsed:
        return []
    checks = parsed.get("checks") or {}
    n_verified = sum(1 for v in checks.values() if v)
    if not n_verified:
        return []
    cfg = _get_gdpr_scanner_config()
    out: list[dict] = []

    def _mk(rule_id: str, value: str) -> dict:
        return {
            "rule_id": rule_id,
            "label": PII_RULE_LABELS.get(rule_id, rule_id),
            "category": PII_RULE_CATEGORIES.get(rule_id, "personal"),
            "action": _pii_effective_action(rule_id, cfg),
            # Checksum-verified machine read — always the high band.
            "confidence": 0.95,
            "value": value,
        }

    sur = (parsed.get("surname") or "").strip()
    giv = (parsed.get("givens") or "").strip()
    if sur and giv and n_verified >= 2:
        form = " ".join(t.title() for t in f"{giv} {sur}".split())
        out.append(_mk("mrz_name", form))
    number = (parsed.get("document_number") or "").strip()
    if number and checks.get("document_number"):
        out.append(_mk("mrz_passport", number))
    dob = parsed.get("dob")
    import datetime as _dt_mod
    if isinstance(dob, _dt_mod.date) and checks.get("dob"):
        out.append(_mk("mrz_dob", dob.isoformat()))
    return out


def _route_to_node(tool_name: str, args: dict) -> str | None:
    """If args contain 'node', route to remote node via server API. Returns result string or None for local."""
    node = args.pop("node", None)
    if not node:
        return None
    try:
        import urllib.request
        body = json.dumps({"node": node, "tool": tool_name, "params": args}).encode("utf-8")
        req = urllib.request.Request(
            "http://127.0.0.1:8420/v1/nodes/execute",
            data=body,
            headers={"Content-Type": "application/json"},
            method="POST",
        )
        with urllib.request.urlopen(req, timeout=300) as resp:
            result = json.loads(resp.read().decode("utf-8"))
        if "error" in result:
            return _err(f"Node '{node}': {result['error']}")
        return _ok(result)
    except Exception as e:
        return _err(f"Node routing error: {e}")


