def get_tool_config() -> dict:
    """Load tool configuration from tools_config.json, falling back to defaults."""
    cfg = {}
    if os.path.exists(_TOOLS_CONFIG_PATH):
        try:
            with open(_TOOLS_CONFIG_PATH) as f:
                cfg = json.load(f)
        except (json.JSONDecodeError, OSError):
            cfg = {}
    # Merge with defaults (defaults provide missing keys)
    merged = {}
    for tool_name, defaults in _TOOLS_CONFIG_DEFAULTS.items():
        tool_cfg = cfg.get(tool_name, {})
        merged[tool_name] = {**defaults, **tool_cfg}
    return merged


def _searxng_base_url() -> str:
    """Single source of truth for the SearXNG base URL used by searxng_search.

    The bundled self-hosted instance is managed by the SearxngSupervisor and
    binds to `config.json -> searxng.url`; the tool talks to that same
    instance. An admin can still point at an EXTERNAL SearXNG by setting
    `tools_config.searxng_search.url` (override) — but the common case needs
    no tool config at all. Returns "" if neither is configured."""
    override = (get_tool_config().get("searxng_search", {}).get("url") or "").strip()
    if override:
        return override.rstrip("/")
    inst = ""
    try:
        import sys as _sys
        for _name in ("__main__", "server"):
            _srv_mod = _sys.modules.get(_name)
            _sc = getattr(_srv_mod, "server_config", None) if _srv_mod else None
            if _sc:
                inst = (_sc.get("searxng") or {}).get("url") or ""
                break
    except Exception:
        inst = ""
    return inst.rstrip("/")


def _crawl4ai_base_url() -> str:
    """Base URL of the bundled crawl4ai render service (managed by
    Crawl4aiSupervisor), from `config.json -> crawl4ai.url`. "" if absent."""
    try:
        import sys as _sys
        for _name in ("__main__", "server"):
            _srv_mod = _sys.modules.get(_name)
            _sc = getattr(_srv_mod, "server_config", None) if _srv_mod else None
            if _sc:
                return ((_sc.get("crawl4ai") or {}).get("url") or "").rstrip("/")
    except Exception:
        pass
    return ""


def _server_config() -> dict:
    """The live `server_config` dict, resolved off the SINGLETON server module.

    Under launchd the running server is `sys.modules['__main__']`; a bare
    `import server` yields a SECOND module instance whose `server_config` is the
    bare module-level default (no `auto_route`/`chat_summary_model`/etc.). This
    is the v9.45.1 footgun. Resolve `__main__` first (then plain `server`) so
    readers see the config `main()` actually populated. Returns {} if neither is
    available (e.g. unit tests importing brain alone)."""
    try:
        for _name in ("__main__", "server"):
            _srv_mod = sys.modules.get(_name)
            _sc = getattr(_srv_mod, "server_config", None) if _srv_mod else None
            if _sc:
                return _sc
    except Exception:
        pass
    return {}


def _crawl4ai_render(url: str, timeout_s: float = 45.0) -> dict:
    """Render a URL via the crawl4ai headless service → {success, markdown,
    length, error}. Used as a FALLBACK when the cheap HTTP fetch returns an
    empty / JS-shell result. Degrades gracefully: if the service isn't
    configured or is unreachable, returns success=False so the caller keeps
    today's behavior (raw HTTP result) rather than failing the fetch."""
    base = _crawl4ai_base_url()
    if not base:
        return {"success": False, "markdown": "", "error": "render service not configured"}
    try:
        import urllib.request, json as _json
        req = urllib.request.Request(
            base + "/render",
            data=_json.dumps({"url": url}).encode("utf-8"),
            headers={"Content-Type": "application/json"},
            method="POST")
        with urllib.request.urlopen(req, timeout=timeout_s) as resp:
            return _json.loads(resp.read().decode("utf-8"))
    except Exception as e:
        return {"success": False, "markdown": "", "error": f"{type(e).__name__}: {e}"}


def _crawl4ai_render_stealth(url: str, timeout_s: float = 75.0) -> dict:
    """SECOND-fallback render via Scrapling's StealthyFetcher (stealth Firefox,
    Cloudflare Turnstile/Interstitial bypass), served by the SAME crawl4ai
    render service on POST /render_stealth → {success, markdown, length, error}.
    Tried only after the plain crawl4ai headless render still comes back thin /
    blocked. Same graceful degradation as _crawl4ai_render: an unconfigured or
    unreachable service (or a venv without scrapling) returns success=False so
    the caller keeps the best result it already has. Longer default timeout —
    a stealth fetch that solves a Cloudflare challenge is slower than a plain
    headless render."""
    base = _crawl4ai_base_url()
    if not base:
        return {"success": False, "markdown": "", "error": "render service not configured"}
    try:
        import urllib.request, json as _json
        req = urllib.request.Request(
            base + "/render_stealth",
            data=_json.dumps({"url": url}).encode("utf-8"),
            headers={"Content-Type": "application/json"},
            method="POST")
        with urllib.request.urlopen(req, timeout=timeout_s) as resp:
            return _json.loads(resp.read().decode("utf-8"))
    except Exception as e:
        return {"success": False, "markdown": "", "error": f"{type(e).__name__}: {e}"}


def _crawl4ai_pdf(html: str, timeout_s: float = 60.0) -> dict:
    """Print a raw HTML string to PDF via the render service's Chromium
    (POST /pdf, Design-Modus Phase C) → {success, pdf_b64, error}. Same
    graceful degradation as _crawl4ai_render: unconfigured/unreachable
    service → success=False with a clear error, no fallback rendering."""
    base = _crawl4ai_base_url()
    if not base:
        return {"success": False, "pdf_b64": "", "error": "render service not configured"}
    try:
        import urllib.request, json as _json
        req = urllib.request.Request(
            base + "/pdf",
            data=_json.dumps({"html": html}).encode("utf-8"),
            headers={"Content-Type": "application/json"},
            method="POST")
        with urllib.request.urlopen(req, timeout=timeout_s) as resp:
            return _json.loads(resp.read().decode("utf-8"))
    except Exception as e:
        return {"success": False, "pdf_b64": "", "error": f"{type(e).__name__}: {e}"}


def _crawl4ai_screenshots(html: str, selector: str = "", width: int = 1280,
                          height: int = 720, timeout_s: float = 120.0) -> dict:
    """Screenshot each element matching `selector` in a rendered raw HTML
    string (POST /screenshot; deck export: one PNG per <section data-slide>),
    or the full page without a selector → {success, images: [b64,...], count,
    error}. Graceful degradation like _crawl4ai_pdf."""
    base = _crawl4ai_base_url()
    if not base:
        return {"success": False, "images": [], "error": "render service not configured"}
    try:
        import urllib.request, json as _json
        req = urllib.request.Request(
            base + "/screenshot",
            data=_json.dumps({"html": html, "selector": selector,
                              "width": width, "height": height}).encode("utf-8"),
            headers={"Content-Type": "application/json"},
            method="POST")
        with urllib.request.urlopen(req, timeout=timeout_s) as resp:
            return _json.loads(resp.read().decode("utf-8"))
    except Exception as e:
        return {"success": False, "images": [], "error": f"{type(e).__name__}: {e}"}


def save_tool_config(cfg: dict) -> dict:
    """Save tool configuration to tools_config.json. Returns saved config."""
    # Merge with existing to preserve fields not in the incoming payload
    existing = get_tool_config()
    for tool_name, tool_cfg in cfg.items():
        if tool_name in existing:
            existing[tool_name].update(tool_cfg)
        else:
            existing[tool_name] = tool_cfg
    try:
        with open(_TOOLS_CONFIG_PATH, "w") as f:
            json.dump(existing, f, indent=2)
    except OSError as e:
        return {"error": str(e)}
    return existing


def migrate_gmail_to_email_config() -> bool:
    """ONE-TIME boot migration (Email-Tools v2, E4): fold the legacy `gmail`
    integration record (+ the agents/main/gmail.json fallback it shadowed)
    into the new multi-account `email` record — one IMAP account with the
    gmail preset. Idempotent: no-op as soon as an `email` record exists on
    disk. The legacy `gmail` key is removed (get_tool_config would drop it
    from the merged view anyway once the defaults key is gone)."""
    raw = {}
    if os.path.exists(_TOOLS_CONFIG_PATH):
        try:
            with open(_TOOLS_CONFIG_PATH) as f:
                raw = json.load(f)
        except (json.JSONDecodeError, OSError):
            return False
    if "email" in raw:
        # Already migrated — still drop a stale legacy record if present.
        if "gmail" in raw:
            raw.pop("gmail", None)
            try:
                with open(_TOOLS_CONFIG_PATH, "w") as f:
                    json.dump(raw, f, indent=2)
            except OSError:
                pass
        return False
    legacy = dict(raw.pop("gmail", None) or {})
    if not (legacy.get("email") and legacy.get("app_password")):
        # The old _gmail_config() fallback chain: agents/main/gmail.json.
        fb_path = os.path.join(AGENTS_DIR, "main", "gmail.json")
        if os.path.exists(fb_path):
            try:
                with open(fb_path) as f:
                    fb = json.load(f) or {}
                if not legacy.get("email"):
                    legacy["email"] = fb.get("email", "")
                if not legacy.get("app_password"):
                    legacy["app_password"] = fb.get("app_password", "")
            except (json.JSONDecodeError, OSError):
                pass
    accounts = []
    if legacy.get("email"):
        accounts.append({
            "name": "gmail", "type": "imap", "preset": "gmail",
            "email": legacy.get("email", ""), "username": "",
            "password": legacy.get("app_password", ""),
            "imap_host": "imap.gmail.com", "imap_port": 993,
            "smtp_host": "smtp.gmail.com", "smtp_port": 465,
            "smtp_security": "ssl",
        })
    raw["email"] = {
        "enabled": legacy.get("enabled", True) if legacy else True,
        "default_account": accounts[0]["name"] if accounts else "",
        "accounts": accounts,
    }
    try:
        with open(_TOOLS_CONFIG_PATH, "w") as f:
            json.dump(raw, f, indent=2)
    except OSError:
        return False
    return True


# Tool-name rename map of the Email-Tools-v2 cutover (E4) — used by the
# tool_settings key migration below; kept module-level for tests.
_EMAIL_TOOL_RENAMES = {
    "gmail_inbox": "email_inbox",
    "gmail_read": "email_read",
    "gmail_search": "email_search",
    "gmail_send": "email_send",
    "gmail_reply": "email_reply",
}


def migrate_email_tool_settings(settings: dict) -> int:
    """Rename config.json → tool_settings keys gmail_* → email_* (E4) so the
    renamed tools keep their enabled/deferred/purpose matrix + prose instead of
    being re-seeded as fresh defaults. Idempotent: a record only moves when the
    new key is absent; a stale old key next to an existing new one is dropped.
    Mutates `settings` in place; returns the number of records touched."""
    changed = 0
    for old, new in _EMAIL_TOOL_RENAMES.items():
        if old not in settings:
            continue
        if new not in settings:
            settings[new] = settings.pop(old)
        else:
            settings.pop(old)
        changed += 1
    return changed


def get_tool_status() -> dict:
    """Return status of each configurable tool, checking all fallback sources."""
    cfg = get_tool_config()
    status = {}
    for tool_name, tool_cfg in cfg.items():
        tool_cfg = dict(tool_cfg)  # copy to avoid mutating defaults
        # The real enable gate is tool_settings.enabled (resolved by
        # _global_tool_enabled), NOT the legacy integration `enabled` field.
        # For tools that have a TOOL_DISPATCH entry, defer to the gate so the
        # status display matches what actually gates the LLM. Integration-only
        # pseudo-tools (no dispatch entry) keep their own `enabled` field.
        if tool_name in TOOL_DISPATCH:
            enabled = _global_tool_enabled(tool_name)
        else:
            enabled = tool_cfg.get("enabled", True)
        if not enabled:
            s = "disabled"
        elif tool_name == "exa_search":
            exa_key = tool_cfg.get("api_key") or os.environ.get("EXA_API_KEY", "")
            if not tool_cfg.get("api_key") and os.environ.get("EXA_API_KEY"):
                tool_cfg["_source"] = "environment variable"
            s = "configured" if exa_key else "not configured"
        elif tool_name == "searxng_search":
            _resolved = _searxng_base_url()
            if _resolved and not tool_cfg.get("url"):
                tool_cfg["_source"] = "bundled instance (searxng.url)"
            s = "configured" if _resolved else "not configured"
        elif tool_name == "email":
            accounts = tool_cfg.get("accounts") or []
            n_ok = sum(1 for a in accounts
                       if a.get("email") and (a.get("password") or a.get("app_password")))
            s = (f"configured ({n_ok}/{len(accounts)} Konten)" if n_ok
                 else "not configured")
            # Never ship account secrets through the status endpoint.
            tool_cfg["accounts"] = [
                {k: v for k, v in a.items() if k not in ("password", "app_password")}
                for a in accounts
            ]
        elif tool_name == "refinement":
            s = "configured" if tool_cfg.get("model") else "auto (Haiku > cheapest)"
        else:
            s = "configured"
        status[tool_name] = {"enabled": enabled, "status": s, "config": tool_cfg}
    return status


class AgentConfig:
    """Configuration and file management for a single agent."""

    def __init__(self, agent_id: str):
        self.agent_id = agent_id
        self.dir = os.path.join(AGENTS_DIR, agent_id)
        os.makedirs(self.dir, exist_ok=True)
        self._ensure_defaults()

    def _ensure_defaults(self):
        """Create default files if they don't exist."""
        soul_path = os.path.join(self.dir, "soul.md")
        if not os.path.exists(soul_path):
            with open(soul_path, "w") as f:
                f.write(f"""# {self.agent_id}

You are the **{self.agent_id}** agent.
Adapt your behavior to the tasks you are given.
""")
        config_path = os.path.join(self.dir, "agent.json")
        if not os.path.exists(config_path):
            with open(config_path, "w") as f:
                json.dump({
                    "description": f"{self.agent_id} agent",
                    "model": None,
                }, f, indent=2)

    @property
    def soul(self) -> str:
        """Load soul.md content."""
        path = os.path.join(self.dir, "soul.md")
        try:
            with open(path, "r") as f:
                return f.read()
        except OSError:
            return ""

    @property
    def config(self) -> dict:
        """Load agent.json config."""
        path = os.path.join(self.dir, "agent.json")
        try:
            with open(path, "r") as f:
                return json.load(f)
        except (OSError, json.JSONDecodeError):
            return {}

    @property
    def description(self) -> str:
        return self.config.get("description", self.agent_id)

    @property
    def preferred_model(self) -> str | None:
        raw = self.config.get("model")
        if not raw:
            return None
        purpose = self.config.get("model_purpose")
        resolved = resolve_model(raw, purpose) if _models_config else raw
        return resolved or raw

    @property
    def max_context(self) -> int | None:
        """Return model's max_context if a preferred model is set."""
        model = self.preferred_model
        if model:
            return get_model_max_context(model)
        return None

    @property
    def memory_dir(self) -> str:
        return self.dir  # memory.db lives alongside soul.md

    @property
    def skills_dir(self) -> str:
        return os.path.join(self.dir, "skills")

    @property
    def mcp_config_path(self) -> str:
        return os.path.join(self.dir, "mcp.json")

    def load_commands(self) -> list[dict]:
        """Load custom slash commands from commands.json + .claude/commands/*.md.

        Supports both Brain Agent format (JSON) and Claude Code format (markdown
        with YAML frontmatter, $ARGUMENTS, !`command` interpolation).
        """
        commands = []

        # 1. Brain Agent format: commands.json
        path = os.path.join(self.dir, "commands.json")
        try:
            with open(path, "r") as f:
                data = json.load(f)
                if isinstance(data, list):
                    for cmd in data:
                        cmd["_format"] = "brain"
                    commands.extend(data)
        except (OSError, json.JSONDecodeError):
            pass

        # 2. Claude Code format: .claude/commands/*.md and agent commands/ dir
        for cmd_dir in [
            os.path.join(os.path.dirname(os.path.abspath(__file__)), ".claude", "commands"),
            os.path.join(self.dir, "commands"),
        ]:
            if not os.path.isdir(cmd_dir):
                continue
            for fname in sorted(os.listdir(cmd_dir)):
                if not fname.endswith(".md"):
                    continue
                fpath = os.path.join(cmd_dir, fname)
                if os.path.islink(fpath):
                    fpath = os.path.realpath(fpath)
                if not os.path.isfile(fpath):
                    continue
                try:
                    with open(fpath, "r") as f:
                        raw = f.read()
                    # Parse YAML frontmatter
                    fm = {}
                    body = raw
                    fm_match = re.match(r'^---\s*\n(.*?)\n---\s*\n(.*)$', raw, re.DOTALL)
                    if fm_match:
                        for line in fm_match.group(1).split("\n"):
                            if ":" in line:
                                k, v = line.split(":", 1)
                                fm[k.strip()] = v.strip().strip('"').strip("'")
                        body = fm_match.group(2).strip()
                    cmd_name = fname[:-3]  # strip .md
                    # Skip if already defined in commands.json (brain format takes priority)
                    if any(c.get("name") == cmd_name for c in commands):
                        continue
                    commands.append({
                        "name": cmd_name,
                        "description": fm.get("description", ""),
                        "prompt": body,
                        "allowed_tools": fm.get("allowed-tools", ""),
                        "_format": "claude-code",
                        "_path": fpath,
                    })
                except OSError:
                    continue

        return commands

    def save_commands(self, commands: list[dict]):
        """Save custom slash commands to commands.json (Brain Agent format only)."""
        path = os.path.join(self.dir, "commands.json")
        # Only save brain-format commands
        brain_cmds = [c for c in commands if c.get("_format") != "claude-code"]
        # Strip internal fields
        clean = [{k: v for k, v in c.items() if not k.startswith("_")} for c in brain_cmds]
        with open(path, "w") as f:
            json.dump(clean, f, indent=2)

    @staticmethod
    def expand_command(cmd: dict, args: str = "") -> str:
        """Expand a command template with arguments and dynamic content.

        Supports both formats:
        - Brain Agent: {{variable}} substitution
        - Claude Code: $ARGUMENTS substitution + !`command` interpolation
        """
        template = cmd.get("prompt", cmd.get("template", ""))
        fmt = cmd.get("_format", "brain")

        if fmt == "claude-code":
            # Replace $ARGUMENTS with user args
            result = template.replace("$ARGUMENTS", args)

            # Interpolate !`command` — runs shell command and injects output
            import subprocess
            def _run_interpolation(match):
                shell_cmd = match.group(1)
                try:
                    proc = subprocess.run(
                        shell_cmd, shell=True, capture_output=True, text=True,
                        timeout=10, cwd=os.getcwd(),
                        env={**os.environ, "TERM": "dumb"},
                    )
                    return proc.stdout.strip()
                except Exception as e:
                    return f"(error: {e})"

            result = re.sub(r'!`([^`]+)`', _run_interpolation, result)
            return result

        else:
            # Brain Agent: {{variable}} substitution
            if "{{" in template and args:
                var_match = re.search(r'\{\{(\w+)\}\}', template)
                if var_match:
                    return template.replace("{{" + var_match.group(1) + "}}", args)
            return template + (" " + args if args else "")

    def list_skills(self) -> list[dict]:
        """List all skills for this agent (own + main's global skills).

        Backend-exclusive skills (HELPDESK_ONLY_SKILLS, e.g. the
        `brain-agent-guide` skill that powers Brainy) are hidden from the normal
        skill list — they only surface when the request context is in helpdesk
        mode. This keeps them out of the regular chat agent's awareness so they
        don't interfere with ordinary conversations."""
        skills = {}
        # Load main's skills first (global)
        if self.agent_id != "main":
            main_skills_dir = os.path.join(AGENTS_DIR, "main", "skills")
            skills.update(self._scan_skills(main_skills_dir, source="main"))
        # Load own skills (override globals if same name)
        skills.update(self._scan_skills(self.skills_dir, source=self.agent_id))
        if not get_request_context().helpdesk_mode:
            for slug in HELPDESK_ONLY_SKILLS:
                skills.pop(slug, None)
        return list(skills.values())

    def _scan_skills(self, skills_dir: str, source: str) -> dict[str, dict]:
        """Scan a skills directory and return {name: skill_info}."""
        result = {}
        if not os.path.isdir(skills_dir):
            return result
        for name in sorted(os.listdir(skills_dir)):
            skill_dir = os.path.join(skills_dir, name)
            skill_file = os.path.join(skill_dir, "SKILL.md")
            if not os.path.isfile(skill_file):
                continue
            try:
                with open(skill_file, "r") as f:
                    raw = f.read()
                # Parse YAML frontmatter
                fm_match = re.match(r'^---\s*\n(.*?)\n---\s*\n(.*)$', raw, re.DOTALL)
                if fm_match:
                    fm_text, body = fm_match.groups()
                    fm = {}
                    for line in fm_text.split("\n"):
                        if ":" in line:
                            k, v = line.split(":", 1)
                            fm[k.strip()] = v.strip().strip('"').strip("'")
                    result[name] = {
                        "name": fm.get("name", name),
                        "slug": name,
                        "description": fm.get("description", ""),
                        "source": source,
                        "path": skill_file,
                    }
                else:
                    result[name] = {
                        "name": name,
                        "slug": name,
                        "description": "",
                        "source": source,
                        "path": skill_file,
                    }
            except OSError:
                continue
        return result

    def load_skill(self, skill_name: str) -> str | None:
        """Load the full SKILL.md body for a specific skill.
        Accepts either the directory name (slug) or the display name."""
        # Backend-exclusive skills load only in helpdesk mode (the Brainy bot).
        if skill_name in HELPDESK_ONLY_SKILLS and not get_request_context().helpdesk_mode:
            return None
        # Try direct match first (slug = directory name)
        own_path = os.path.join(self.skills_dir, skill_name, "SKILL.md")
        if os.path.isfile(own_path):
            return self._read_skill_body(own_path)
        # Fall back to main's skills
        if self.agent_id != "main":
            main_path = os.path.join(AGENTS_DIR, "main", "skills", skill_name, "SKILL.md")
            if os.path.isfile(main_path):
                return self._read_skill_body(main_path)
        # Try matching by display name → slug lookup
        for s in self.list_skills():
            if s.get("name", "").lower() == skill_name.lower() or s.get("slug", "").lower() == skill_name.lower():
                slug = s.get("slug", "")
                if slug:
                    own_path = os.path.join(self.skills_dir, slug, "SKILL.md")
                    if os.path.isfile(own_path):
                        return self._read_skill_body(own_path)
                    if self.agent_id != "main":
                        main_path = os.path.join(AGENTS_DIR, "main", "skills", slug, "SKILL.md")
                        if os.path.isfile(main_path):
                            return self._read_skill_body(main_path)
        return None

    @staticmethod
    def _read_skill_body(path: str) -> str:
        """Read a SKILL.md and return just the body (after frontmatter)."""
        with open(path, "r") as f:
            raw = f.read()
        fm_match = re.match(r'^---\s*\n.*?\n---\s*\n(.*)$', raw, re.DOTALL)
        if fm_match:
            return fm_match.group(1).strip()
        return raw.strip()

    # ── Per-user skills (generated from chats, shared like chats) ─────────────
    # These live in agents/<agent>/user_skills/<slug>/ (SKILL.md +
    # skill.meta.json) and are OWNED by a user + shared via the generic 5-field
    # block (private/users/team/global) — distinct from the built-in skills/
    # dir (agent-global, user-agnostic) which stays in the cached system prompt.
    # Per-user visibility is surfaced via the first-user-message preamble
    # (wire-only), NOT the cached prompt, so the warm-pool KV prefix is stable.

    @staticmethod
    def _user_skills_root(agent_id: str) -> str:
        return os.path.join(AGENTS_DIR, agent_id, "user_skills")

    @staticmethod
    def user_skill_exists(agent_id: str, slug: str) -> bool:
        """True if a slug is already taken by EITHER a built-in skill or a
        per-user skill (slugs are agent-global unique to keep use_skill simple)."""
        if not slug:
            return False
        if os.path.isfile(os.path.join(AGENTS_DIR, agent_id, "skills", slug, "SKILL.md")):
            return True
        return os.path.isfile(
            os.path.join(AgentConfig._user_skills_root(agent_id), slug, "SKILL.md"))

    @staticmethod
    def get_skill_meta(agent_id: str, slug: str) -> dict | None:
        """Return the per-user skill's sharing block. None if the skill dir
        doesn't exist. Mirrors WorkflowEngine.get_workflow_meta."""
        sd = os.path.join(AgentConfig._user_skills_root(agent_id), slug)
        if not os.path.isfile(os.path.join(sd, "SKILL.md")):
            return None
        meta = {"owner_user_id": "", "visibility": "private", "owner_team_id": "",
                "extra_member_user_ids": [], "excluded_user_ids": [], "created_at": ""}
        mp = os.path.join(sd, "skill.meta.json")
        if os.path.exists(mp):
            try:
                with open(mp, "r") as f:
                    stored = json.load(f)
                if isinstance(stored, dict):
                    meta.update({k: stored[k] for k in stored if k in meta})
            except (OSError, json.JSONDecodeError):
                pass
        return meta

    @staticmethod
    def update_skill_meta(agent_id: str, slug: str, updates: dict) -> dict:
        meta = AgentConfig.get_skill_meta(agent_id, slug)
        if meta is None:
            return {"error": "skill not found"}
        for k in ("owner_user_id", "visibility", "owner_team_id",
                  "extra_member_user_ids", "excluded_user_ids", "created_at"):
            if k in updates:
                meta[k] = updates[k]
        if not meta.get("created_at"):
            meta["created_at"] = datetime.datetime.now(
                datetime.timezone.utc).isoformat()
        mp = os.path.join(AgentConfig._user_skills_root(agent_id), slug,
                          "skill.meta.json")
        try:
            os.makedirs(os.path.dirname(mp), exist_ok=True)
            with open(mp, "w") as f:
                json.dump(meta, f, indent=2)
        except OSError as e:
            return {"error": str(e)}
        return {"status": "updated"}

    @staticmethod
    def skill_block(meta: dict) -> dict:
        return {
            "owner_user_id": (meta or {}).get("owner_user_id", "") or "",
            "visibility": (meta or {}).get("visibility", "private") or "private",
            "owner_team_id": (meta or {}).get("owner_team_id", "") or "",
            "extra_member_user_ids": (meta or {}).get("extra_member_user_ids", []) or [],
            "excluded_user_ids": (meta or {}).get("excluded_user_ids", []) or [],
        }

    @staticmethod
    def save_user_skill(agent_id: str, *, slug: str, display_name: str,
                        description: str, body_md: str, owner_user_id: str,
                        source_kind: str = "", source_ref: str = "",
                        share: dict | None = None) -> dict:
        """Write a per-user skill (SKILL.md + skill.meta.json). Owner is the
        caller; sharing defaults to private. Returns {status, slug} or {error}."""
        slug = re.sub(r"[^a-z0-9]+", "-", (slug or "").lower()).strip("-")[:56]
        if not slug:
            return {"error": "slug ist leer/ungültig"}
        if not body_md.strip():
            return {"error": "body_md ist leer"}
        sd = os.path.join(AgentConfig._user_skills_root(agent_id), slug)
        # Frontmatter: only name + description are parsed by _scan_skills; the
        # rest is provenance the editor/UI can read.
        fm_lines = [
            "---",
            f"name: {display_name or slug}",
            f"description: {' '.join((description or '').split())}",
            "metadata:",
            "  type: user",
            f"  owner: {owner_user_id}",
        ]
        if source_kind:
            fm_lines.append(f"  source: {source_kind}")
        if source_ref:
            fm_lines.append(f"  generated_from: {source_ref}")
        fm_lines.append("---")
        content = "\n".join(fm_lines) + "\n\n" + body_md.strip() + "\n"
        try:
            os.makedirs(sd, exist_ok=True)
            with open(os.path.join(sd, "SKILL.md"), "w") as f:
                f.write(content)
        except OSError as e:
            return {"error": str(e)}
        # Sharing sidecar — normalize the block before persisting.
        from server_lib.auth import normalize_share_block
        blk = {"owner_user_id": owner_user_id, "visibility": "private",
               "owner_team_id": "", "extra_member_user_ids": [],
               "excluded_user_ids": []}
        if isinstance(share, dict):
            for k in ("visibility", "owner_team_id", "extra_member_user_ids",
                      "excluded_user_ids"):
                if k in share:
                    blk[k] = share[k]
        blk = normalize_share_block(blk)
        AgentConfig.update_skill_meta(agent_id, slug, blk)
        # Index the skill for semantic discovery (find_skills). Best-effort —
        # keyword matching still works if the vector store is unavailable. Text
        # = title + description (what a task query is matched against).
        try:
            _idx = f"{display_name or slug}\n{description or ''}".strip()
            _embed_and_store_skill(owner_user_id, slug, _idx)
        except Exception:
            pass
        return {"status": "saved", "slug": slug}

    @staticmethod
    def delete_user_skill(agent_id: str, slug: str) -> dict:
        sd = os.path.join(AgentConfig._user_skills_root(agent_id), slug)
        if not os.path.isdir(sd):
            return {"error": "skill not found"}
        # Drop the semantic-index drawer first (needs the owner uid from meta,
        # which the rmtree below removes). Best-effort.
        try:
            meta = AgentConfig.get_skill_meta(agent_id, slug) or {}
            owner = meta.get("owner_user_id") or ""
            if owner:
                _delete_skill_vector(owner, slug)
        except Exception:
            pass
        import shutil
        shutil.rmtree(sd, ignore_errors=True)
        return {"status": "deleted"}

    def list_user_skills(self, user: dict | None) -> list[dict]:
        """List the per-user skills VISIBLE to `user` (own + shared via the
        generic block). Empty when `user` is None. Owner-less skills are NOT
        world-visible (legacy_open=False) — a generated skill always has an
        owner. Distinct from list_skills() (built-in, user-agnostic)."""
        if not user:
            return []
        from server_lib.auth import can_access
        root = self._user_skills_root(self.agent_id)
        out = []
        if not os.path.isdir(root):
            return out
        for slug in sorted(os.listdir(root)):
            meta = AgentConfig.get_skill_meta(self.agent_id, slug)
            if meta is None:
                continue
            if not can_access(user, AgentConfig.skill_block(meta), legacy_open=False):
                continue
            info = self._scan_skills(root, source="user").get(slug)
            if not info:
                continue
            info = dict(info)
            info["owner_user_id"] = meta.get("owner_user_id", "")
            info["visibility"] = meta.get("visibility", "private")
            out.append(info)
        return out

    def load_user_skill_body(self, slug: str, user: dict | None) -> str | None:
        """Load a per-user skill body IFF `user` may access it (gate for
        use_skill). Returns None when not found or not permitted."""
        meta = AgentConfig.get_skill_meta(self.agent_id, slug)
        if meta is None:
            return None
        from server_lib.auth import can_access
        if not can_access(user or {}, AgentConfig.skill_block(meta),
                          legacy_open=False):
            return None
        path = os.path.join(self._user_skills_root(self.agent_id), slug, "SKILL.md")
        if os.path.isfile(path):
            return self._read_skill_body(path)
        return None


def scan_claude_code_skills() -> list[dict]:
    """Discover Claude Code skills/plugins from ~/.claude.

    Scans three sources:
    1. Plugin skills — cached plugins with SKILL.md files
    2. Plugin commands — marketplace plugin commands (slash commands)
    3. User commands — ~/.claude/commands/ markdown files

    Returns list of dicts with: name, slug, description, source, type, path, plugin, marketplace, enabled
    """
    home = os.path.expanduser("~")
    claude_dir = os.path.join(home, ".claude")
    results = []

    # Read installed_plugins.json to get install paths
    installed = {}
    try:
        with open(os.path.join(claude_dir, "plugins", "installed_plugins.json")) as f:
            data = json.load(f)
            installed = data.get("plugins", {})
    except (OSError, json.JSONDecodeError):
        pass

    # Read settings.json for enabled state
    enabled_plugins = {}
    try:
        with open(os.path.join(claude_dir, "settings.json")) as f:
            settings = json.load(f)
            enabled_plugins = settings.get("enabledPlugins", {})
    except (OSError, json.JSONDecodeError):
        pass

    # 1. Plugin skills — scan installed plugin cache dirs for skills/*/SKILL.md
    for plugin_key, installs in installed.items():
        if not installs:
            continue
        install = installs[0]  # Use first (latest) install
        install_path = install.get("installPath", "")
        if not os.path.isdir(install_path):
            continue

        plugin_name = plugin_key.split("@")[0] if "@" in plugin_key else plugin_key
        marketplace = plugin_key.split("@")[1] if "@" in plugin_key else ""
        is_enabled = enabled_plugins.get(plugin_key, False)

        skills_dir = os.path.join(install_path, "skills")
        if os.path.isdir(skills_dir):
            for skill_name in sorted(os.listdir(skills_dir)):
                skill_file = os.path.join(skills_dir, skill_name, "SKILL.md")
                if not os.path.isfile(skill_file):
                    continue
                # Parse frontmatter for name/description
                try:
                    with open(skill_file) as f:
                        raw = f.read(4096)
                    fm_match = re.match(r'^---\s*\n(.*?)\n---\s*\n', raw, re.DOTALL)
                    fm = {}
                    if fm_match:
                        for line in fm_match.group(1).split("\n"):
                            if ":" in line:
                                k, v = line.split(":", 1)
                                fm[k.strip()] = v.strip().strip('"').strip("'")
                except OSError:
                    fm = {}

                results.append({
                    "name": fm.get("name", skill_name),
                    "slug": f"{plugin_name}:{skill_name}",
                    "description": fm.get("description", ""),
                    "source": "claude-code",
                    "type": "skill",
                    "path": skill_file,
                    "plugin": plugin_name,
                    "marketplace": marketplace,
                    "enabled": is_enabled,
                })

        # 2. Plugin commands — commands/*.md in the marketplace plugin dir
        # Find commands in the marketplace source (not cache)
        for mp_dir in ["claude-plugins-official", "anthropic-agent-skills"]:
            cmd_dir = os.path.join(claude_dir, "plugins", "marketplaces", mp_dir, "plugins", plugin_name, "commands")
            if os.path.isdir(cmd_dir):
                for cmd_file in sorted(os.listdir(cmd_dir)):
                    if not cmd_file.endswith(".md"):
                        continue
                    cmd_path = os.path.join(cmd_dir, cmd_file)
                    cmd_name = cmd_file[:-3]  # strip .md
                    # Parse frontmatter
                    try:
                        with open(cmd_path) as f:
                            raw = f.read(4096)
                        fm_match = re.match(r'^---\s*\n(.*?)\n---\s*\n', raw, re.DOTALL)
                        fm = {}
                        if fm_match:
                            for line in fm_match.group(1).split("\n"):
                                if ":" in line:
                                    k, v = line.split(":", 1)
                                    fm[k.strip()] = v.strip().strip('"').strip("'")
                    except OSError:
                        fm = {}

                    results.append({
                        "name": fm.get("name", cmd_name),
                        "slug": f"{plugin_name}:{cmd_name}",
                        "description": fm.get("description", ""),
                        "source": "claude-code",
                        "type": "command",
                        "path": cmd_path,
                        "plugin": plugin_name,
                        "marketplace": mp_dir,
                        "enabled": is_enabled,
                    })

    # 3. User commands — ~/.claude/commands/*.md
    user_cmd_dir = os.path.join(claude_dir, "commands")
    if os.path.isdir(user_cmd_dir):
        for entry in sorted(os.listdir(user_cmd_dir)):
            if entry.startswith("."):
                continue
            entry_path = os.path.join(user_cmd_dir, entry)
            if os.path.islink(entry_path):
                # Resolve symlink
                entry_path = os.path.realpath(entry_path)
            if os.path.isfile(entry_path) and entry_path.endswith(".md"):
                cmd_name = entry[:-3]
                try:
                    with open(entry_path) as f:
                        raw = f.read(4096)
                    fm_match = re.match(r'^---\s*\n(.*?)\n---\s*\n', raw, re.DOTALL)
                    fm = {}
                    if fm_match:
                        for line in fm_match.group(1).split("\n"):
                            if ":" in line:
                                k, v = line.split(":", 1)
                                fm[k.strip()] = v.strip().strip('"').strip("'")
                except OSError:
                    fm = {}
                results.append({
                    "name": fm.get("name", cmd_name),
                    "slug": cmd_name,
                    "description": fm.get("description", ""),
                    "source": "claude-code",
                    "type": "user-command",
                    "path": entry_path,
                    "plugin": "",
                    "marketplace": "",
                    "enabled": True,  # User commands are always enabled
                })
            elif os.path.isdir(entry_path):
                # Directory with SKILL.md
                skill_file = os.path.join(entry_path, "SKILL.md")
                if os.path.isfile(skill_file):
                    try:
                        with open(skill_file) as f:
                            raw = f.read(4096)
                        fm_match = re.match(r'^---\s*\n(.*?)\n---\s*\n', raw, re.DOTALL)
                        fm = {}
                        if fm_match:
                            for line in fm_match.group(1).split("\n"):
                                if ":" in line:
                                    k, v = line.split(":", 1)
                                    fm[k.strip()] = v.strip().strip('"').strip("'")
                    except OSError:
                        fm = {}
                    results.append({
                        "name": fm.get("name", entry),
                        "slug": entry,
                        "description": fm.get("description", ""),
                        "source": "claude-code",
                        "type": "user-skill",
                        "path": skill_file,
                        "plugin": "",
                        "marketplace": "",
                        "enabled": True,
                    })

    # Deduplicate: same skill name across plugins → keep first occurrence
    seen_names = {}
    deduped = []
    for s in results:
        key = (s["name"], s["type"])
        if key in seen_names:
            continue
        seen_names[key] = True
        deduped.append(s)

    return deduped


def browse_claude_code_plugins(query: str = "") -> list[dict]:
    """Browse available Claude Code plugins from local marketplace manifests.

    Returns list of dicts with: name, description, category, marketplace, source, homepage, installed
    """
    home = os.path.expanduser("~")
    claude_dir = os.path.join(home, ".claude")
    results = []

    # Read installed_plugins.json to check install state
    installed_keys = set()
    try:
        with open(os.path.join(claude_dir, "plugins", "installed_plugins.json")) as f:
            data = json.load(f)
            installed_keys = set(data.get("plugins", {}).keys())
    except (OSError, json.JSONDecodeError):
        pass

    # Scan all marketplace manifests
    mp_dir = os.path.join(claude_dir, "plugins", "marketplaces")
    if not os.path.isdir(mp_dir):
        return results

    for mp_name in sorted(os.listdir(mp_dir)):
        manifest_path = os.path.join(mp_dir, mp_name, ".claude-plugin", "marketplace.json")
        if not os.path.isfile(manifest_path):
            continue
        try:
            with open(manifest_path) as f:
                manifest = json.load(f)
        except (OSError, json.JSONDecodeError):
            continue

        for plugin in manifest.get("plugins", []):
            name = plugin.get("name", "")
            description = plugin.get("description", "")
            # Filter by query
            if query:
                q = query.lower()
                if q not in name.lower() and q not in description.lower():
                    continue

            plugin_key = f"{name}@{mp_name}"
            results.append({
                "name": name,
                "description": description,
                "category": plugin.get("category", ""),
                "marketplace": mp_name,
                "homepage": plugin.get("homepage", ""),
                "source": plugin.get("source", {}),
                "installed": plugin_key in installed_keys,
            })

    return results


def install_claude_code_plugin(plugin_name: str, marketplace: str = "claude-plugins-official") -> dict:
    """Install a Claude Code plugin from a marketplace.

    Uses `claude plugins add` CLI if available, otherwise clones from git source.
    Returns dict with status/error.
    """
    import subprocess
    import shutil

    home = os.path.expanduser("~")
    claude_dir = os.path.join(home, ".claude")

    # Find the plugin in the marketplace manifest
    manifest_path = os.path.join(claude_dir, "plugins", "marketplaces", marketplace,
                                  ".claude-plugin", "marketplace.json")
    if not os.path.isfile(manifest_path):
        return {"error": f"Marketplace '{marketplace}' not found"}

    try:
        with open(manifest_path) as f:
            manifest = json.load(f)
    except (OSError, json.JSONDecodeError) as e:
        return {"error": f"Failed to read manifest: {e}"}

    plugin_info = None
    for p in manifest.get("plugins", []):
        if p.get("name") == plugin_name:
            plugin_info = p
            break
    if not plugin_info:
        return {"error": f"Plugin '{plugin_name}' not found in {marketplace}"}

    # Try using claude CLI first
    claude_bin = shutil.which("claude")
    if claude_bin:
        try:
            result = subprocess.run(
                [claude_bin, "plugins", "add", f"{plugin_name}@{marketplace}"],
                capture_output=True, text=True, timeout=60,
                env={**os.environ, "TERM": "dumb"},
            )
            if result.returncode == 0:
                return {"status": "installed", "plugin": plugin_name, "marketplace": marketplace,
                        "method": "claude-cli"}
        except (subprocess.TimeoutExpired, OSError):
            pass  # Fall through to manual install

    # Manual install: clone from git source
    source = plugin_info.get("source", {})
    if isinstance(source, str):
        # Local source (relative path in marketplace)
        src_dir = os.path.join(claude_dir, "plugins", "marketplaces", marketplace, source)
        if os.path.isdir(src_dir):
            # Copy to cache
            cache_dir = os.path.join(claude_dir, "plugins", "cache", marketplace,
                                      plugin_name, "local")
            os.makedirs(cache_dir, exist_ok=True)
            shutil.copytree(src_dir, cache_dir, dirs_exist_ok=True)
            # Register in installed_plugins.json
            _register_cc_plugin(plugin_name, marketplace, cache_dir)
            return {"status": "installed", "plugin": plugin_name, "marketplace": marketplace,
                    "method": "copy", "path": cache_dir}
        return {"error": f"Local source '{source}' not found"}

    elif isinstance(source, dict):
        git_url = source.get("url", "")
        if not git_url:
            return {"error": "No git URL in plugin source"}

        # Clone to cache
        cache_dir = os.path.join(claude_dir, "plugins", "cache", marketplace,
                                  plugin_name, "latest")
        if os.path.isdir(cache_dir):
            shutil.rmtree(cache_dir)
        os.makedirs(os.path.dirname(cache_dir), exist_ok=True)

        try:
            # For git-subdir sources, clone then extract subdir
            subdir = source.get("path", "")
            ref = source.get("ref", "main")

            result = subprocess.run(
                ["git", "clone", "--depth", "1", "--branch", ref,
                 git_url if git_url.endswith(".git") else f"https://github.com/{git_url}.git",
                 cache_dir],
                capture_output=True, text=True, timeout=60,
            )
            if result.returncode != 0:
                return {"error": f"git clone failed: {result.stderr[:200]}"}

            # If subdir specified, move it up
            if subdir:
                subdir_path = os.path.join(cache_dir, subdir)
                if os.path.isdir(subdir_path):
                    import tempfile
                    tmp = tempfile.mkdtemp()
                    shutil.copytree(subdir_path, os.path.join(tmp, plugin_name), dirs_exist_ok=True)
                    shutil.rmtree(cache_dir)
                    shutil.copytree(os.path.join(tmp, plugin_name), cache_dir, dirs_exist_ok=True)
                    shutil.rmtree(tmp)

            _register_cc_plugin(plugin_name, marketplace, cache_dir)
            return {"status": "installed", "plugin": plugin_name, "marketplace": marketplace,
                    "method": "git", "path": cache_dir}

        except (subprocess.TimeoutExpired, OSError) as e:
            return {"error": f"Install failed: {e}"}

    return {"error": "Unknown source format"}


def _register_cc_plugin(plugin_name: str, marketplace: str, install_path: str):
    """Register a plugin in ~/.claude/plugins/installed_plugins.json."""
    import datetime
    home = os.path.expanduser("~")
    ip_path = os.path.join(home, ".claude", "plugins", "installed_plugins.json")

    try:
        with open(ip_path) as f:
            data = json.load(f)
    except (OSError, json.JSONDecodeError):
        data = {"version": 2, "plugins": {}}

    plugin_key = f"{plugin_name}@{marketplace}"
    now = datetime.datetime.utcnow().isoformat() + "Z"
    data["plugins"][plugin_key] = [{
        "scope": "user",
        "installPath": install_path,
        "version": "latest",
        "installedAt": now,
        "lastUpdated": now,
        "isLocal": True,
    }]

    with open(ip_path, "w") as f:
        json.dump(data, f, indent=4)

    # Also enable in settings.json
    settings_path = os.path.join(home, ".claude", "settings.json")
    try:
        with open(settings_path) as f:
            settings = json.load(f)
    except (OSError, json.JSONDecodeError):
        settings = {}
    if "enabledPlugins" not in settings:
        settings["enabledPlugins"] = {}
    settings["enabledPlugins"][plugin_key] = True
    with open(settings_path, "w") as f:
        json.dump(settings, f, indent=4)


def list_agents() -> list[str]:
    """List all available agent IDs."""
    if not os.path.isdir(AGENTS_DIR):
        return ["main"]
    agents = []
    for name in sorted(os.listdir(AGENTS_DIR)):
        if os.path.isdir(os.path.join(AGENTS_DIR, name)) and not name.startswith("."):
            agents.append(name)
    if not agents:
        agents = ["main"]
    return agents


def get_agent_summaries() -> list[dict]:
    """Get agent ID + description + soul summary for all agents, with team metadata."""
    # First pass: collect raw summaries and scan for teams
    raw = []
    # team_id (the agent whose config holds the team) -> team config
    teams_cfg: dict[str, dict] = {}
    for agent_id in list_agents():
        cfg = AgentConfig(agent_id)
        config = cfg.config
        soul = cfg.soul.strip()
        summary = ""
        for line in soul.split("\n"):
            line = line.strip()
            if line and not line.startswith("#") and not line.startswith("---"):
                summary = line
                break
        # Report the raw configured model when it's the "auto" directive, so
        # the UI reflects what's actually set (and a new chat defaults to Auto).
        # preferred_model would resolve "auto" to a concrete model id, hiding
        # the auto setting from the composer. Non-auto values still go through
        # preferred_model so shortnames resolve to canonical ids.
        _agent_model = "auto" if config.get("model") == "auto" else cfg.preferred_model
        entry = {
            "id": agent_id,
            "display_name": config.get("display_name", ""),
            "description": cfg.description,
            "soul_summary": summary,
            "model": _agent_model,
            "avatar": config.get("avatar"),
            "paused": config.get("paused", False),
        }
        team_cfg = config.get("team")
        if isinstance(team_cfg, dict) and team_cfg.get("members"):
            teams_cfg[agent_id] = team_cfg
        raw.append(entry)

    # Second pass: compute team metadata per agent
    for entry in raw:
        aid = entry["id"]
        # Which teams is this agent a member of?
        member_of = []
        is_head_of = None
        for cfg_holder, tcfg in teams_cfg.items():
            members = tcfg.get("members", [])
            head_id = tcfg.get("head", members[0] if members else cfg_holder)
            if aid in members:
                team_name = tcfg.get("name", cfg_holder)
                member_of.append({"team_id": cfg_holder, "team_name": team_name})
                if aid == head_id:
                    is_head_of = cfg_holder
        entry["teams"] = member_of
        entry["is_team_head"] = is_head_of is not None
        if is_head_of:
            tcfg = teams_cfg[is_head_of]
            entry["team_config_holder"] = is_head_of
            entry["team_members"] = list(tcfg.get("members", []))
            entry["team_head"] = tcfg.get("head", entry["team_members"][0] if entry["team_members"] else is_head_of)
            entry["team_name"] = tcfg.get("name", "")
            entry["team_description"] = tcfg.get("description", "")
            entry["team_avatar"] = tcfg.get("avatar", "")
    return raw


def get_team_structure() -> dict:
    """Return hierarchical team structure for UI and API consumption."""
    agents = get_agent_summaries()
    agent_map = {a["id"]: a for a in agents}
    teams = {}
    in_team = set()  # agents that appear in at least one team

    # Find all agents that hold team configs
    for agent_id in list_agents():
        cfg = AgentConfig(agent_id).config
        team_cfg = cfg.get("team")
        if not isinstance(team_cfg, dict) or not team_cfg.get("members"):
            continue
        members_ids = team_cfg["members"]
        head_id = team_cfg.get("head", members_ids[0] if members_ids else agent_id)
        members = []
        for mid in members_ids:
            if mid in agent_map:
                members.append(agent_map[mid])
                in_team.add(mid)
        teams[agent_id] = {
            "head": head_id,
            "head_agent": agent_map.get(head_id),
            "members": members,
            "name": team_cfg.get("name") or agent_id,
            "description": team_cfg.get("description", ""),
            "avatar": team_cfg.get("avatar", ""),
            "config_holder": agent_id,
        }

    standalone = [a for a in agents if a["id"] not in in_team and a["id"] != "main"]
    main_agent = agent_map.get("main")
    return {"teams": teams, "standalone": standalone, "main": main_agent}


def _get_delegation_scope(caller_agent_id: str) -> list[str]:
    """Return list of agent IDs the caller is allowed to delegate to."""
    all_agents = list_agents()

    # Collect all team configs
    team_cfgs = {}  # config_holder_id -> team_cfg
    for aid in all_agents:
        cfg = AgentConfig(aid).config
        team_cfg = cfg.get("team")
        if isinstance(team_cfg, dict) and team_cfg.get("members"):
            team_cfgs[aid] = team_cfg

    in_team = set()
    head_ids = set()
    for holder, tcfg in team_cfgs.items():
        head_id = tcfg.get("head", tcfg["members"][0] if tcfg["members"] else holder)
        head_ids.add(head_id)
        for m in tcfg["members"]:
            in_team.add(m)

    if caller_agent_id == "main":
        # Main can delegate to team heads and standalone agents (not regular members)
        return [a for a in all_agents if a != "main" and (a in head_ids or a not in in_team)]

    # Check if caller is a team head
    for holder, tcfg in team_cfgs.items():
        head_id = tcfg.get("head", tcfg["members"][0] if tcfg["members"] else holder)
        if caller_agent_id == head_id:
            # Team head can delegate to its members (excluding self)
            return [m for m in tcfg["members"] if m != caller_agent_id and m in all_agents]

    # Regular member: can delegate to peers in same team + team head
    reachable = set()
    for holder, tcfg in team_cfgs.items():
        if caller_agent_id in tcfg["members"]:
            for m in tcfg["members"]:
                if m != caller_agent_id and m in all_agents:
                    reachable.add(m)
    return list(reachable) if reachable else [a for a in all_agents if a != caller_agent_id]


def _find_team_head(agent_id: str) -> str | None:
    """Find the team head for a given agent. Returns None if not in any team."""
    for aid in list_agents():
        cfg = AgentConfig(aid).config
        team_cfg = cfg.get("team")
        if isinstance(team_cfg, dict) and team_cfg.get("members"):
            if agent_id in team_cfg["members"]:
                return team_cfg.get("head", team_cfg["members"][0] if team_cfg["members"] else aid)
    return None


def _get_agent_team_info(agent_id: str) -> dict | None:
    """Get team info for an agent. Returns dict with name, head, members, is_head, or None."""
    for aid in list_agents():
        cfg = AgentConfig(aid).config
        team_cfg = cfg.get("team")
        if isinstance(team_cfg, dict) and team_cfg.get("members"):
            if agent_id in team_cfg["members"]:
                head = team_cfg.get("head", team_cfg["members"][0])
                return {
                    "name": team_cfg.get("name", aid),
                    "head": head,
                    "members": team_cfg["members"],
                    "is_head": agent_id == head,
                    "config_holder": aid,
                }
    return None


def build_agent_registry(for_agent_id: str | None = None) -> str:
    """Build a text block describing available agents for injection into system prompts.
    Respects team hierarchy: team heads see members, main sees heads + standalone."""
    agents = get_agent_summaries()
    if len(agents) <= 1:
        return ""

    caller = for_agent_id or "main"
    scope = _get_delegation_scope(caller)
    agent_map = {a["id"]: a for a in agents}

    # Check if caller is a team head
    caller_team_info = _get_agent_team_info(caller) if caller != "main" else None
    caller_is_head = caller_team_info and caller_team_info["is_head"]

    lines = ["AGENT REGISTRY — use delegate_task to send tasks to these agents:"]

    if caller == "main":
        # Group by teams + standalone
        struct = get_team_structure()
        if struct["teams"]:
            lines.append("  TEAMS:")
            for tid, team in struct["teams"].items():
                team_name = team.get("name", tid)
                head_id = team["head"]
                head_agent = team.get("head_agent", {})
                detail = head_agent.get("soul_summary") or head_agent.get("description", "")
                model_note = f" (model: {head_agent.get('model')})" if head_agent.get("model") else ""
                member_names = ", ".join(m["id"] for m in team["members"])
                lines.append(f"    - {head_id} (head of '{team_name}'): {detail}{model_note}")
                lines.append(f"      Members: {member_names}")
        if struct["standalone"]:
            lines.append("  STANDALONE AGENTS:")
            for a in struct["standalone"]:
                detail = a.get("soul_summary") or a.get("description", "")
                model_note = f" (model: {a['model']})" if a.get("model") else ""
                lines.append(f"    - {a['id']}: {detail}{model_note}")
    elif caller_is_head:
        lines.append("  YOUR TEAM MEMBERS:")
        for mid in scope:
            a = agent_map.get(mid, {})
            detail = a.get("soul_summary") or a.get("description", mid)
            model_note = f" (model: {a.get('model')})" if a.get("model") else ""
            lines.append(f"    - {mid}: {detail}{model_note}")
    else:
        for aid in scope:
            a = agent_map.get(aid, {})
            detail = a.get("soul_summary") or a.get("description", aid)
            model_note = f" (model: {a.get('model')})" if a.get("model") else ""
            lines.append(f"  - {aid}: {detail}{model_note}")

    lines.append("")
    lines.append(
        "Before performing a task, consider if another agent is better suited. "
        "Delegate when the task clearly matches another agent's specialty. "
        "Do NOT delegate simple tasks you can handle yourself."
    )
    return "\n".join(lines)


# Current active agent (set in _run_interactive)
_current_agent: AgentConfig | None = None


# --- Memory System (QMD hybrid search) ---

import hashlib
import urllib.request
import urllib.error


def _extract_json_from_llm(text: str, expect_array: bool = False):
    """Robustly extract JSON object or array from LLM response text.

    Handles markdown code fences, nested objects, surrounding text.
    Returns parsed dict/list or None on failure.
    """
    if not text:
        return None
    # Strip markdown code fences first
    stripped = re.sub(r'```(?:json)?\s*', '', text)
    stripped = stripped.replace('```', '')

    # Try parsing the entire stripped text first
    try:
        parsed = json.loads(stripped.strip())
        if expect_array and isinstance(parsed, list):
            return parsed
        if not expect_array and isinstance(parsed, dict):
            return parsed
    except (json.JSONDecodeError, ValueError):
        pass

    # Use json.JSONDecoder.raw_decode to find the first valid JSON structure
    decoder = json.JSONDecoder()
    target_char = '[' if expect_array else '{'
    for i, ch in enumerate(stripped):
        if ch == target_char:
            try:
                obj, _ = decoder.raw_decode(stripped[i:])
                if expect_array and isinstance(obj, list):
                    return obj
                if not expect_array and isinstance(obj, dict):
                    return obj
            except (json.JSONDecodeError, ValueError):
                continue
    return None

# QMD HTTP MCP daemon endpoint
_QMD_URL = "http://localhost:8181/mcp"
_QMD_HEADERS = {
    "Content-Type": "application/json",
    "Accept": "application/json, text/event-stream",
}

# Shared MCP session ID (set on first successful init)
_qmd_session_id: str | None = None
_qmd_session_lock = threading.RLock()
# Per-collection debounce timers for embedding after writes
_qmd_embed_timers: dict[str, threading.Timer] = {}
_qmd_embed_lock = threading.Lock()

# Files to skip when indexing (not memory files)
_QMD_IGNORE_FILES = {"soul.md", "tools.md"}


def _qmd_rpc(method: str, params: dict | None = None) -> dict | None:
    """DISABLED — qmd reverted. Always None so callers take their fallback path
    (MemoryStore.recall → file-scan). No network call to the (removed) qmd MCP."""
    return None
    global _qmd_session_id  # noqa: F811 — unreachable
    payload = {"jsonrpc": "2.0", "id": 1, "method": method, "params": params or {}}
    data = json.dumps(payload).encode()
    headers = dict(_QMD_HEADERS)
    with _qmd_session_lock:
        if _qmd_session_id:
            headers["Mcp-Session-Id"] = _qmd_session_id
    req = urllib.request.Request(_QMD_URL, data=data, headers=headers)
    try:
        with urllib.request.urlopen(req, timeout=10) as resp:
            # Capture session ID from response (under lock)
            sid = resp.headers.get("Mcp-Session-Id")
            if sid:
                with _qmd_session_lock:
                    _qmd_session_id = sid
            body = json.loads(resp.read().decode())
            if "error" in body:
                logging.warning("QMD RPC error: %s", body["error"])
                return None
            return body.get("result")
    except Exception as e:
        logging.debug("QMD unreachable: %s", e)
        return None


def _qmd_init_session() -> bool:
    """Initialize an MCP session with QMD. Returns True if successful.
    Thread-safe: only one session is created even under concurrent access."""
    with _qmd_session_lock:
        if _qmd_session_id:
            return True  # Another thread already initialized
        result = _qmd_rpc("initialize", {
            "protocolVersion": "2024-11-05",
            "capabilities": {},
            "clientInfo": {"name": "brain-agent", "version": "1.0"},
        })
        return result is not None


def _qmd_ensure_collection(name: str, directory: str):
    """DISABLED — qmd reverted. No-op so init never shells out to the (removed)
    qmd CLI / spawns a collection registration."""
    return
    try:  # noqa — unreachable below
        result = subprocess.run(
            ["qmd", "collection", "show", name],
            capture_output=True, text=True, timeout=5,
        )
        if result.returncode == 0:
            return  # Already exists
        subprocess.run(
            ["qmd", "collection", "add", directory,
             "--name", name, "--pattern", "*.md",
             "--ignore", ",".join(_QMD_IGNORE_FILES)],
            capture_output=True, text=True, timeout=15,
        )
    except Exception as e:
        logging.debug("QMD collection setup failed for %s: %s", name, e)


def _qmd_debounced_embed(collection: str):
    """DISABLED — qmd was reverted (failed experiment). No-op so memory writes +
    ingest never invoke the qmd subprocess/MCP. Kept as a stub so existing call
    sites (engine/ingest.py, MemoryStore.store) don't need touching."""
    return
    def _do_embed():  # noqa: F811 — unreachable, retained for reference
        try:
            subprocess.run(
                ["qmd", "update"], capture_output=True, text=True, timeout=30,
            )
            subprocess.run(
                ["qmd", "embed", "-c", collection],
                capture_output=True, text=True, timeout=60,
            )
        except Exception as e:
            logging.debug("QMD embed failed for %s: %s", collection, e)
        finally:
            with _qmd_embed_lock:
                _qmd_embed_timers.pop(collection, None)
    with _qmd_embed_lock:
        old = _qmd_embed_timers.get(collection)
        if old:
            old.cancel()
        timer = threading.Timer(2.0, _do_embed)
        timer.daemon = True
        _qmd_embed_timers[collection] = timer
        timer.start()


def _parse_frontmatter(raw: str) -> tuple[dict, str]:
    """Parse YAML frontmatter from a markdown file. Returns (metadata, body)."""
    # Normalize line endings for cross-platform compatibility
    raw = raw.replace("\r\n", "\n")
    fm_match = re.match(r'^---\s*\n(.*?)\n---\s*\n(.*)$', raw, re.DOTALL)
    if fm_match:
        fm_text, body = fm_match.groups()
        fm = {}
        for line in fm_text.split("\n"):
            # Only parse top-level keys (skip indented/nested YAML lines)
            if ":" in line and not line.startswith((" ", "\t", "-")):
                k, v = line.split(":", 1)
                fm[k.strip()] = v.strip()
        return fm, body.strip()
    return {}, raw.strip()


def _yaml_escape(value: str) -> str:
    """Escape a string for safe inclusion in YAML frontmatter."""
    if not value:
        return '""'
    # Quote if contains special YAML chars
    if any(c in value for c in (':', '#', '{', '}', '[', ']', ',', '&', '*', '?', '|', '-', '<', '>', '=', '!', '%', '@', '`', '\n')):
        escaped = value.replace('\\', '\\\\').replace('"', '\\"').replace('\n', ' ')
        return f'"{escaped}"'
    return value




# ─── Projects System ──────────────────────────────────────────────────

def _project_research_mode(cfg: dict) -> bool:
    """Resolve a project's research_mode flag with backwards-compat migration.

    `research_mode` toggles the strict retrieval/citation regime: forced
    `mempalace_query` 3-step flow + REFUSAL/PRECISION/CITATION disciplines
    + server-side citation validator + synchronous re-round on uncited
    claims. Off for general-purpose project chats (build/research/codegen
    that USES the project's documents as inputs rather than reproducing
    them verbatim).

    Migration: legacy projects predate the field. To preserve current
    behavior we infer a sensible default from whether the owner has
    customised `instructions`:
      - empty instructions -> research_mode=True (they were getting the
        v8.22 default disciplines via the old fallback; keep that)
      - non-empty instructions -> research_mode=False (the owner already
        wrote their own — the disciplines weren't applied anyway, so the
        chat behaves like a non-research chat already)
    Project owners can flip the flag in project settings.
    """
    if "research_mode" in cfg:
        return bool(cfg.get("research_mode"))
    # Backwards-compat default for projects predating the flag.
    return not bool((cfg.get("instructions") or "").strip())


# Virtual-folder grouping for the project source-panel tree. Per type (files /
# folders / urls — 'instructions' is a singleton, never grouped), a list of
# user-created virtual folders + a flat map of item-id → group-id. Depth is
# capped at 3 levels (a group's parent chain length ≤ 2 → node depth ≤ 3).
_SOURCE_GROUP_TYPES = ("files", "folders", "urls")
_SOURCE_GROUP_MAX_DEPTH = 3


def _sanitise_source_groups(raw) -> dict:
    """Coerce a client source_groups payload into the canonical, safe on-disk
    shape: only the 3 groupable types, each with `groups` (id/name/parent/order,
    depth-capped, no parent cycles) + `assign` (item-id → existing group-id).
    Drops anything malformed rather than raising — a bad payload must never
    corrupt project.json or yield an un-renderable tree."""
    if not isinstance(raw, dict):
        return {}
    out = {}
    for t in _SOURCE_GROUP_TYPES:
        bucket = raw.get(t) or {}
        if not isinstance(bucket, dict):
            bucket = {}
        # 1) Clean groups: keep well-formed ones, index by id.
        groups = {}
        for g in (bucket.get("groups") or []):
            if not isinstance(g, dict):
                continue
            gid = str(g.get("id") or "").strip()
            if not gid or gid in groups:
                continue
            groups[gid] = {
                "id": gid,
                "name": str(g.get("name") or "").strip()[:120] or "Gruppe",
                "parent": str(g.get("parent") or "").strip(),
                "order": int(g.get("order") or 0) if str(g.get("order") or "0").lstrip("-").isdigit() else 0,
            }
        # 2) Resolve parents: a parent must be an existing group; break cycles
        #    and enforce the depth cap by walking the parent chain.
        def _depth(gid, _seen=None):
            _seen = _seen or set()
            g = groups.get(gid)
            if not g or gid in _seen:
                return 99  # cycle → treat as too-deep so it gets flattened
            p = g.get("parent")
            if not p or p not in groups:
                return 1
            return 1 + _depth(p, _seen | {gid})
        for gid, g in list(groups.items()):
            p = g.get("parent")
            if p and p not in groups:
                g["parent"] = ""           # dangling parent → root
            if _depth(gid) > _SOURCE_GROUP_MAX_DEPTH:
                g["parent"] = ""           # too deep / cyclic → flatten to root
        # 3) Clean assignments: item-id → an existing group-id.
        assign = {}
        for item_id, gid in (bucket.get("assign") or {}).items():
            gid = str(gid or "").strip()
            if gid and gid in groups:
                assign[str(item_id)] = gid
        out[t] = {"groups": sorted(groups.values(), key=lambda x: (x["order"], x["name"])),
                  "assign": assign}
    return out


class ProjectManager:
    """CRUD operations for per-agent projects."""

    @staticmethod
    def _project_dir(agent_id: str, name: str) -> str:
        return os.path.join(AGENTS_DIR, agent_id, "projects", name)

    @staticmethod
    def _projects_base(agent_id: str) -> str:
        return os.path.join(AGENTS_DIR, agent_id, "projects")

    @staticmethod
    def _instruction_files_dir(agent_id: str, name: str) -> str:
        """Per-project dir for supplementary instruction files. These are
        owner-uploaded explanatory docs that ride ALONGSIDE the project
        instructions: NEVER mined into memory — the model is given their disk
        paths in the system prompt and reads them on demand with read_document
        (same concept as chat attachments). Kept separate from ingested/ (which
        IS mined) and notes/."""
        return os.path.join(
            ProjectManager._project_dir(agent_id, name), "instruction-files")

    @staticmethod
    def list_projects(agent_id: str, user_id: str | None = None,
                      user_team_ids: list[str] | None = None) -> list[dict]:
        """List projects for an agent, optionally filtered by user access.
        user_id=None means admin (sees all). user_team_ids are team IDs the user belongs to."""
        base = ProjectManager._projects_base(agent_id)
        if not os.path.isdir(base):
            return []
        projects = []
        for name in sorted(os.listdir(base)):
            pdir = os.path.join(base, name)
            if not os.path.isdir(pdir) or name.startswith("."):
                continue
            cfg_path = os.path.join(pdir, "project.json")
            cfg = {}
            if os.path.exists(cfg_path):
                try:
                    with open(cfg_path, "r") as f:
                        cfg = json.load(f)
                except (OSError, json.JSONDecodeError):
                    pass
            # Count ingested docs
            ingested_dir = os.path.join(pdir, "ingested")
            chunk_count = 0
            if os.path.isdir(ingested_dir):
                chunk_count = sum(1 for fn in os.listdir(ingested_dir)
                                  if IngestManager._key_from_filename(fn))
            # Count memory files
            mem_count = sum(1 for fn in os.listdir(pdir) if fn.endswith(".md") and not fn.startswith("ingest-") and fn not in _QMD_IGNORE_FILES)
            # Count ingested source files (unique sources, not chunks)
            doc_count = 0
            if os.path.isdir(ingested_dir):
                seen_sources = set()
                for fn in os.listdir(ingested_dir):
                    k = IngestManager._key_from_filename(fn)
                    if k:
                        seen_sources.add(k)
                doc_count = len(seen_sources) if seen_sources else chunk_count
            visibility = cfg.get("visibility", "global")
            if visibility == "user":
                visibility = "private"   # legacy alias (see get_project)
            owner_uid = cfg.get("owner_user_id", "")
            owner_tid = cfg.get("owner_team_id", "")
            projects.append({
                "id": cfg.get("id", ""),
                "name": name,
                "display_name": cfg.get("name") or name,
                "description": cfg.get("description", ""),
                "instructions": cfg.get("instructions", ""),
                "instruction_files": cfg.get("instruction_files", []) or [],
                "code_mode": bool(cfg.get("code_mode", False)),
                "working_dir": cfg.get("working_dir", "") or "",
                "research_mode": _project_research_mode(cfg),
                "icon": cfg.get("icon", "folder"),
                "image": cfg.get("image", ""),
                "color": cfg.get("color", ""),
                "created_at": cfg.get("created_at", ""),
                "tags": cfg.get("tags", []),
                "watch_folders": cfg.get("watch_folders", []),
                "input_folders": cfg.get("input_folders", []) or [],
                "input_folders_last_scan": cfg.get("input_folders_last_scan", ""),
                "sync_status": cfg.get("sync_status", {}) or {},
                "status": cfg.get("status", "active"),
                "chunks": chunk_count,
                "doc_count": doc_count,
                "memories": mem_count,
                "visibility": visibility,
                "owner_user_id": owner_uid,
                "owner_team_id": owner_tid,
                "extra_member_user_ids": cfg.get("extra_member_user_ids", []) or [],
                "excluded_user_ids": cfg.get("excluded_user_ids", []) or [],
            })
        # Filter by user access if user_id provided
        if user_id is not None:
            team_set = set(user_team_ids or [])
            def _accessible(p):
                if p["owner_user_id"] == user_id:
                    return True
                extras = p.get("extra_member_user_ids") or []
                if user_id in extras:
                    return True
                if p["visibility"] == "global":
                    return user_id not in (p.get("excluded_user_ids") or [])
                if p["visibility"] == "team":
                    return p["owner_team_id"] in team_set
                # visibility == "user"
                return False
            projects = [p for p in projects if _accessible(p)]
        return projects

    @staticmethod
    def create_project(agent_id: str, name: str, description: str = "",
                       config: dict | None = None,
                       visibility: str = "global",
                       owner_user_id: str = "",
                       owner_team_id: str = "") -> dict:
        """Create a new project directory with project.json.
        visibility: 'global', 'user', or 'team'"""
        # Validate name
        safe_name = re.sub(r'[^\w\s-]', '', name).strip().lower().replace(' ', '-')
        if not safe_name:
            return {"error": "Invalid project name"}
        pdir = ProjectManager._project_dir(agent_id, safe_name)
        if os.path.exists(pdir):
            return {"error": f"Project '{safe_name}' already exists"}
        os.makedirs(pdir, exist_ok=True)
        os.makedirs(os.path.join(pdir, "ingested"), exist_ok=True)
        os.makedirs(os.path.join(pdir, "notes"), exist_ok=True)
        cfg = {
            "id": uuid.uuid4().hex[:12],
            "name": config.get("name", name) if config else name,
            "description": description,
            "icon": (config or {}).get("icon", "📁"),
            "created_at": datetime.datetime.now(datetime.timezone.utc).isoformat(),
            "watch_folders": (config or {}).get("watch_folders", []),
            "tags": (config or {}).get("tags", []),
            "model": (config or {}).get("model"),
            "visibility": visibility,
            "owner_user_id": owner_user_id,
            "owner_team_id": owner_team_id,
            "extra_member_user_ids": (config or {}).get("extra_member_user_ids", []) or [],
            "excluded_user_ids": (config or {}).get("excluded_user_ids", []) or [],
        }
        # Code Mode is fixed AT CREATION (a code project never converts to a
        # memory project or vice-versa — they're structurally different). When
        # set, the working_dir (if supplied + valid) is stored too.
        if config and config.get("code_mode"):
            cfg["code_mode"] = True
            _wd = os.path.expanduser(str(config.get("working_dir") or "").strip())
            cfg["working_dir"] = _wd if (_wd and os.path.isdir(_wd)) else ""
        cfg_path = os.path.join(pdir, "project.json")
        with open(cfg_path, "w") as f:
            json.dump(cfg, f, indent=2)
        # Register QMD collection for this project
        collection_name = f"{agent_id}/{safe_name}"
        threading.Thread(
            target=_qmd_ensure_collection,
            args=(collection_name, pdir),
            daemon=True,
        ).start()
        return {"name": safe_name, "status": "created", "path": pdir}

    @staticmethod
    def get_project(agent_id: str, name: str) -> dict | None:
        """Read project.json for a project."""
        pdir = ProjectManager._project_dir(agent_id, name)
        if not os.path.isdir(pdir):
            return None
        cfg_path = os.path.join(pdir, "project.json")
        if not os.path.exists(cfg_path):
            # Auto-create minimal project.json for dirs that exist without one
            cfg = {"name": name, "description": "", "created_at": datetime.datetime.now(datetime.timezone.utc).isoformat()}
            try:
                with open(cfg_path, "w") as f:
                    json.dump(cfg, f, indent=2)
            except OSError:
                pass
        try:
            with open(cfg_path, "r") as f:
                cfg = json.load(f)
            # Backfill a stable globally-unique id on first read. Used as the
            # MemPalace wing key so renaming the project doesn't strand its
            # drawers, and so two same-named projects under different agents
            # never collide. Persisted lazily — if the disk file is read-only
            # we still hand back the in-memory id, but old chats may produce
            # new ids on each read until the file becomes writable.
            # Lazy normalisation of the sharing block: backfill owner +
            # alias legacy visibility value "user" → "private". Persisted
            # alongside the id backfill so we only write once.
            _dirty = False
            if not cfg.get("id"):
                cfg["id"] = uuid.uuid4().hex[:12]
                _dirty = True
            if cfg.get("visibility") == "user":
                cfg["visibility"] = "private"
                _dirty = True
            if _dirty:
                try:
                    with open(cfg_path, "w") as f:
                        json.dump(cfg, f, indent=2)
                except OSError:
                    pass
            # Add computed stats
            ingested_dir = os.path.join(pdir, "ingested")
            chunk_count = 0
            if os.path.isdir(ingested_dir):
                chunk_count = sum(1 for fn in os.listdir(ingested_dir)
                                  if IngestManager._key_from_filename(fn))
            cfg["chunks"] = chunk_count
            cfg["dir"] = pdir
            cfg["folder_name"] = name   # filesystem name; display name is cfg["name"]
            # Surface the resolved research_mode (with legacy migration) so
            # every reader (system-prompt builder, chat handler, HTTP API)
            # sees the same value without re-implementing the rule.
            cfg["research_mode"] = _project_research_mode(cfg)
            return cfg
        except (OSError, json.JSONDecodeError):
            return None

    @staticmethod
    def update_project(agent_id: str, name: str, updates: dict) -> dict:
        """Update project.json fields."""
        pdir = ProjectManager._project_dir(agent_id, name)
        cfg_path = os.path.join(pdir, "project.json")
        if not os.path.exists(cfg_path):
            return {"error": f"Project '{name}' not found"}
        try:
            with open(cfg_path, "r") as f:
                cfg = json.load(f)
            # Snapshot the per-project KG override BEFORE the whitelist loop
            # overwrites it, so we can detect a method/profile switch and
            # invalidate this project's KG cursor (a switch must re-extract —
            # the per-drawer cursor only self-invalidates on source-file change,
            # not on a method/profile change, so without this a rules→llm flip
            # silently keeps the old triples). Empty string = "inherit global".
            _kg_method_old = str(cfg.get("kg_method") or "").strip().lower()
            _kg_profile_old = str(cfg.get("kg_profile") or "").strip().lower()
            for k in ("description", "watch_folders", "tags", "model", "name", "icon",
                       "image", "color",
                       "status", "instructions",
                       "input_folders", "input_folders_last_scan", "sync_status",
                       "visibility", "owner_user_id", "owner_team_id",
                       "extra_member_user_ids", "excluded_user_ids",
                       "research_mode", "web_urls", "disable_web_search",
                       "source_groups", "kg_method", "kg_profile", "doc_style",
                       "instruction_files", "working_dir", "bottom_workspace"):
                if k in updates:
                    cfg[k] = updates[k]
            # Per-project data-source scope (DATA_SOURCES_V2 Phase 4, E2):
            # [{name, tables:[str]}] — the project config DECIDES what is
            # usable in project chats (missing/empty = nothing; no silent
            # global fallback). Names validated against the CONFIGURED
            # sources — an unknown name fails loud instead of silently
            # scoping to nothing.
            if "data_sources" in updates:
                _ds_in = updates.get("data_sources")
                _known = {(s.get("name") or "").strip()
                          for s in (_server_config().get("data_sources") or [])}
                _ds_out = []
                for _e in (_ds_in if isinstance(_ds_in, list) else [])[:50]:
                    if not isinstance(_e, dict):
                        continue
                    _n = str(_e.get("name") or "").strip()
                    if not _n:
                        continue
                    if _n not in _known:
                        return {"error": f"Unbekannte Datenquelle '{_n}' — "
                                         f"konfiguriert sind: "
                                         f"{', '.join(sorted(_known)) or '(keine)'}"}
                    _tabs = [str(t).strip()[:200]
                             for t in (_e.get("tables") or [])[:500]
                             if str(t).strip()]
                    _ds_out.append({"name": _n, "tables": _tabs})
                cfg["data_sources"] = _ds_out
            # NOTE: `code_mode` is intentionally NOT in the update whitelist — it
            # is fixed at creation (create_project) and never toggles afterward
            # (a code project and a memory project are structurally different).
            # `working_dir` IS editable (the user can re-point a code project's
            # directory) — validate it exists.
            if "working_dir" in updates:
                _wd = os.path.expanduser(str(updates.get("working_dir") or "").strip())
                if _wd and not os.path.isdir(_wd):
                    return {"error": f"Working dir does not exist: {_wd}"}
                cfg["working_dir"] = _wd
            # Per-project KG override: method (llm|rules) + profile
            # (normative|generic). Empty string = inherit the global default
            # (config.json mempalace.kg). Coerce to a safe shape so the
            # project-sync daemon never reads a bogus value.
            if "kg_method" in updates:
                _m = str(updates.get("kg_method") or "").strip().lower()
                cfg["kg_method"] = _m if _m in ("llm", "rules") else ""
            if "kg_profile" in updates:
                _p = str(updates.get("kg_profile") or "").strip().lower()
                cfg["kg_profile"] = _p if _p in ("normative", "generic") else ""
            # If the per-project KG method/profile override actually changed,
            # purge this project's KG + closet cursors so the next sync
            # re-extracts everything under the new setting (mirrors the global
            # kg-config-save invalidation in handlers/admin_observability.py;
            # the per-project edit path previously had none — the rules→llm
            # switch that kept stale triples). Best-effort: a failure here must
            # not block the project-settings save itself.
            _kg_method_new = str(cfg.get("kg_method") or "").strip().lower()
            _kg_profile_new = str(cfg.get("kg_profile") or "").strip().lower()
            if (_kg_method_new != _kg_method_old
                    or _kg_profile_new != _kg_profile_old):
                _pid = cfg.get("id") or ""
                if _pid:
                    try:
                        from engine import kg_extract as _kg
                        _mp = _load_mempalace_config() or {}
                        _palace = _mp.get("palace_path", "")
                        _chats_db = os.path.join(AGENTS_DIR, "main", "chats.db")
                        _wing = f"project__{_pid}"
                        _kg.kg_purge_for_scope(
                            palace_path=_palace, source_prefix="",
                            adapter_name="brain-project-kg",
                            chats_db_path=_chats_db, wing=_wing)
                        _kg.closet_regen_purge_for_scope(
                            chats_db_path=_chats_db, palace_wing=_wing)
                        print(f"[project] KG override changed for {name} "
                              f"(method {_kg_method_old or 'inherit'}→"
                              f"{_kg_method_new or 'inherit'}, profile "
                              f"{_kg_profile_old or 'inherit'}→"
                              f"{_kg_profile_new or 'inherit'}) — "
                              f"KG+closet cursors purged, will re-extract on "
                              f"next sync", flush=True)
                    except Exception as _ie:
                        print(f"[project] KG cursor invalidation failed for "
                              f"{name}: {type(_ie).__name__}: {_ie}", flush=True)
            # source_groups (virtual-folder tree for the source-panel UI):
            # sanitise to a stable shape + enforce the ≤3-level depth invariant
            # so a malformed client payload can't corrupt project.json or build
            # an un-renderable tree.
            if "source_groups" in updates:
                cfg["source_groups"] = _sanitise_source_groups(updates["source_groups"])
            # Coerce research_mode to bool so the on-disk shape is stable.
            if "research_mode" in updates:
                cfg["research_mode"] = bool(updates["research_mode"])
            # GDPR project presets were REMOVED in 9.348.0 (user call: the
            # rule/category action matrix in Settings → GDPR is the single
            # enforcement mechanism; a per-project posture layer would either
            # go unused or be circumvented). Strip any legacy field on save.
            cfg.pop("gdpr_preset", None)
            with open(cfg_path, "w") as f:
                json.dump(cfg, f, indent=2)
            return {"name": name, "status": "updated"}
        except (OSError, json.JSONDecodeError) as e:
            return {"error": str(e)}

    @staticmethod
    def delete_project(agent_id: str, name: str) -> dict:
        """Soft-delete a project (move to .trash)."""
        pdir = ProjectManager._project_dir(agent_id, name)
        if not os.path.isdir(pdir):
            return {"error": f"Project '{name}' not found"}
        trash_dir = os.path.join(AGENTS_DIR, ".trash")
        os.makedirs(trash_dir, exist_ok=True)
        dest = os.path.join(trash_dir, f"{agent_id}_project_{name}_{int(time.time())}")
        shutil.move(pdir, dest)
        # (qmd reverted — no collection to remove)
        return {"name": name, "status": "deleted", "moved_to": dest}


class NoteManager:
    """CRUD operations for project notes (markdown files in notes/ subdirectory)."""

    @staticmethod
    def _notes_dir(agent_id: str, project_name: str) -> str:
        return os.path.join(AGENTS_DIR, agent_id, "projects", project_name, "notes")

    @staticmethod
    def list_notes(agent_id: str, project_name: str) -> list[dict]:
        """Walk notes/ tree recursively, return metadata for each .md file."""
        notes_dir = NoteManager._notes_dir(agent_id, project_name)
        if not os.path.isdir(notes_dir):
            return []
        results = []
        for dirpath, _, filenames in os.walk(notes_dir):
            for fname in sorted(filenames):
                if not fname.endswith(".md"):
                    continue
                fpath = os.path.join(dirpath, fname)
                rel_path = os.path.relpath(fpath, notes_dir)
                try:
                    stat = os.stat(fpath)
                    with open(fpath, "r", errors="replace") as f:
                        raw = f.read(2000)
                    fm, _ = _parse_frontmatter(raw)
                    results.append({
                        "path": rel_path,
                        "name": fm.get("name", fname.replace(".md", "")),
                        "type": fm.get("type", "note"),
                        "size": stat.st_size,
                        "created_at": fm.get("created_at", ""),
                        "updated_at": fm.get("updated_at", ""),
                    })
                except Exception:
                    continue
        return results

    @staticmethod
    def get_note(agent_id: str, project_name: str, path: str) -> dict | None:
        """Read a note file and return its content with metadata."""
        notes_dir = NoteManager._notes_dir(agent_id, project_name)
        fpath = os.path.join(notes_dir, path)
        if not os.path.isfile(fpath):
            return None
        try:
            stat = os.stat(fpath)
            with open(fpath, "r", errors="replace") as f:
                raw = f.read()
            fm, body = _parse_frontmatter(raw)
            return {
                "path": path,
                "name": fm.get("name", os.path.basename(path).replace(".md", "")),
                "content": body,
                "frontmatter": fm,
                "size": stat.st_size,
                "created_at": fm.get("created_at", ""),
                "updated_at": fm.get("updated_at", ""),
            }
        except Exception:
            return None

    @staticmethod
    def create_note(agent_id: str, project_name: str, path: str, content: str = "") -> dict:
        """Create a note with YAML frontmatter, entity extraction, and QMD reindex."""
        notes_dir = NoteManager._notes_dir(agent_id, project_name)
        fpath = os.path.join(notes_dir, path)
        # Create parent dirs if needed
        os.makedirs(os.path.dirname(fpath), exist_ok=True)
        if os.path.exists(fpath):
            return {"error": f"Note '{path}' already exists"}

        now = datetime.datetime.now(datetime.timezone.utc).isoformat()
        name = os.path.basename(path).replace(".md", "")
        md_content = f"""---
name: {_yaml_escape(name)}
type: note
created_at: {now}
updated_at: {now}
agent: {agent_id}
project: {project_name}
---

{content}
"""
        with open(fpath, "w") as f:
            f.write(md_content)

        # Entity extraction + auto-link
        try:
            entities = _extract_entities(content)
            if entities:
                filename = os.path.basename(fpath)
                matches = _find_entity_matches(agent_id, filename, entities)
                for other_fname in matches[:10]:
                    other_path = os.path.join(os.path.dirname(fpath), other_fname)
                    if not os.path.exists(other_path):
                        # Try agent dir
                        other_path = os.path.join(AGENTS_DIR, agent_id, other_fname)
                    if os.path.exists(other_path):
                        _add_related_to_file(fpath, other_fname, "same_topic")
                        _add_related_to_file(other_path, filename, "same_topic")
                _update_entity_index(agent_id, filename, entities)
        except Exception:
            pass

        # Add same_folder relationships with sibling notes
        try:
            folder = os.path.dirname(fpath)
            fname = os.path.basename(fpath)
            for sibling in os.listdir(folder):
                if sibling.endswith(".md") and sibling != fname:
                    sibling_path = os.path.join(folder, sibling)
                    _add_related_to_file(fpath, sibling, "same_folder")
                    _add_related_to_file(sibling_path, fname, "same_folder")
        except Exception:
            pass

        # Trigger QMD reindex
        collection = f"{agent_id}/{project_name}"
        _qmd_debounced_embed(collection)

        return {"path": path, "status": "created"}

    @staticmethod
    def update_note(agent_id: str, project_name: str, path: str, content: str) -> dict:
        """Update a note's content, preserving frontmatter and updating timestamp."""
        notes_dir = NoteManager._notes_dir(agent_id, project_name)
        fpath = os.path.join(notes_dir, path)
        if not os.path.isfile(fpath):
            return {"error": f"Note '{path}' not found"}

        try:
            with open(fpath, "r") as f:
                raw = f.read()
            fm, _ = _parse_frontmatter(raw)
        except Exception:
            fm = {}

        now = datetime.datetime.now(datetime.timezone.utc).isoformat()
        fm["updated_at"] = now

        # Rebuild frontmatter
        fm_lines = []
        for k, v in fm.items():
            if k == "related":
                continue  # related is multi-line, handle separately
            fm_lines.append(f"{k}: {v}")

        # Preserve related section if it exists
        related_section = ""
        fm_match = re.match(r'^---\s*\n(.*?)\n---\s*\n', raw, re.DOTALL)
        if fm_match:
            fm_text = fm_match.group(1)
            rel_match = re.search(r'(related:.*)', fm_text, re.DOTALL)
            if rel_match:
                related_section = "\n" + rel_match.group(1)

        md_content = f"---\n" + "\n".join(fm_lines) + related_section + f"\n---\n\n{content}\n"
        with open(fpath, "w") as f:
            f.write(md_content)

        # Re-run entity extraction
        try:
            entities = _extract_entities(content)
            if entities:
                filename = os.path.basename(fpath)
                _update_entity_index(agent_id, filename, entities)
        except Exception:
            pass

        # Trigger QMD reindex
        collection = f"{agent_id}/{project_name}"
        _qmd_debounced_embed(collection)

        return {"path": path, "status": "updated"}

    @staticmethod
    def delete_note(agent_id: str, project_name: str, path: str) -> dict:
        """Remove a note file and trigger QMD reindex."""
        notes_dir = NoteManager._notes_dir(agent_id, project_name)
        fpath = os.path.join(notes_dir, path)
        if not os.path.isfile(fpath):
            return {"error": f"Note '{path}' not found"}

        os.remove(fpath)

        # Clean up empty parent directories
        parent = os.path.dirname(fpath)
        while parent != notes_dir:
            try:
                if not os.listdir(parent):
                    os.rmdir(parent)
                    parent = os.path.dirname(parent)
                else:
                    break
            except Exception:
                break

        # Trigger QMD reindex
        collection = f"{agent_id}/{project_name}"
        _qmd_debounced_embed(collection)

        return {"path": path, "status": "deleted"}

    @staticmethod
    def rename_note(agent_id: str, project_name: str, old_path: str, new_path: str) -> dict:
        """Rename/move a note file and update its frontmatter name."""
        notes_dir = NoteManager._notes_dir(agent_id, project_name)
        old_fpath = os.path.join(notes_dir, old_path)
        new_fpath = os.path.join(notes_dir, new_path)
        if not os.path.isfile(old_fpath):
            return {"error": f"Note '{old_path}' not found"}
        if os.path.exists(new_fpath):
            return {"error": f"Note '{new_path}' already exists"}

        # Create parent dirs for new path if needed
        os.makedirs(os.path.dirname(new_fpath), exist_ok=True)
        os.rename(old_fpath, new_fpath)

        # Update frontmatter name field
        try:
            with open(new_fpath, "r") as f:
                raw = f.read()
            new_name = os.path.basename(new_path).replace(".md", "")
            raw = re.sub(r'^(name:\s*).*$', rf'\g<1>{_yaml_escape(new_name)}', raw, count=1, flags=re.MULTILINE)
            now = datetime.datetime.now(datetime.timezone.utc).isoformat()
            raw = re.sub(r'^(updated_at:\s*).*$', rf'\g<1>{now}', raw, count=1, flags=re.MULTILINE)
            with open(new_fpath, "w") as f:
                f.write(raw)
        except Exception:
            pass

        # Trigger QMD reindex
        collection = f"{agent_id}/{project_name}"
        _qmd_debounced_embed(collection)

        return {"old_path": old_path, "new_path": new_path, "status": "renamed"}

    @staticmethod
    def create_folder(agent_id: str, project_name: str, folder_path: str) -> dict:
        """Create a folder within the notes directory."""
        notes_dir = NoteManager._notes_dir(agent_id, project_name)
        fpath = os.path.join(notes_dir, folder_path)
        os.makedirs(fpath, exist_ok=True)
        return {"path": folder_path, "status": "created"}


