# --- Warmup Registry ---
#
# Per-PREFIX warmup state tracker. A background keeper daemon (in server.py)
# fires minimal prefill requests against local model endpoints so the first
# real user turn hits a warm KV cache and time-to-first-token is minimised.
# Each model's warmup is opt-in via models_config[id].warmup.
#
# WHY prefix-keyed and not model-keyed:
#   The thing that's actually warm on the GPU is a *KV prefix* — the tokenised
#   (system prompt + tools [+ enable_thinking]) the prefill primed. The SAME
#   model can be needed under several different prefixes within one session:
#   a bare chat, a project chat (project instructions in the system prompt), a
#   thinking-on turn (oMLX enable_thinking changes the tokens). Tracking state
#   by model alone made every prefix-changing context switch *look* like the
#   model "went cold", so the keeper / session-warmup kept re-priming a prefix
#   that was actually already warm — the mid-session re-warm the user saw.
#   Keying by (model, prefix_id) makes the only decision "is THIS prefix warm?"
#   — no per-scenario special-casing.
#
# Shape: _warmup_state[model] = { prefix_id: {state, mode, last_warmup_ts,
#   last_used_ts, last_error, thinking_primed, minimal} }
# State values: "idle"/absent (never warmed), "warming", "warm", "failed",
# "skipped_cloud".
#
# `minimal` mode (weights-only, no system/tools prefix) is a degenerate prefix:
# it primes nothing the KV cache reuses, only the resident weights — which a
# `full` prime of ANY prefix on the same model already covers. So a minimal
# need is satisfied by any warm full prefix on the model (the SUBSET rule in
# prefix_is_warm), and a minimal prime is recorded under the sentinel prefix
# id MINIMAL_PREFIX_ID rather than a real hash.

import hashlib as _hashlib

_warmup_state: dict[str, dict] = {}
_warmup_state_lock = threading.Lock()

# Sentinel prefix id for weights-only ("minimal") primes — they have no real
# system/tools prefix to hash.
MINIMAL_PREFIX_ID = "__minimal__"


def compute_prefix_id(system_prompt: str, active_tool_names,
                      thinking_in_prefix: bool) -> str:
    """Canonical id of a KV prefix.

    Two primes share a prefix id IFF they would prime byte-identical KV — i.e.
    same system prompt, same active tool-name set, same enable_thinking (only
    when thinking actually changes the tokenised prefix; see
    prefix_thinking_relevant). Tool *names* (sorted) stand in for the full tool
    serialization: build_first_turn_prefix guarantees the name set determines
    the wire tools, and the OpenAI/Anthropic shape difference is KV-irrelevant
    (same rationale as build_first_turn_prefix's is_openai_shape note).
    """
    h = _hashlib.sha1()
    h.update((system_prompt or "").encode("utf-8"))
    h.update(b"\x00")
    for n in sorted(active_tool_names or []):
        h.update(n.encode("utf-8"))
        h.update(b"\x00")
    h.update(b"\x01think" if thinking_in_prefix else b"\x00nothink")
    return h.hexdigest()[:16]


def prefix_thinking_relevant(model: str) -> bool:
    """Does toggling thinking actually change this model's KV prefix?

    Only for oMLX-style providers that accept chat_template_kwargs AND a
    non-`none` thinking_format — there `enable_thinking` is rendered INTO the
    tokenised prompt (see _apply_inference_to_payload). For cloud reasoning
    formats (mistral_blocks / reasoning_field over a non-template provider) the
    toggle is just an API field (reasoning_effort) and leaves the prefix
    unchanged, so it must NOT enter the prefix id (else a harmless toggle would
    fork the warm prefix and trigger a pointless re-prime).
    """
    cfg = _models_config.get(model, {}) or {}
    if cfg.get("thinking_format", "none") == "none":
        return False
    prov = resolve_provider_for_model(model) or {}
    return _provider_supports_chat_template_kwargs(prov.get("provider_name", ""))


# --- Provider Concurrency Queue ---
#
# Local LLM gateways (oMLX, cliproxyapi) typically cannot process multiple
# /chat/completions in parallel even when multiple models are loaded. We
# serialize per-provider via a semaphore + strict-FIFO waitlist so concurrent
# chats/delegates/warmups line up instead of fighting for the same GPU.
#
# Config (config.json → providers.<name>.max_concurrent):
#   0         (default)  unlimited — no queue
#   >=1                  cap at N simultaneous calls
#
# Tickets carry (provider, label, session_id, agent_id, user_id, model,
# enqueued_at). While a ticket waits, the queue emits queue_wait events via
# event_callback so the UI can show "waiting in queue, position 3 of 5".

_PROVIDER_QUEUE_TIMEOUT_DEFAULT = 300  # seconds


class _ProviderTicket:
    __slots__ = ("id", "provider", "label", "session_id", "agent_id",
                 "user_id", "model", "enqueued_at", "acquired_at",
                 "released_at", "event_callback", "cancel_token",
                 "_released", "_position", "_admin_cancelled",
                 "_admin_cancel_reason")

    def __init__(self, provider, label, session_id, agent_id, user_id, model,
                 event_callback=None, cancel_token=None):
        self.id = uuid.uuid4().hex[:12]
        self.provider = provider
        self.label = label
        self.session_id = session_id
        self.agent_id = agent_id
        self.user_id = user_id
        self.model = model
        self.enqueued_at = time.time()
        self.acquired_at = 0.0
        self.released_at = 0.0
        self.event_callback = event_callback
        self.cancel_token = cancel_token
        self._released = False
        self._position = 0  # last-emitted position (1-based); 0 = none yet
        self._admin_cancelled = False
        self._admin_cancel_reason = ""


class _ProviderQueueSlot:
    """Per-provider serialization primitive + FIFO waitlist."""

    def __init__(self, provider: str, max_concurrent: int):
        self.provider = provider
        self.max_concurrent = max(1, int(max_concurrent))
        self._sem = threading.Semaphore(self.max_concurrent)
        self._lock = threading.Lock()
        self._waiters: list[_ProviderTicket] = []  # FIFO
        self._active: list[_ProviderTicket] = []
        # Wall-clock of the last non-warmup ticket release. Read by the
        # warmup keeper to back off when real user load just finished —
        # prevents the keeper from snapping into the gap between two
        # close-together user turns (e.g. mid-eval-run).
        self.last_release_ts: float = 0.0

    def snapshot(self) -> dict:
        with self._lock:
            now = time.time()
            return {
                "provider": self.provider,
                "max_concurrent": self.max_concurrent,
                "active_count": len(self._active),
                "waiting_count": len(self._waiters),
                "active": [
                    {
                        "id": t.id,
                        "label": t.label,
                        "session_id": t.session_id,
                        "agent_id": t.agent_id,
                        "user_id": t.user_id,
                        "model": t.model,
                        "age_ms": int((now - (t.acquired_at or t.enqueued_at)) * 1000),
                    }
                    for t in self._active
                ],
                "waiting": [
                    {
                        "id": t.id,
                        "label": t.label,
                        "session_id": t.session_id,
                        "agent_id": t.agent_id,
                        "user_id": t.user_id,
                        "model": t.model,
                        "age_ms": int((now - t.enqueued_at) * 1000),
                        "position": i + 1,
                    }
                    for i, t in enumerate(self._waiters)
                ],
            }


class LocalProviderQueue:
    """Per-provider concurrency gate + FIFO waitlist.

    Providers opt in via `max_concurrent` in their config.json entry:
      - 0 / missing:  no queue (unlimited), acquire_if is a no-op
      - >= 1:          semaphore cap; extras wait FIFO

    Default is 0 — cloud providers stay unlimited unless explicitly capped.
    Thread-safe; supports cancel_token for clean cancellation while waiting.
    """

    def __init__(self):
        self._slots: dict[str, _ProviderQueueSlot] = {}
        self._lock = threading.Lock()

    def _resolve_max_concurrent(self, provider_name: str) -> int:
        if not provider_name or provider_name == "default":
            return 0
        try:
            cfg_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "config.json")
            with open(cfg_path) as f:
                prov = json.load(f).get("providers", {}).get(provider_name, {})
            return max(0, int(prov.get("max_concurrent", 0) or 0))
        except Exception:
            return 0

    def _get_or_create_slot(self, provider_name: str) -> _ProviderQueueSlot | None:
        max_c = self._resolve_max_concurrent(provider_name)
        if max_c <= 0:
            return None
        with self._lock:
            slot = self._slots.get(provider_name)
            if slot is None or slot.max_concurrent != max_c:
                slot = _ProviderQueueSlot(provider_name, max_c)
                self._slots[provider_name] = slot
            return slot

    def snapshot_all(self) -> dict:
        with self._lock:
            slots = list(self._slots.values())
        # snapshot each slot without holding the outer lock
        return {
            "providers": {s.provider: s.snapshot() for s in slots},
        }

    def provider_busy(self, provider_name: str, grace_seconds: float = 15.0) -> bool:
        """True if the warmup keeper should defer firing on this provider.

        Busy means any of:
          - a non-warmup ticket is currently holding a slot,
          - any ticket is waiting in the FIFO,
          - a non-warmup ticket released within the last `grace_seconds`.

        The grace window keeps the keeper from snapping into the brief gap
        between two close-together user turns (eval runs, multi-turn chats).
        Providers without a queue slot (cloud, max_concurrent=0) return False.
        """
        if not provider_name or provider_name == "default":
            return False
        with self._lock:
            slot = self._slots.get(provider_name)
        if slot is None:
            return False
        with slot._lock:
            non_warmup_active = any(t.label != "warmup" for t in slot._active)
            waiting = len(slot._waiters) > 0
            last_release = slot.last_release_ts
        if non_warmup_active or waiting:
            return True
        if grace_seconds > 0 and last_release > 0 \
                and (time.time() - last_release) < grace_seconds:
            return True
        return False

    def cancel_ticket(self, ticket_id: str, reason: str = "") -> dict:
        """Admin action: cancel a queued or running ticket.

        Waiting: marks the ticket cancelled so the waiting thread raises
          TaskCancelled on its next 200ms loop tick, ~instant.
        Running: fires the ticket's cancel_token (same as pressing the chat's
          stop button). The sidecar proxy's `_watch_cancel` thread polls the
          token and POSTs `/cancel/<turn_id>` to the sidecar, which terminates
          the in-flight Anthropic SDK call.

        Returns a result dict describing what was cancelled.
        """
        with self._lock:
            slots = list(self._slots.values())
        for slot in slots:
            with slot._lock:
                for t in slot._waiters:
                    if t.id == ticket_id:
                        t._admin_cancelled = True
                        t._admin_cancel_reason = reason or "admin cancel"
                        return {
                            "ok": True, "state": "waiting",
                            "ticket_id": ticket_id, "provider": slot.provider,
                            "label": t.label, "session_id": t.session_id,
                        }
                for t in slot._active:
                    if t.id == ticket_id:
                        t._admin_cancelled = True
                        t._admin_cancel_reason = reason or "admin cancel"
                        # Fire the ticket's cancel_token if present — this is
                        # the same signal the per-chat Stop button uses.
                        ct = t.cancel_token
                        fired = False
                        if ct is not None:
                            try:
                                # CancelToken exposes cancel()
                                if hasattr(ct, "cancel"):
                                    ct.cancel()
                                    fired = True
                                else:
                                    # Some watchers just expose .cancelled = True
                                    try:
                                        ct.cancelled = True
                                        fired = True
                                    except Exception:
                                        pass
                            except Exception:
                                pass
                        return {
                            "ok": True, "state": "running",
                            "ticket_id": ticket_id, "provider": slot.provider,
                            "label": t.label, "session_id": t.session_id,
                            "cancel_token_fired": fired,
                        }
        return {"ok": False, "error": "ticket not found", "ticket_id": ticket_id}

    def reset_config(self):
        """Drop all slots; next acquire rebuilds from fresh config."""
        with self._lock:
            # Never destroy a slot while it holds active tickets; just clear
            # so a future acquire rebuilds. Active tickets retain their ref.
            self._slots.clear()

    @contextlib.contextmanager
    def acquire_if(self, provider_name: str, *, label: str,
                   session_id: str | None = None,
                   agent_id: str | None = None,
                   user_id: str | None = None,
                   model: str | None = None,
                   event_callback=None,
                   cancel_token=None,
                   timeout: float | None = None):
        """Block until the provider's semaphore has a free slot.

        No-op if the provider isn't queued (max_concurrent <= 0).

        Scope: wrap *only* the HTTP call to /chat/completions. Release as soon
        as the LLM response completes — don't hold across tool execution or
        nested calls. The gateway's actual bottleneck is one HTTP call at a
        time; tool work happens locally and doesn't consume gateway capacity.
        This also avoids a deadlock where a worker subagent's nested
        send_message (e.g. summariser) would block on the outer chat's slot.

        Emits queue_wait / queue_acquired / queue_released events via
        event_callback. Raises TimeoutError on timeout, TaskCancelled on cancel.
        """
        slot = self._get_or_create_slot(provider_name)
        if slot is None:
            yield None
            return

        ticket = _ProviderTicket(
            provider=provider_name, label=label, session_id=session_id,
            agent_id=agent_id, user_id=user_id, model=model,
            event_callback=event_callback, cancel_token=cancel_token,
        )
        to = float(timeout) if timeout is not None else _PROVIDER_QUEUE_TIMEOUT_DEFAULT

        # Enqueue + emit initial position
        with slot._lock:
            slot._waiters.append(ticket)
            ticket._position = len(slot._waiters)
            waiting_count = len(slot._waiters)
            active_count = len(slot._active)
        self._emit(ticket, "queue_wait", slot, ticket._position,
                   waiting_count, active_count)

        deadline = time.time() + to
        acquired = False
        try:
            # Wait for our turn: we must be the head of the waiter list AND
            # the semaphore must have a free slot.
            while True:
                if cancel_token and getattr(cancel_token, "cancelled", False):
                    raise TaskCancelled()
                if ticket._admin_cancelled:
                    raise TaskCancelled(
                        f"Queue cancel by admin: {ticket._admin_cancel_reason or 'no reason given'}"
                    )
                remaining = deadline - time.time()
                if remaining <= 0:
                    raise TimeoutError(
                        f"Provider '{provider_name}' queue timeout after {to}s "
                        f"(label={label}, position={ticket._position})"
                    )
                # Only the FIFO head is allowed to try acquiring the semaphore;
                # others wait for the head to be popped. Poll every 200ms so we
                # can respond to cancels and re-emit position when it changes.
                with slot._lock:
                    is_head = slot._waiters and slot._waiters[0].id == ticket.id
                    cur_position = 0
                    for i, t in enumerate(slot._waiters):
                        if t.id == ticket.id:
                            cur_position = i + 1
                            break
                if cur_position != ticket._position:
                    ticket._position = cur_position
                    self._emit(ticket, "queue_wait", slot, cur_position,
                               len(slot._waiters), len(slot._active))
                if is_head:
                    got = slot._sem.acquire(timeout=min(0.2, remaining))
                    if got:
                        acquired = True
                        with slot._lock:
                            try:
                                slot._waiters.remove(ticket)
                            except ValueError:
                                pass
                            ticket.acquired_at = time.time()
                            slot._active.append(ticket)
                        self._emit(ticket, "queue_acquired", slot, 0,
                                   len(slot._waiters), len(slot._active))
                        break
                else:
                    # Not the head — sleep briefly and re-check.
                    time.sleep(min(0.2, max(0.05, remaining)))
            yield ticket
        except BaseException:
            # On cancel/timeout/exception before acquisition, remove from waiters.
            if not acquired:
                with slot._lock:
                    try:
                        slot._waiters.remove(ticket)
                    except ValueError:
                        pass
            raise
        finally:
            if acquired and not ticket._released:
                ticket._released = True
                ticket.released_at = time.time()
                with slot._lock:
                    try:
                        slot._active.remove(ticket)
                    except ValueError:
                        pass
                    waiting_count = len(slot._waiters)
                    active_count = len(slot._active)
                    # Track when real user load (not the warmup keeper itself)
                    # last finished on this provider, so the keeper can back
                    # off for a short grace window afterwards.
                    if ticket.label != "warmup":
                        slot.last_release_ts = ticket.released_at
                slot._sem.release()
                self._emit(ticket, "queue_released", slot, 0,
                           waiting_count, active_count)

    def _emit(self, ticket: _ProviderTicket, event_type: str, slot,
              position: int, waiting_count: int, active_count: int):
        cb = ticket.event_callback
        if not cb:
            return
        try:
            cb(event_type, {
                "provider": ticket.provider,
                "label": ticket.label,
                "model": ticket.model,
                "session_id": ticket.session_id,
                "agent_id": ticket.agent_id,
                "position": position,
                "waiting": waiting_count,
                "active": active_count,
                "max_concurrent": slot.max_concurrent,
                "ticket_id": ticket.id,
                "wait_ms": int((time.time() - ticket.enqueued_at) * 1000),
            })
        except Exception:
            pass


_provider_queue = LocalProviderQueue()


def get_provider_queue() -> LocalProviderQueue:
    return _provider_queue


def _blank_warmup_entry() -> dict:
    return {
        "state": "idle",
        "last_warmup_ts": 0,
        "last_used_ts": 0,
        "last_error": "",
        "next_due_ts": 0,
        "mode": "full",
        "thinking_primed": False,
        "minimal": False,
    }


# Rank used to pick the "best" prefix entry for a model when the UI / keeper
# asks model-level (prefix_id=None). A warm full prefix is the most useful
# thing to report; warming next; then everything else.
def _entry_rank(e: dict) -> tuple:
    st = e.get("state", "idle")
    state_score = {"warm": 3, "warming": 2}.get(st, 1)
    full_score = 0 if e.get("minimal") else 1
    recency = max(e.get("last_warmup_ts", 0), e.get("last_used_ts", 0))
    return (state_score, full_score, recency)


def _best_entry(model: str) -> dict:
    """Lock-held: the highest-ranked prefix entry for a model, or a blank."""
    prefixes = _warmup_state.get(model) or {}
    if not prefixes:
        return _blank_warmup_entry()
    return max(prefixes.values(), key=_entry_rank)


def get_warmup_state(model: str, prefix_id: str | None = None) -> dict:
    """Copy of warmup state. With prefix_id → that exact prefix's entry (blank
    if unknown). Without → the model's best entry (UI / coarse callers)."""
    with _warmup_state_lock:
        if prefix_id is not None:
            entry = (_warmup_state.get(model) or {}).get(prefix_id)
            return dict(entry) if entry else _blank_warmup_entry()
        return dict(_best_entry(model))


def set_warmup_state(model: str, prefix_id: str, **fields):
    """Update fields on one (model, prefix_id) warmup entry."""
    with _warmup_state_lock:
        cur = _warmup_state.setdefault(model, {}).setdefault(
            prefix_id, _blank_warmup_entry())
        cur.update(fields)


def prefix_is_warm(model: str, prefix_id: str, *, minimal: bool = False) -> bool:
    """The ONE warmup decision: is the KV prefix the next turn needs already
    primed (and not known-stale)?

    Subset rule: a `minimal` need (weights only, no real prefix) is satisfied by
    ANY warm full prefix on the model — a full prime loaded the weights too. So
    a model that's warm under any full prefix never needs a separate minimal
    prime, and switching from a full chat to a (hypothetically minimal) context
    doesn't re-warm.

    A prefix that's currently `warming` also counts as "don't start another" —
    the in-flight prime will cover it.
    """
    with _warmup_state_lock:
        prefixes = _warmup_state.get(model) or {}
        if minimal:
            # Any warm/warming full prefix covers a minimal need (weights loaded).
            for pid, e in prefixes.items():
                if pid == MINIMAL_PREFIX_ID:
                    continue
                if e.get("state") in ("warm", "warming"):
                    return True
            e = prefixes.get(MINIMAL_PREFIX_ID)
            return bool(e and e.get("state") in ("warm", "warming"))
        e = prefixes.get(prefix_id)
        return bool(e and e.get("state") in ("warm", "warming"))


def mark_prefix_used(model: str, prefix_id: str, *, minimal: bool = False):
    """Call when a real request hits a model under a known prefix. Using the
    prefix keeps it resident on the GPU — using it IS the best warmup — so we
    bump last_used_ts and (if cold/idle) flip it warm so the UI matches reality
    without a redundant prime."""
    now = time.time()
    with _warmup_state_lock:
        cur = _warmup_state.setdefault(model, {}).setdefault(
            prefix_id, _blank_warmup_entry())
        cur["last_used_ts"] = now
        cur["minimal"] = bool(minimal)
        if cur.get("state") in ("idle", "cold", "failed"):
            cur["state"] = "warm"
            cur["last_warmup_ts"] = now
            cur["last_error"] = ""


def evict_prefixes_except(model: str, keep_prefix_id: str):
    """A fresh full prime on `keep_prefix_id` evicts the model's OTHER KV
    prefixes on the GPU (oMLX keeps a bounded number of resident prefixes; a new
    prefill on a different prompt pushes others out via the gateway's LRU). Our
    optimistic mirror must reflect that, or it would keep reporting a stale
    prefix as warm and (worse) suppress a needed re-prime. We demote the others
    to idle but keep their entries so last_used_ts/history survive."""
    with _warmup_state_lock:
        prefixes = _warmup_state.get(model) or {}
        for pid, e in prefixes.items():
            if pid == keep_prefix_id:
                continue
            if e.get("state") in ("warm", "warming"):
                e["state"] = "idle"


def invalidate_model_warmup(model: str):
    """Drop ALL prefix entries for a model. Used when KV-prefix-relevant config
    changed (system prompt / tools / context / provider) — every primed prefix
    is now stale, so the keeper must re-prime from scratch."""
    with _warmup_state_lock:
        _warmup_state.pop(model, None)


def all_warmup_states() -> dict:
    """Per-MODEL snapshot (best prefix entry per model) for the UI, which keys
    its warmup indicators by model id."""
    with _warmup_state_lock:
        return {m: dict(_best_entry(m)) for m in _warmup_state}


def all_prefix_states() -> dict:
    """Full (model → {prefix_id → entry}) snapshot for diagnostics."""
    with _warmup_state_lock:
        return {m: {p: dict(e) for p, e in prefs.items()}
                for m, prefs in _warmup_state.items()}


# Inflight tracker for thinking-mode re-primes — prevents stacking concurrent
# warmups against the same model when a chat toggles thinking rapidly.
_reprime_inflight: set = set()
_reprime_inflight_lock = threading.Lock()


def maybe_reprime_for_thinking(model: str, thinking: bool, agent_id: str = "main",
                               *, system_prompt: str | None = None,
                               active_tool_names=None) -> bool:
    """Pre-warm the prefix the NEXT turn will need when toggling thinking would
    change the KV prefix. No-op when:
      - the model has no warmup configured
      - toggling thinking doesn't change the prefix (cloud reasoning_effort —
        prefix_thinking_relevant False)
      - the target prefix is already warm/warming (prefix_is_warm)
      - a re-prime for this model is already in flight

    The caller passes the turn's resolved system_prompt + active_tool_names so
    we hash the EXACT prefix the next turn will hit (project chat, etc.); when
    omitted we fall back to a bare full prefix.

    Returns True if a re-prime thread was kicked off.
    """
    cfg = _models_config.get(model, {}) or {}
    if not cfg.get("warmup"):
        return False
    if not prefix_thinking_relevant(model):
        return False  # toggle is just an API field — prefix unchanged

    think_in_prefix = bool(thinking)  # relevant by the guard above
    # Hash the prefix the next turn will actually need.
    if system_prompt is None or active_tool_names is None:
        pid = _bare_full_prefix_id(model, agent_id, thinking_in_prefix=think_in_prefix)
        if pid is None:
            return False
    else:
        pid = compute_prefix_id(system_prompt, active_tool_names, think_in_prefix)

    if prefix_is_warm(model, pid):
        return False

    with _reprime_inflight_lock:
        if model in _reprime_inflight:
            return False
        _reprime_inflight.add(model)

    def _bg():
        try:
            allow_cloud = bool(cfg.get("warmup_allow_cloud"))
            mode = (cfg.get("warmup_mode") or "full").lower()
            # A thinking re-prime must prime the REAL prefix (full), not minimal —
            # minimal has no prefix to differ on thinking.
            run_model_warmup(model, allow_cloud=allow_cloud,
                             agent_id=agent_id, mode="full", thinking=thinking)
        finally:
            with _reprime_inflight_lock:
                _reprime_inflight.discard(model)

    threading.Thread(target=_bg, daemon=True,
                     name=f"reprime-{model[:20]}-think{int(thinking)}").start()
    return True


def _bare_full_prefix_id(model: str, agent_id: str = "main", *,
                         thinking_in_prefix: bool = False) -> str | None:
    """Prefix id of the bare main full prefix for a model — the prefix the
    keeper primes and the warm pool hands out. Builds it through the shared
    build_first_turn_prefix so it matches run_model_warmup exactly. Returns None
    if the prefix can't be built (treated as 'unknown' by callers)."""
    try:
        agent_config = AgentConfig(agent_id)
        _ctx = ExecutionContext(mode="chat", agent_id=agent_id,
                                mcp_manager=_mcp_manager)
        with request_context():
            init_thread_context(_ctx, agent_config=agent_config)
            system_prompt, _tools, atn = build_first_turn_prefix(
                model, agent_id,
                mcp_manager=_mcp_manager,
                discovered_tools=set(),
                is_openai_shape=True,
                purpose="interactive",
            )
        return compute_prefix_id(system_prompt, atn, thinking_in_prefix)
    except Exception:
        return None


# --- Shared domain context + tool_context construction -----------------
#
# A scheduled task in a given domain (plain chat vs. project chat) runs the
# SAME domain logic as a chat in that domain — it has no parallel
# implementation. `apply_domain_context` is the single place that turns the
# domain inputs (agent, project, user) into request-context state:
#   - project scope (`project` = name; resolved from project_id for callers
#     that only have the id, like the scheduler)
#   - team_ids (from the user's auth record) → team-scoped MemPalace wings
#   - research_mode_override
#   - the `disable_web_search` project lockout (web tools removed from the
#     active set, additive to any caller-supplied exclude list)
# Both the chat worker and the scheduler fire-path call it, so the two never
# drift. `build_tool_context` then snapshots the request context into the dict
# `run_turn` consumes — again one definition for both callers.

def apply_domain_context(*, agent_id: str, project: str = "",
                         project_id: str = "", user_id: str = "",
                         research_mode_override=None,
                         base_exclude_tools: list | None = None) -> None:
    """Set the domain-determining fields on the ACTIVE request context.

    Must be called inside a `with request_context():` scope. Idempotent-ish:
    overwrites project / team_ids / research_mode_override / exclude_tools.

    project / project_id: pass whichever you have. project_id wins if given
    (resolved to the project NAME — the value every downstream consumer reads).
    base_exclude_tools: names to exclude regardless (e.g. the chat's Websuche
    basket lockout); the project web lockout is unioned on top.
    """
    ctx = get_request_context()
    # 1. Resolve project name. The scheduler stores project_id; the chat passes
    #    the name directly. Either way the request context holds the NAME.
    proj_name = (project or "").strip()
    if project_id and not proj_name:
        try:
            for _p in ProjectManager.list_projects(agent_id):
                if _p.get("id") == project_id:
                    proj_name = _p.get("name") or ""
                    break
        except Exception:
            proj_name = ""
    ctx.project = proj_name

    # 2. Team IDs (team-scoped MemPalace wing visibility). Empty for anon.
    try:
        from server_lib.auth import AuthDB as _AuthDB
        ctx.current_team_ids = [
            t["id"] for t in _AuthDB.get_user_teams(user_id)
        ] if user_id else []
    except Exception:
        ctx.current_team_ids = []

    # 3. Research-mode override (sticky per session; None = project default).
    ctx.research_mode_override = research_mode_override

    # 4. Web-search lockout. Start from any caller-supplied exclusions (the
    #    chat's Websuche-basket lockout), then add the 3 web tools when the
    #    project has `disable_web_search` set. Model-independent enforcement.
    _excl = set(base_exclude_tools or [])
    ctx.working_dir = None
    if proj_name:
        try:
            _pcfg = ProjectManager.get_project(agent_id, proj_name)
        except Exception:
            _pcfg = None
        # Per-turn data-source scope (E8): in a project the PROJECT CONFIG
        # decides which sources/tables db_query may touch (E2 — missing/empty
        # = none usable, deliberately no global fallback). Applies to normal
        # AND code-mode projects. Plain chats: the worker sets the scope from
        # the session selection AFTER this call (Phase 5) — here we only
        # own the project case.
        _scope = {}
        for _e in ((_pcfg or {}).get("data_sources") or []):
            if isinstance(_e, dict) and str(_e.get("name") or "").strip():
                _scope[str(_e["name"]).strip()] = [
                    str(t) for t in (_e.get("tables") or [])]
        ctx.data_source_scope = _scope or None
        if _pcfg and _pcfg.get("disable_web_search"):
            _excl |= set(WEB_SEARCH_TOOLS)
        # Code Mode: point file tools at the project's working directory and
        # remove the MemPalace tools (this project doesn't use project memory —
        # the model reads/edits files directly in working_dir + reads BRAIN.md
        # from the system prompt). File/code/web tools stay live.
        if _pcfg and _pcfg.get("code_mode"):
            _wd = (_pcfg.get("working_dir") or "").strip()
            if _wd and os.path.isdir(_wd):
                ctx.working_dir = _wd
            _excl |= {"mempalace_query", "save_chat_to_memory",
                      "mempalace_get_drawer", "mempalace_list_drawers",
                      "read_document"}
            # Code-intelligence per-tenant scoping: this code-mode project gets
            # its own codebase-memory index under its project dir (never the
            # global brain-source index). request_context.code_graph_db carries
            # the tenant CBM_CACHE_DIR (repurposed from the old sqlite path).
            # Promote the code_* tools in-prompt here — they ship `deferred` for
            # the interactive purpose (a normal chat doesn't pay for them and the
            # warm KV prefix stays identical), but code mode is exactly where
            # code retrieval is wanted.
            _pdir = _pcfg.get("dir") or ProjectManager._project_dir(agent_id, proj_name)
            _cbm_cache = os.path.join(_pdir, ".cbm-cache")
            ctx.code_graph_db = _cbm_cache
            # run_background_task is undeferred here too: the classifier's
            # group mapping rarely flags `delegation` for analysis/report
            # prompts, which silently removed the tool from the wire — the
            # model can't choose the subagent-pane path it cannot see (live
            # incident: SQL dependency-report turn on gpt-5.6-luna, classifier
            # tools=[memory,files,code_graph,python] → run_background_task
            # deferred → inline despite the point-5 nudge). Code mode is
            # exactly where detaching long work is wanted (panes visualize it).
            ctx.undefer_tools = list((ctx.undefer_tools or []) + [
                "code_search", "code_trace", "code_query", "code_snippet",
                "ast_grep_search", "ast_grep_replace", "run_background_task",
                "retry_background_task"])
            # Build the index on first code-mode entry (idempotent + fast,
            # incremental). Repos may not be git, so we don't rely on cbm's
            # git-watcher — index explicitly. Best-effort; failure must not break
            # the turn (tools will report "no index" and the user can re-index).
            try:
                if _wd and os.path.isdir(_wd) and not os.path.isdir(_cbm_cache):
                    cbm_index_repository(_wd, cache_dir=_cbm_cache)
            except Exception:
                pass
    ctx.exclude_tools = list(_excl) if _excl else None


def build_tool_context(*, session_id: str, agent_id: str, user_id: str = "",
                       gdpr_mapping_id: str = "") -> dict:
    """Snapshot the active request context into the tool_context dict that
    `run_turn` passes to the sidecar. Single definition for chat + scheduler so
    the per-tool-call context rebuild is identical in both. Reads project,
    team_ids, note_context, workflow_run_id, plan_mode, research_mode_override,
    execution_overrides, attachment_image_model, caveman_* off the context —
    so whatever `apply_domain_context` (and the caller) set is reflected."""
    ctx = get_request_context()
    return {
        "session_id": session_id,
        "agent_id": agent_id,
        "user_id": user_id or "",
        "team_ids": list(ctx.current_team_ids or []),
        "project": ctx.project or "",
        "working_dir": ctx.working_dir or "",
        "code_graph_db": ctx.code_graph_db or "",
        "note_context": ctx.note_context,
        "workflow_run_id": ctx.workflow_run_id or "",
        "plan_mode": bool(ctx.plan_mode),
        "data_source_scope": ctx.data_source_scope,
        "research_mode_override": ctx.research_mode_override,
        "execution_overrides": ctx.execution_overrides or {},
        "attachment_image_model": ctx.attachment_image_model or "",
        "caveman_chat": int(ctx.caveman_chat or 0),
        "caveman_system": int(ctx.caveman_system or 0),
        "gdpr_mapping_id": gdpr_mapping_id or "",
    }


def build_first_turn_prefix(model: str, agent_id: str, *,
                            mcp_manager=None,
                            discovered_tools: set | None = None,
                            is_openai_shape: bool = False,
                            purpose: str = "interactive",
                            system_prompt_override: str | None = None,
                            breakdown: dict | None = None):
    """SINGLE source of truth for the first-turn KV prefix (system prompt +
    active tools). Both the warm-pool prime (`run_model_warmup`) and the live
    chat worker call this so their prefixes are byte-identical — the entire
    point of warmup. Any input that one caller sets and the other doesn't is a
    silent cache-miss; centralising the recipe here makes that impossible.

    Binds `get_request_context()._current_model = model` so `_get_token_config`
    resolves the SAME model-profile overlay (deferred_tool_groups, etc.) in
    both paths. Caller is responsible for the thread-context (`current_agent`,
    mcp_manager) being set, and for restoring/clearing `_current_model`.

    `is_openai_shape` affects only the tool serialization shape, NOT the tool
    names or the system-prompt text — so it's safe for the two callers to
    differ there (warmup hits oMLX's OpenAI endpoint; the turn goes through the
    Anthropic-shape sidecar). The KV-prefix-relevant outputs (system_prompt +
    active_tool_names) are shape-independent.

    Returns (system_prompt, active_tools, active_tool_names).
    """
    get_request_context()._current_model = model
    active_tools = resolve_active_tools(
        purpose=purpose,
        agent_id=agent_id,
        discovered_tools=discovered_tools if discovered_tools is not None else set(),
        mcp_manager=mcp_manager,
        is_openai_shape=is_openai_shape,
        breakdown=breakdown,
    )
    active_tool_names = {
        (t.get("function", {}) or {}).get("name", "") or t.get("name", "")
        for t in active_tools
    }
    # Brainy (purpose="helpdesk") ships a FIXED system prompt from config, not
    # the agent's _build_system_prompt — so its warmup prime must mirror that
    # exact text, else the KV prefix misses on the first Brainy turn.
    if system_prompt_override is not None:
        system_prompt = system_prompt_override
    else:
        system_prompt = _build_system_prompt(
            include_memory_summary=True,
            purpose=purpose,
            active_tool_names=active_tool_names,
        )
    return system_prompt, active_tools, active_tool_names


def run_model_warmup(model: str, allow_cloud: bool = False,
                     agent_id: str = "main", timeout: int = 30,
                     mode: str = "full", thinking: bool = False,
                     purpose: str = "interactive",
                     track_state: bool = True) -> dict:
    """Fire a single prefill request against a model's provider.

    Returns a result dict: {ok, state, duration_ms, error, mode}. Updates
    _warmup_state.

    `mode` controls the payload shape:
      - "full":    system prompt + tools + "." user. Primes the KV cache so
                   the user's first real turn reuses the prefix. Best when
                   exactly one warmup model is active (its KV stays resident).
      - "minimal": 1-token user ("."), no system, no tools. Only loads the
                   model's weights into GPU memory — no KV prefix primed.
                   Used when multiple warmup models are active, because they'd
                   evict each other's KV cache anyway, so paying the prefill
                   cost is wasted work.

    `thinking` (oMLX thinking-capable models only): when True, the warmup
    payload sets chat_template_kwargs.enable_thinking=true so the primed KV
    prefix matches a chat that has thinking enabled. Without this match, the
    first thinking-on turn cache-misses and pays full prefill cost.
    """
    t0 = time.time()
    is_minimal = (mode != "full")
    thinking_in_prefix = bool(thinking) and prefix_thinking_relevant(model)
    # Prefix id keys the warmup state entry. For minimal primes (no real
    # system/tools prefix) we use the sentinel; for full primes it's the hash of
    # the prefix we're about to build — computed once the prefix is known, below.
    prefix_id = MINIMAL_PREFIX_ID if is_minimal else None

    # The helpdesk (Brainy) side-prime warms a DIFFERENT prefix (its own system
    # prompt + tool set) — now naturally a distinct prefix_id, so it no longer
    # clobbers the main prefix's state. track_state=False is still honoured for
    # callers (helpdesk) that want zero state writes at all.
    def _set_state(pid, **k):
        if track_state and pid is not None:
            set_warmup_state(model, pid, **k)
    prov = resolve_provider_for_model(model)
    base_url = prov.get("base_url", "")
    api_key = prov.get("api_key", "")

    if not base_url:
        err = "no base_url"
        _set_state(prefix_id, state="failed", last_error=err, minimal=is_minimal)
        return {"ok": False, "state": "failed", "error": err, "duration_ms": 0, "mode": mode}

    # `prov` (resolve_provider_for_model) returns only {api_key, base_url,
    # provider_name} — it has NO is_local key, so prov.get("is_local") was
    # always False and every model was treated as cloud (warmup skipped unless
    # warmup_allow_cloud was set). Same bug class as the v8.8.0 is_model_local
    # fix. Use the authoritative resolver, which reads the provider's is_local
    # flag from config by name.
    if not allow_cloud and not is_model_local(model):
        _set_state(prefix_id, state="skipped_cloud",
                   last_error="cloud provider (warmup.allow_cloud=false)",
                   minimal=is_minimal)
        return {"ok": False, "state": "skipped_cloud",
                "error": "cloud skipped", "duration_ms": 0, "mode": mode}

    # For minimal we already know the prefix id; mark it warming now. For full
    # we mark warming after the prefix is built (prefix_id known).
    if is_minimal:
        _set_state(prefix_id, state="warming", last_error="", mode=mode,
                   thinking_primed=bool(thinking), minimal=True)

    try:
        agent_config = AgentConfig(agent_id)
        # Reuse the process-global MCP manager so warmup's tool list matches
        # the real chat payload. Without this, the KV prefix differs (MCP
        # tools are in the real request but not the warmup) and oMLX's
        # prompt cache misses on the first turn — defeating warmup entirely.
        mcp_mgr = _mcp_manager if mode == "full" else None
        _warmup_ctx = ExecutionContext(
            mode="chat",
            agent_id=agent_id,
            mcp_manager=mcp_mgr,
        )
        with request_context():
            init_thread_context(_warmup_ctx, agent_config=agent_config)
            # Caveman no longer touches the system prompt (v9.121.0 — it's a
            # trailing wire-only suffix on the user message), so warmup needs NO
            # caveman handling: the primed system-prompt prefix is byte-identical
            # to every turn regardless of caveman level.

            if mode == "full":
                # Build the prefix through the SHARED helper so it is byte-identical
                # to the live chat worker's first-turn prefix (the chat worker calls
                # the same build_first_turn_prefix). discovered_tools=set() matches
                # turn 0 (nothing discovered yet); mcp_manager + model binding are
                # handled inside the helper. Tool wire-shape (openai) differs from
                # the sidecar's anthropic shape but does NOT affect the KV-relevant
                # system_prompt / tool-name set.
                #
                # purpose="helpdesk": prime BRAINY's prefix instead — its fixed
                # read-only tool set + the helpdesk system prompt from config (NOT
                # the agent's _build_system_prompt). Mirrors handlers/helpdesk.py
                # so the first Brainy turn on a local model hits the warm prefix.
                _sp_override = None
                if purpose == "helpdesk":
                    try:
                        from handlers.helpdesk import _load_helpdesk_config
                        _sp_override = _load_helpdesk_config()["system_prompt"]
                    except Exception:
                        _sp_override = None
                system_prompt, all_tools, _ = build_first_turn_prefix(
                    model, agent_id,
                    mcp_manager=mcp_mgr,
                    discovered_tools=set(),
                    is_openai_shape=True,
                    purpose=purpose,
                    system_prompt_override=_sp_override,
                )
                messages = [
                    {"role": "system", "content": system_prompt},
                    {"role": "user", "content": "."},
                ]
                # Now that the prefix is built, key the state by its hash and
                # mark it warming. active_tool_names from build_first_turn_prefix
                # is the canonical name set (we discard `all_tools` shape here).
                _atn = {(t.get("function", {}) or {}).get("name", "") or t.get("name", "")
                        for t in (all_tools or [])}
                prefix_id = compute_prefix_id(system_prompt, _atn, thinking_in_prefix)
                _set_state(prefix_id, state="warming", last_error="", mode=mode,
                           thinking_primed=bool(thinking), minimal=False)
            else:  # "minimal"
                # Weights-only prime: no system prompt, no tools. all_tools must
                # still be bound (the shared payload-build below reads it) — empty
                # so no `tools` key is added.
                messages = [{"role": "user", "content": "."}]
                all_tools = []

            endpoint = f"{base_url}/chat/completions"
            # Match send_message: stream=True + stream_options so the tokenised
            # request shape is identical to what the real first turn sends.
            # max_tokens=8 is fine — the KV prefix covers system+tools+user and
            # doesn't depend on the output-length budget.
            payload = {
                "model": get_api_model_id(model),
                "max_tokens": 8,
                "messages": messages,
                "stream": True,
                "stream_options": {"include_usage": True},
            }
            if all_tools:
                payload["tools"] = all_tools
            model_cfg = resolve_model_settings(model)
            if all_tools and model_cfg.get("parallel_tool_calls", True):
                payload["parallel_tool_calls"] = True
            # KV-prefix stability: real chat requests now go through
            # _apply_inference_to_payload, which forces enable_thinking on/off for
            # oMLX thinking-capable models. The warmup payload must mirror that
            # exactly or the prefix won't match and prompt cache will miss.
            # When `thinking=True` we inject the same legacy flag the chat path
            # uses so the helper renders enable_thinking=true into the payload.
            provider_name = prov.get("provider_name", "")
            _inf = get_inference_params(model)
            if thinking:
                _inf = dict(_inf)
                _inf["thinking"] = True
                _inf["thinking_level"] = "high"
            _apply_inference_to_payload(payload, _inf, provider_name, scoped_model=model)
            headers = make_headers(api_key)
            data = json.dumps(payload).encode("utf-8")
            req = urllib.request.Request(endpoint, data=data, headers=headers, method="POST")
            _provider_name = prov.get("provider_name", "") or "default"
            with _provider_queue.acquire_if(
                _provider_name, label="warmup",
                session_id=None, agent_id=agent_id, user_id=None,
                model=model, event_callback=None, cancel_token=None,
                timeout=max(timeout * 2, 60),
            ):
                with urllib.request.urlopen(req, timeout=timeout) as resp:
                    resp.read()
            dur_ms = int((time.time() - t0) * 1000)
            now = time.time()
            _set_state(prefix_id, state="warm", last_warmup_ts=now,
                       last_error="", mode=mode,
                       thinking_primed=bool(thinking), minimal=is_minimal)
            # A full prime evicts the model's other resident KV prefixes on the
            # GPU — reflect that so the mirror doesn't report a stale prefix as
            # warm. Minimal primes touch no prefix, so they evict nothing.
            if track_state and not is_minimal and prefix_id is not None:
                evict_prefixes_except(model, prefix_id)
            return {"ok": True, "state": "warm", "duration_ms": dur_ms,
                    "error": "", "mode": mode, "thinking": bool(thinking)}
    except urllib.error.HTTPError as e:
        try:
            body = e.read().decode("utf-8", errors="replace")[:500]
        except Exception:
            body = ""
        err = f"HTTP {e.code}: {body or e.reason}"
        _set_state(prefix_id, state="failed", last_error=err,
                   last_warmup_ts=time.time(), mode=mode, minimal=is_minimal)
        return {"ok": False, "state": "failed", "error": err,
                "duration_ms": int((time.time() - t0) * 1000), "mode": mode}
    except Exception as e:
        err = f"{type(e).__name__}: {e}"
        _set_state(prefix_id, state="failed", last_error=err,
                   last_warmup_ts=time.time(), mode=mode, minimal=is_minimal)
        return {"ok": False, "state": "failed", "error": err,
                "duration_ms": int((time.time() - t0) * 1000), "mode": mode}


# --- Background Task Runner ---

import uuid as _uuid


class TaskRunner:
    """Manages background agent tasks with status tracking and cancellation."""

    def __init__(self):
        self._tasks: dict[str, dict] = {}  # task_id -> task_info
        self._threads: dict[str, threading.Thread] = {}
        self._cancel_flags: dict[str, threading.Event] = {}
        self._lock = threading.Lock()

    def submit(self, agent_id: str, task: str, model: str | None = None) -> str:
        """Submit a task to run in a background thread. Returns task_id."""
        task_id = _uuid.uuid4().hex[:8]
        cancel_flag = threading.Event()
        # Capture caller's user_id and team ids for MemPalace wing scoping in the child thread
        caller_user_id = get_request_context().current_user_id or ""
        caller_team_ids = list(get_request_context().current_team_ids or [])
        # M1 (G1): and the caller's anonymisation mapping — the delegate must run
        # in the SAME fake world. The delegating model only ever saw fakes, so the
        # `task` string it wrote is already pseudonymised; binding the parent
        # mapping in the child thread is what makes the delegate's own tool loop
        # obey the result seam, the args de-anonymiser and the web-egress gate.
        caller_mapping_id = get_request_context()._gdpr_mapping_id or ""
        caller_session_id = get_request_context().current_session_id or ""

        # Pre-minted turn id for the delegate's LLM call: cancel() trips the
        # loop's per-turn cancel Event via sidecar_proxy.cancel_turn, so a
        # cancel actually STOPS the running call instead of merely flagging
        # the row (the pre-hardening soft-cancel only checked the flag before/
        # after the call).
        turn_id = _uuid.uuid4().hex

        with self._lock:
            self._tasks[task_id] = {
                "id": task_id,
                "agent": agent_id,
                "task": task,
                "model": model,
                "status": "running",
                "result": None,
                "error": None,
                "submitted_at": datetime.datetime.now().isoformat(),
                "finished_at": None,
                "turn_id": turn_id,
            }
            self._cancel_flags[task_id] = cancel_flag

        thread = threading.Thread(
            target=self._run_task,
            args=(task_id, agent_id, task, model, cancel_flag, caller_user_id,
                  caller_team_ids, turn_id, caller_mapping_id, caller_session_id),
            daemon=True)
        self._threads[task_id] = thread
        thread.start()
        return task_id

    def get_status(self, task_id: str) -> dict | None:
        with self._lock:
            return self._tasks.get(task_id, {}).copy() if task_id in self._tasks else None

    def list_tasks(self) -> list[dict]:
        with self._lock:
            return [t.copy() for t in self._tasks.values()]

    def cancel(self, task_id: str) -> bool:
        with self._lock:
            if task_id not in self._tasks:
                return False
            if self._tasks[task_id]["status"] != "running":
                return False
            self._cancel_flags[task_id].set()
            self._tasks[task_id]["status"] = "cancelled"
            self._tasks[task_id]["finished_at"] = datetime.datetime.now().isoformat()
            turn_id = self._tasks[task_id].get("turn_id") or ""
        # Actually stop the in-flight LLM call (not just flag the row): trip the
        # per-turn cancel Event the delegate's background_call registered.
        if turn_id:
            try:
                from handlers import sidecar_proxy as _sp
                _sp.cancel_turn(turn_id)
            except Exception:
                pass
        return True

    def get_result(self, task_id: str) -> dict | None:
        """Get result, blocking until complete if still running. Timeout 0.1s poll."""
        if task_id not in self._threads:
            return self.get_status(task_id)
        # Wait for thread to finish (with timeout so we don't block forever)
        self._threads[task_id].join(timeout=300)
        return self.get_status(task_id)

    def _run_task(self, task_id: str, agent_id: str, task: str,
                  model: str | None, cancel_flag: threading.Event,
                  caller_user_id: str = "",
                  caller_team_ids: list | None = None,
                  turn_id: str = "",
                  caller_mapping_id: str = "",
                  caller_session_id: str = ""):
        caller_team_ids = caller_team_ids or []
        """Execute a task in a background thread."""
        target = AgentConfig(agent_id)

        if not model:
            model = target.preferred_model or _delegate_fallback_model or "claude-opus-4-5-20251101"

        import platform
        cwd = os.getcwd()
        os_name = platform.system()
        soul = target.soul

        from datetime import datetime as _dt
        system_prompt = (
            f"{soul}\n\n"
            f"You are agent '{agent_id}' running a background task.\n"
            f"Current date and time: {_dt.now().strftime('%Y-%m-%d %H:%M %Z').strip()}\n"
            f"Current working directory: {cwd}\n"
            f"Operating system: {os_name}\n\n"
            "Complete the task and provide a concise result summary.\n"
        )
        # Inject team context
        team_info = _get_agent_team_info(agent_id)
        if team_info:
            if team_info["is_head"]:
                peers = [m for m in team_info["members"] if m != agent_id]
                system_prompt += (
                    f"\nTEAM: You are the head of team '{team_info['name']}'. "
                    f"Your team members: {', '.join(peers)}\n"
                    "Delegate sub-tasks to your team members when appropriate.\n"
                    "Use wiki_write(scope='team') for team-level shared knowledge.\n"
                )
            else:
                peers = [m for m in team_info["members"] if m != agent_id and m != team_info["head"]]
                system_prompt += (
                    f"\nTEAM: You are a member of team '{team_info['name']}'.\n"
                    f"Team head: {team_info['head']}\n"
                )
                if peers:
                    system_prompt += f"Team peers: {', '.join(peers)}\n"
                system_prompt += "Use wiki_write(scope='team') for team-level shared knowledge.\n"

        # Per-tool prompt prose for the delegate's resolved tool set.
        _delegate_tool_names = _get_agent_tool_names(agent_id)
        if _delegate_tool_names:
            _rules = _render_tool_descriptions(_delegate_tool_names)
            if _rules:
                system_prompt += f"\n--- TOOL USAGE GUIDE ---\n{_rules}"

        # Build team-aware agent registry for this delegate
        agent_registry = build_agent_registry(for_agent_id=agent_id)
        if agent_registry:
            system_prompt += f"\n\n{agent_registry}\n"

        messages = [{"role": "user", "content": task}]

        result_text = ""
        status = "completed"
        try:
            _task_ctx = ExecutionContext(
                mode="delegate",
                agent_id=agent_id,
                user_id=caller_user_id,
                team_ids=caller_team_ids,
            )
            with request_context():
                init_thread_context(_task_ctx, agent_config=target)
                if cancel_flag.is_set():
                    status = "cancelled"
                else:
                    delegate_inf = get_inference_params(model, target.config.get("model_purpose"))
                    # GDPR policy gate: the calling agent's context (system
                    # prompt + the task payload itself) may carry PII, and the
                    # delegate target can be a different cloud provider than
                    # the parent. Scan both, swap model and/or pseudonymise
                    # per admin policy, deanon the reply before returning it
                    # up to the caller.
                    _del_deanon = _identity_deanon
                    _wire_system = system_prompt
                    _wire_messages = messages
                    # M1 (G1): join the caller's fake world before the gate — same
                    # reasoning as the background-task leaf. Rehydrates from
                    # chats.db when the parent turn already close_mapping()'d it.
                    _del_mid = caller_mapping_id or ""
                    _del_bound = gdpr_bind_mapping(_del_mid) if _del_mid else False
                    try:
                        _msg_blobs = []
                        _msg_idx = []
                        for _i, _m in enumerate(messages):
                            _c = _m.get("content")
                            if isinstance(_c, str):
                                _msg_blobs.append(_c)
                                _msg_idx.append(_i)
                        _scan_inputs = [system_prompt] + _msg_blobs
                        # Never bypassed — the gate also enforces ARL
                        # classification + the quota/force-local swap. With a bound
                        # parent mapping the payload is already fake-space, so it
                        # finds nothing and returns identity.
                        model, _new_blobs, _del_deanon = gdpr_pick_model_for_background(
                            model, _scan_inputs, purpose="delegate_task")
                        if _new_blobs is not _scan_inputs:
                            _wire_system = _new_blobs[0]
                            _wire_messages = list(messages)
                            for _i, _nb in zip(_msg_idx, _new_blobs[1:]):
                                _wire_messages[_i] = {**messages[_i], "content": _nb}
                        if not _del_bound:
                            _del_mid = getattr(_del_deanon, "mapping_id", "") or ""
                    except GDPRBlockedError as e:
                        status = "error"
                        result_text = f"Delegate error: GDPR block — {e}"
                    if status != "error":
                        from handlers import sidecar_proxy as _sidecar_proxy
                        _res = _sidecar_proxy.background_call(
                            messages=_wire_messages, model=model, system_prompt=_wire_system,
                            agent_id=agent_id, cost_purpose="delegate_task",
                            max_tokens=int(delegate_inf.get("max_tokens") or 0) or None,
                            turn_id=turn_id or None,
                            # Protect the delegate's own tool loop (seams + gate).
                            gdpr_mapping_id=_del_mid,
                        )
                        # M1 (G1) — LEAK FIX. `result_text` goes STRAIGHT back to
                        # the delegating (cloud) model as the delegate_task /
                        # task_status tool result, and that path has no
                        # re-anonymising seam. Two cases:
                        #
                        #  - Shared mapping (we bound the caller's): the reply is
                        #    already in the caller's fake world → return it AS IS.
                        #    De-anonymising here — what the code did before — fed
                        #    REAL values into the very model the mapping exists to
                        #    keep them from. The user-facing reverse happens once,
                        #    later, at the parent's StreamingDeanonymizer.
                        #
                        #  - No shared mapping (delegate spawned from a
                        #    non-anonymising session; the gate minted a ONE-SHOT
                        #    map for this call): nothing downstream knows those
                        #    tokens, so they must be reversed here or the caller
                        #    would receive unresolvable placeholders. The caller is
                        #    non-anonymising by definition, so this is not a leak.
                        _reply = _res.get("reply") or ""
                        result_text = _reply if _del_bound else _del_deanon(_reply)
                        # The delegate may have extended the shared mapping.
                        if _del_mid and caller_session_id:
                            gdpr_persist_mapping(
                                _del_mid, caller_session_id,
                                turn_id=f"delegate:{task_id}")
                        if cancel_flag.is_set() or _res.get("cancelled"):
                            status = "cancelled"
                        elif _res.get("timed_out"):
                            result_text = (result_text
                                           + "\n\n(Delegate timeout — Teilergebnis)").strip()
                            status = "error"
                        elif _res.get("error"):
                            result_text = f"Delegate error: {_res['error']}"
                            status = "error"
        except Exception as e:
            result_text = str(e)
            status = "error"

        with self._lock:
            self._tasks[task_id]["status"] = status
            self._tasks[task_id]["result"] = result_text
            self._tasks[task_id]["finished_at"] = datetime.datetime.now().isoformat()
            if status == "error":
                self._tasks[task_id]["error"] = result_text
            # Clean up thread reference
            self._threads.pop(task_id, None)
            self._cancel_flags.pop(task_id, None)


# Global task runner
_task_runner: TaskRunner | None = None


# --- Workflow Engine ---

try:
    import yaml as _yaml
except ImportError:
    _yaml = None  # Graceful fallback — suggest pip3 install pyyaml


# =================================================================
# Workflow Language (.flow) — small scripted DSL.
#
# A workflow is a plain-text file storing keywords + tool calls. The
# language stays deliberately tiny (Excel-formula-tier) so non-programmer
# users can read and edit them; every action is a CALL to a Brain tool
# from TOOL_DISPATCH so the language never lags behind the tool surface.
#
# Grammar (informal):
#
#   workflow      := (line)*
#   line          := comment | header | statement
#   comment       := '#' .*
#   header        := 'WORKFLOW' STRING
#                  | 'DESCRIPTION' STRING
#                  | 'TRIGGER' STRING
#   statement     := assign | call_stmt | if_stmt | for_stmt | return_stmt
#   assign        := 'SET' IDENT '=' expr
#   call_stmt     := 'CALL' IDENT (NAME '=' expr)*
#                  | 'CALL?' IDENT (NAME '=' expr)*
#   if_stmt       := 'IF' expr ':' BLOCK ('ELSE' ':' BLOCK)?
#   for_stmt      := 'FOR' 'EACH' IDENT 'IN' expr ':' BLOCK
#   return_stmt   := 'RETURN' expr
#   BLOCK         := indented child lines
#   expr          := literal | ident | indexing | call_expr | binop | str_interp
#
# Errors halt by default. `CALL?` makes a call non-fatal — on tool error
# the variable is set to null and `last_error` holds the message.
# =================================================================


# ----------------------------- Workflow scripting engine -----------------------------
# Lexer / AST / parser / interpreter extracted to engine/workflow.py (governing
# principle #3). Re-exported here so in-file callers (WorkflowEngine /
# WorkflowExecution) and external `brain.X` references still resolve.
from engine.workflow import (
    WorkflowError,
    _WF_KEYWORDS, _WF_TT, _WF_OP_MULTICHAR,
    _wf_tokenize, _wf_tok_line,
    _WFNode, _WFLiteral, _WFVar, _WFGetAttr, _WFGetItem, _WFBinOp, _WFUnary,
    _WFFnCall, _WFList, _WFDict, _WFInterpStr, _WFAssign, _WFCall, _WFIf,
    _WFFor, _WFReturn, _WFProgram, _WFParser,
    _wf_parse,
    _WFReturnValue, _WorkflowInterpreter,
)


# ----------------------------- Public API -----------------------------


class WorkflowEngine:
    """Workflow definitions stored as plain text under agents/<id>/workflows/*.flow."""

    EXTENSION = ".flow"

    @staticmethod
    def _workflows_dir(agent_id: str) -> str:
        return os.path.join(AGENTS_DIR, agent_id, "workflows")

    @staticmethod
    def list_workflows(agent_id: str) -> list[dict]:
        wdir = WorkflowEngine._workflows_dir(agent_id)
        if not os.path.isdir(wdir):
            return []
        results = []
        for fname in sorted(os.listdir(wdir)):
            if not fname.endswith(WorkflowEngine.EXTENSION):
                continue
            name = fname[:-len(WorkflowEngine.EXTENSION)]
            src = WorkflowEngine.get_workflow_source(agent_id, name)
            display_name = name
            description = ""
            trigger = "manual"
            if src is not None:
                try:
                    prog = _wf_parse(src)
                    if prog.name:
                        display_name = prog.name
                    description = prog.description
                    trigger = prog.trigger
                except WorkflowError:
                    pass
            results.append({
                "file": fname,
                "name": name,
                "display_name": display_name,
                "description": description,
                "trigger": trigger,
            })
        return results

    @staticmethod
    def get_workflow_source(agent_id: str, name: str) -> str | None:
        wdir = WorkflowEngine._workflows_dir(agent_id)
        fpath = os.path.join(wdir, name + WorkflowEngine.EXTENSION)
        if not os.path.exists(fpath):
            return None
        try:
            with open(fpath, "r") as f:
                return f.read()
        except Exception:
            return None

    @staticmethod
    def save_workflow(agent_id: str, name: str, source: str) -> str:
        # Validate by attempting to parse
        try:
            _wf_parse(source)
        except WorkflowError as e:
            raise RuntimeError(f"Workflow parse error on line {e.line}: {e}")
        wdir = WorkflowEngine._workflows_dir(agent_id)
        os.makedirs(wdir, exist_ok=True)
        fpath = os.path.join(wdir, name + WorkflowEngine.EXTENSION)
        with open(fpath, "w") as f:
            f.write(source)
        return fpath

    @staticmethod
    def delete_workflow(agent_id: str, name: str) -> bool:
        wdir = WorkflowEngine._workflows_dir(agent_id)
        fpath = os.path.join(wdir, name + WorkflowEngine.EXTENSION)
        ok = False
        if os.path.exists(fpath):
            os.remove(fpath)
            ok = True
        meta_path = fpath + ".meta.json"
        if os.path.exists(meta_path):
            try:
                os.remove(meta_path)
            except OSError:
                pass
        plan_path = WorkflowEngine._workflow_plan_path(agent_id, name)
        if os.path.exists(plan_path):
            try:
                os.remove(plan_path)
            except OSError:
                pass
        return ok

    # ── plan sidecar (<name>.plan.md) ────────────────────────────────
    # The natural-language plan a plan-driven workflow executes via agent_step
    # ("Der Plan ist das Programm"). Injected into the interpreter env as the
    # `plan_md` variable by workflow_start; editable as a second tab in the
    # workflow editor.
    @staticmethod
    def _workflow_plan_path(agent_id: str, name: str) -> str:
        return os.path.join(WorkflowEngine._workflows_dir(agent_id),
                            name + ".plan.md")

    @staticmethod
    def get_workflow_plan(agent_id: str, name: str) -> str:
        p = WorkflowEngine._workflow_plan_path(agent_id, name)
        if not os.path.exists(p):
            return ""
        try:
            with open(p, "r") as f:
                return f.read()
        except OSError:
            return ""

    @staticmethod
    def save_workflow_plan(agent_id: str, name: str, plan_md: str) -> None:
        p = WorkflowEngine._workflow_plan_path(agent_id, name)
        if not (plan_md or "").strip():
            # Empty plan = remove the sidecar (workflow becomes plan-less).
            if os.path.exists(p):
                try:
                    os.remove(p)
                except OSError:
                    pass
            return
        os.makedirs(os.path.dirname(p), exist_ok=True)
        with open(p, "w") as f:
            f.write(plan_md)

    # ── sharing metadata sidecar (<name>.flow.meta.json) ────────────
    @staticmethod
    def _workflow_meta_path(agent_id: str, name: str) -> str:
        return os.path.join(WorkflowEngine._workflows_dir(agent_id),
                            name + WorkflowEngine.EXTENSION + ".meta.json")

    @staticmethod
    def get_workflow_meta(agent_id: str, name: str) -> dict | None:
        """Return the workflow's sharing-metadata dict. None if the workflow
        doesn't exist; an empty-ish dict (owner='') for a legacy workflow with
        no sidecar yet."""
        wf_path = os.path.join(WorkflowEngine._workflows_dir(agent_id),
                               name + WorkflowEngine.EXTENSION)
        if not os.path.exists(wf_path):
            return None
        mp = WorkflowEngine._workflow_meta_path(agent_id, name)
        meta = {"owner_user_id": "", "visibility": "private", "owner_team_id": "",
                "extra_member_user_ids": [], "excluded_user_ids": [], "created_at": ""}
        if os.path.exists(mp):
            try:
                with open(mp, "r") as f:
                    stored = json.load(f)
                if isinstance(stored, dict):
                    meta.update({k: stored[k] for k in stored if k in meta})
            except (OSError, json.JSONDecodeError):
                pass
        return meta

    @staticmethod
    def update_workflow_meta(agent_id: str, name: str, updates: dict) -> dict:
        meta = WorkflowEngine.get_workflow_meta(agent_id, name)
        if meta is None:
            return {"error": "workflow not found"}
        for k in ("owner_user_id", "visibility", "owner_team_id",
                  "extra_member_user_ids", "excluded_user_ids", "created_at"):
            if k in updates:
                meta[k] = updates[k]
        if not meta.get("created_at"):
            meta["created_at"] = datetime.datetime.now(datetime.timezone.utc).isoformat()
        mp = WorkflowEngine._workflow_meta_path(agent_id, name)
        try:
            os.makedirs(os.path.dirname(mp), exist_ok=True)
            with open(mp, "w") as f:
                json.dump(meta, f, indent=2)
        except OSError as e:
            return {"error": str(e)}
        return {"status": "updated"}

    @staticmethod
    def workflow_block(meta: dict) -> dict:
        return {
            "owner_user_id": (meta or {}).get("owner_user_id", "") or "",
            "visibility": (meta or {}).get("visibility", "private") or "private",
            "owner_team_id": (meta or {}).get("owner_team_id", "") or "",
            "extra_member_user_ids": (meta or {}).get("extra_member_user_ids", []) or [],
            "excluded_user_ids": (meta or {}).get("excluded_user_ids", []) or [],
        }


class WorkflowExecution:
    """Runs a parsed scripted workflow in a background thread.

    Backwards-compatible interface with the old YAML system: the same
    public attributes (`status`, `current_stage_idx`, `current_stage_name`,
    `started_at`, `finished_at`, `error`, `to_dict`) are preserved so the
    HTTP handlers don't need rewriting.
    """

    def __init__(self, source: str, variables: dict, agent_id: str,
                 model: str | None = None, execution_id: str | None = None,
                 workflow_name: str = "",
                 user_id: str = "", user_display: str = "",
                 trigger_kind: str = "manual", trigger_ref: str = ""):
        self.source = source
        self.variables = variables or {}
        self.agent_id = agent_id
        self.model = model
        self.execution_id = execution_id or _uuid.uuid4().hex[:10]
        self.workflow_name = workflow_name
        self.user_id = user_id or ""
        self.user_display = user_display or ""
        self.trigger_kind = trigger_kind or "manual"
        self.trigger_ref = trigger_ref or ""
        self.status = "pending"
        self.current_stage_idx = -1
        self.current_stage_name = ""
        self.steps: list[dict] = []   # ordered execution log (truncated, diagnostic)
        # v9.290.2: chat-style transcript (UNTRUNCATED user/assistant turns) +
        # reliable full output paths — drive the chat-view render + artifact
        # seeding, which the truncated `steps` can't. Populated by the
        # interpreter (_eval_call) as meaningful nodes execute.
        self.transcript: list[dict] = []
        self.output_paths: list[str] = []
        self.started_at: str | None = None
        self.finished_at: str | None = None
        self.error: str | None = None
        self._cancel = threading.Event()
        # Pause gate: when SET the run is RUNNING; when CLEAR the interpreter
        # blocks between top-level nodes until resumed (or cancelled). Starts
        # set (running). A separate `_paused` bool mirrors it for to_dict().
        self._pause = threading.Event()
        self._pause.set()
        self._paused = False
        self._thread: threading.Thread | None = None
        self._return_value = None
        self._program: _WFProgram | None = None
        # turn_ids of in-flight agent_step background calls — cancel() trips
        # them via sidecar_proxy.cancel_turn so a mid-step cancel doesn't wait
        # for the LLM turn to finish on its own.
        self._step_turn_ids: set[str] = set()
        self._step_turn_lock = threading.Lock()
        # Live-progress transcript turn for an in-flight agent_step (see
        # begin_live_progress / live_progress_event / end_live_progress).
        self._live_progress: dict | None = None
        self._live_progress_idx: int = -1
        # Parse upfront to surface parse errors before run()
        try:
            self._program = _wf_parse(source)
        except WorkflowError as e:
            self.status = "failed"
            self.error = f"Parse error on line {e.line}: {e}"
            self.finished_at = datetime.datetime.now().isoformat()
            return
        # Inherit AGENT/MODEL from program headers when not overridden by caller
        if self._program:
            if not self.agent_id and self._program.agent_id:
                self.agent_id = self._program.agent_id
            if not self.model and self._program.model:
                self.model = self._program.model
        # Persist initial history row immediately so even running/zombied executions are visible
        try:
            wf_file = (self.workflow_name or "") + WorkflowEngine.EXTENSION
            now_iso = datetime.datetime.now().isoformat()
            self.started_at = now_iso  # provisional — overwritten on run()
            _workflow_history_insert(
                self.execution_id, self.workflow_name, wf_file, source,
                self.agent_id or "main", self.user_id, self.user_display,
                self.trigger_kind, self.trigger_ref, self.model or "",
                now_iso, json.dumps(self.variables, default=str),
            )
        except Exception as e:
            logging.warning(f"workflow init history: {e}")

    def run(self) -> None:
        if self.status == "failed":
            # Parse-error case: history row was never inserted; persist a final
            # row so the run still appears in history with the parse error.
            try:
                wf_file = (self.workflow_name or "") + WorkflowEngine.EXTENSION
                now_iso = self.finished_at or datetime.datetime.now().isoformat()
                _workflow_history_insert(
                    self.execution_id, self.workflow_name, wf_file, self.source,
                    self.agent_id or "main", self.user_id, self.user_display,
                    self.trigger_kind, self.trigger_ref, self.model or "",
                    now_iso, json.dumps(self.variables, default=str),
                )
                _workflow_history_finalize(
                    self.execution_id, "failed", now_iso, 0, self.error, "",
                    json.dumps(self.steps, default=str),
                )
            except Exception:
                pass
            return
        self.status = "running"
        self.started_at = datetime.datetime.now().isoformat()
        self._thread = threading.Thread(
            target=self._execute, daemon=True,
            name=f"workflow-{self.execution_id}")
        self._thread.start()

    def _execute(self) -> None:
        # Set thread-locals so:
        #  - ask_user_for_file finds the execution id
        #  - cost-logging keys all LLM calls under "wf-<execution_id>"
        #  - ask_llm sees workflow defaults (model, agent)
        with request_context():
            get_request_context().workflow_execution_id = self.execution_id
            get_request_context().current_session_id = f"wf-{self.execution_id}"
            get_request_context().current_user_id = self.user_id or ""
            get_request_context().workflow_default_model = self.model or ""
            get_request_context().workflow_agent_id = self.agent_id or ""
            # Resolve and pin a current_agent so cost logging records the right agent
            try:
                get_request_context().current_agent = AgentConfig(self.agent_id or "main")
            except Exception:
                get_request_context().current_agent = None
            try:
                interp = _WorkflowInterpreter(self._program, self)  # type: ignore
                interp.run()
                if self._cancel.is_set():
                    self.status = "cancelled"
                else:
                    self.status = "completed"
            except WorkflowError as e:
                self.status = "failed"
                self.error = f"Line {e.line}: {e}"
            except Exception as e:
                self.status = "failed"
                self.error = str(e)
            finally:
                self.finished_at = datetime.datetime.now().isoformat()
                # Compute duration
                try:
                    start_dt = datetime.datetime.fromisoformat(self.started_at) if self.started_at else None
                    end_dt = datetime.datetime.fromisoformat(self.finished_at)
                    duration_ms = int((end_dt - start_dt).total_seconds() * 1000) if start_dt else 0
                except Exception:
                    duration_ms = 0
                # Persist terminal state
                try:
                    rv = self._return_value
                    rv_str = json.dumps(rv, default=str) if rv is not None else ""
                    _workflow_history_finalize(
                        self.execution_id, self.status, self.finished_at,
                        duration_ms, self.error, rv_str,
                        json.dumps(self.steps, default=str),
                        json.dumps(self.transcript, default=str),
                        json.dumps(self.output_paths, default=str),
                    )
                except Exception as e:
                    logging.warning(f"workflow finalize: {e}")

    def _record_step(self, line: int, kind: str, detail: str) -> None:
        self.steps.append({
            "line": line,
            "kind": kind,
            "detail": detail,
            "at": datetime.datetime.now().isoformat(),
        })
        self.current_stage_idx = len(self.steps) - 1
        self.current_stage_name = f"line {line}"

    def record_message(self, role: str, content: str, **meta) -> None:
        """Append an UNTRUNCATED chat turn to the run transcript (drives the
        chat-view render). role='user' | 'assistant'. meta may carry model,
        files (list of output paths written by an agent_step), line."""
        msg = {"role": role, "content": content or "",
               "at": datetime.datetime.now().isoformat()}
        for k, v in meta.items():
            if v is not None:
                msg[k] = v
        self.transcript.append(msg)

    def insert_user_before_last_answer(self, content: str, **meta) -> None:
        """Insert a user turn just BEFORE the most recent assistant turn — used
        when the live-progress turn was finalised IN PLACE as the answer (so the
        instruction/request must appear above it, not after)."""
        msg = {"role": "user", "content": content or "",
               "at": datetime.datetime.now().isoformat()}
        for k, v in meta.items():
            if v is not None:
                msg[k] = v
        with self._step_turn_lock:
            for i in range(len(self.transcript) - 1, -1, -1):
                if self.transcript[i].get("role") == "assistant":
                    self.transcript.insert(i, msg)
                    return
            self.transcript.append(msg)

    def record_output_path(self, path: str) -> None:
        """Record a FULL output-file path (untruncated) a write/edit tool
        produced, so artifact seeding is reliable regardless of step-detail
        truncation."""
        if path and path not in self.output_paths:
            self.output_paths.append(path)

    def attach_output_to_last_answer(self, path: str) -> None:
        """Attach an output-file path to the most recent assistant transcript
        turn (so a workflow-level write_file shows as an artifact-card ON the
        answer that produced its content). If there's no assistant turn yet,
        record a minimal one so the file still surfaces in the chat view."""
        if not path:
            return
        for msg in reversed(self.transcript):
            if msg.get("role") == "assistant":
                files = msg.setdefault("files", [])
                if path not in files:
                    files.append(path)
                return
        # No assistant turn yet — create a lightweight carrier turn.
        self.record_message("assistant", "", files=[path])

    def begin_live_progress(self, label: str = "") -> None:
        """Open a LIVE progress transcript turn for an in-flight agent_step.

        agent_step is a blocking background_call that used to surface NOTHING
        until it fully returned (a 20-round forensic run looked frozen). We now
        maintain ONE live assistant turn (`_wf_live: True`) carrying an ordered
        `_wf_events` list — real tool_call/tool_result/thinking/text rows the
        FRONTEND renders exactly like a normal chat turn (args tables, result
        blocks, streamed answer text). The poll (`/executions/{id}` →
        transcript) ships the events; the live turn is dropped by
        `end_live_progress()` and the step's real answer turn is recorded by
        `_capture_transcript` as usual."""
        with self._step_turn_lock:
            # events: ordered [{kind:'tool_call'|'tool_result'|'text'|'thinking', ...}]
            self._live_progress = {"label": label or "Arbeitet …", "events": []}
            self._live_progress_idx = len(self.transcript)
            self.transcript.append({
                "role": "assistant", "_wf_live": True,
                "_wf_label": self._live_progress["label"],
                "_wf_events": self._live_progress["events"],
                "at": datetime.datetime.now().isoformat(),
            })

    def live_progress_event(self, etype: str, data: dict) -> None:
        """Feed one loop event into the live progress turn (thread-safe).

        Builds structured rows the chat renderer understands:
          - tool_call   → a new event with name+args+tool_use_id
          - tool_result → attach result to the matching tool_call event
          - text_delta  → append to the current trailing text segment (a new
                          segment starts after each tool call, so the turn reads
                          text → tool → text like a real chat)
          - thinking_delta → append to the current trailing thinking segment
        """
        lp = getattr(self, "_live_progress", None)
        if lp is None:
            return
        try:
            with self._step_turn_lock:
                evs = lp["events"]
                d = data or {}
                if etype == "tool_call":
                    evs.append({
                        "kind": "tool_call",
                        "name": d.get("name") or d.get("tool") or "tool",
                        "args": d.get("args") or {},
                        "tool_use_id": d.get("tool_use_id") or "",
                    })
                elif etype == "tool_result":
                    tuid = d.get("tool_use_id") or ""
                    name = d.get("name") or d.get("tool") or ""
                    # Attach to the matching tool_call (by id, else last unmatched
                    # call with the same name).
                    for ev in reversed(evs):
                        if ev.get("kind") != "tool_call" or ev.get("_done"):
                            continue
                        if (tuid and ev.get("tool_use_id") == tuid) or (not tuid and ev.get("name") == name):
                            ev["_done"] = True
                            ev["result"] = d.get("result", "")
                            ev["is_error"] = bool(d.get("is_error"))
                            ev["duration_ms"] = d.get("elapsed_ms")
                            break
                elif etype in ("text_delta", "text"):
                    seg = evs[-1] if (evs and evs[-1].get("kind") == "text") else None
                    if seg is None:
                        seg = {"kind": "text", "text": ""}
                        evs.append(seg)
                    seg["text"] += d.get("text", "") or ""
                elif etype == "thinking_delta":
                    seg = evs[-1] if (evs and evs[-1].get("kind") == "thinking") else None
                    if seg is None:
                        seg = {"kind": "thinking", "text": ""}
                        evs.append(seg)
                    seg["text"] += d.get("text", "") or ""
                else:
                    return
                # to_dict serialises self.transcript; the live turn's _wf_events
                # IS this same list object, so the mutation is already visible.
        except Exception:
            pass

    def finalize_live_progress(self, text: str = "", model: str = "", files=None) -> bool:
        """FREEZE the live progress turn into a permanent completed turn: flip
        `_wf_live` off (so the status/controls line drops), set the final answer
        text/model/files, and KEEP the collected `_wf_events` so the tool calls
        + thinking + streamed text the user watched STAY visible after the step
        ends (the v9.291.x bug: they vanished because the live turn was popped
        and only the bare answer was re-recorded).

        Returns True if it finalised a live turn — the caller (agent_step's
        transcript capture) then SKIPS recording a second assistant turn."""
        with self._step_turn_lock:
            idx = getattr(self, "_live_progress_idx", -1)
            ok = 0 <= idx < len(self.transcript) and self.transcript[idx].get("_wf_live")
            if ok:
                turn = self.transcript[idx]
                turn["_wf_live"] = False
                turn["content"] = text or ""
                if model:
                    turn["model"] = model
                if files:
                    turn["files"] = list(files)
                # _wf_events stays on the turn → the frontend keeps rendering the
                # tool calls/thinking/text as a normal completed turn.
            self._live_progress = None
            self._live_progress_idx = -1
            return bool(ok)

    def end_live_progress(self) -> None:
        """Abort path (error/exception before an answer): drop the live turn."""
        with self._step_turn_lock:
            idx = getattr(self, "_live_progress_idx", -1)
            if 0 <= idx < len(self.transcript) and self.transcript[idx].get("_wf_live"):
                self.transcript.pop(idx)
            self._live_progress = None
            self._live_progress_idx = -1

    def register_step_turn(self, turn_id: str) -> None:
        with self._step_turn_lock:
            self._step_turn_ids.add(turn_id)

    def unregister_step_turn(self, turn_id: str) -> None:
        with self._step_turn_lock:
            self._step_turn_ids.discard(turn_id)

    def pause(self) -> None:
        """Request a pause. Takes effect at the next top-level node boundary
        (the interpreter blocks on `_pause_wait()` between statements). An
        in-flight agent_step LLM turn runs to completion first — pause is
        cooperative, not a mid-generation kill."""
        if self.status in ("running", "pending"):
            self._paused = True
            self._pause.clear()

    def resume(self) -> None:
        self._paused = False
        self._pause.set()

    def _pause_wait(self) -> None:
        """Block while paused, waking periodically so a concurrent cancel is
        honoured promptly. Called by the interpreter between top-level nodes."""
        while not self._pause.is_set():
            if self._cancel.is_set():
                return
            self._pause.wait(timeout=0.5)

    def cancel(self) -> None:
        self._cancel.set()
        # A paused run must be un-paused so its interpreter thread wakes, sees
        # the cancel, and exits instead of blocking forever on the pause gate.
        self._paused = False
        self._pause.set()
        # Also unblock any pending file-upload wait
        try:
            deliver_workflow_file_answer(self.execution_id, None)
        except Exception:
            pass
        # Interrupt in-flight agent_step LLM turns.
        with self._step_turn_lock:
            pending_turns = list(self._step_turn_ids)
        if pending_turns:
            try:
                from handlers import sidecar_proxy as _sp
                for tid in pending_turns:
                    _sp.cancel_turn(tid)
            except Exception:
                pass

    # No-op approval methods — kept so HTTP handlers can call them harmlessly.
    def approve(self) -> None: pass
    def reject(self) -> None: self.cancel()

    def to_dict(self) -> dict:
        # For UI, expose the recorded steps as "stages"
        stages = [
            {
                "name": f"L{step['line']}",
                "type": step["kind"],
                "status": "completed",
                "output": step["detail"],
                "elapsed": 0,
            }
            for step in self.steps
        ]
        # Pull final variable map from interpreter env if available
        return {
            "execution_id": self.execution_id,
            "workflow_name": self.workflow_name,
            "agent": self.agent_id,
            "model": self.model,
            "status": self.status,
            "current_stage": self.current_stage_name,
            "current_stage_idx": self.current_stage_idx,
            "total_stages": len(self.steps),
            "paused": bool(self._paused),
            "stages": stages,
            "steps": self.steps,
            "transcript": self.transcript,
            "output_paths": self.output_paths,
            "variables": self.variables,
            "return_value": self._return_value,
            "started_at": self.started_at,
            "finished_at": self.finished_at,
            "error": self.error,
        }


# Global workflow execution registry
_workflow_executions: dict[str, "WorkflowExecution"] = {}
_workflow_lock = threading.Lock()


def workflow_start(agent_id: str, workflow_name: str, variables: dict,
                   model: str | None = None,
                   user_id: str = "", user_display: str = "",
                   trigger_kind: str = "manual",
                   trigger_ref: str = "") -> WorkflowExecution:
    src = WorkflowEngine.get_workflow_source(agent_id, workflow_name)
    if src is None:
        raise ValueError(f"Workflow '{workflow_name}' not found for agent '{agent_id}'")
    # Seed the plan sidecar as the `plan_md` variable so plan-driven workflows
    # (agent_step / plan_steps) can reference it without any file-loading DSL.
    # An explicit caller-provided plan_md variable wins.
    variables = dict(variables or {})
    if "plan_md" not in variables:
        plan_md = WorkflowEngine.get_workflow_plan(agent_id, workflow_name)
        if plan_md:
            variables["plan_md"] = plan_md
    execution = WorkflowExecution(
        src, variables, agent_id, model,
        workflow_name=workflow_name,
        user_id=user_id, user_display=user_display,
        trigger_kind=trigger_kind, trigger_ref=trigger_ref,
    )
    with _workflow_lock:
        _workflow_executions[execution.execution_id] = execution
    execution.run()
    return execution


def workflow_get_execution(execution_id: str) -> WorkflowExecution | None:
    with _workflow_lock:
        return _workflow_executions.get(execution_id)


def workflow_list_executions() -> list[dict]:
    with _workflow_lock:
        return [ex.to_dict() for ex in _workflow_executions.values()]


def workflow_cleanup_old(max_age_hours: int = 24) -> None:
    cutoff = datetime.datetime.now() - datetime.timedelta(hours=max_age_hours)
    with _workflow_lock:
        to_remove = []
        for eid, ex in _workflow_executions.items():
            if ex.status in ("completed", "failed", "cancelled") and ex.finished_at:
                try:
                    finished = datetime.datetime.fromisoformat(ex.finished_at)
                    if finished < cutoff:
                        to_remove.append(eid)
                except (ValueError, TypeError):
                    pass
        for eid in to_remove:
            del _workflow_executions[eid]


# tool_delegate_task / tool_task_status / tool_task_cancel moved to
# engine/tools/delegation_tools.py (refactor E4); re-exported below near
# TOOL_DISPATCH.


# --- Scheduler ---

import sqlite3

# The scheduler subsystem (DB pool, Scheduler class,
# _validate_thinking_level_for_model, tool_schedule_*) was extracted to
# engine/scheduler.py (refactor B2). Re-exported here so every existing
# caller still resolves via `brain.X` / `engine.X`:
#   - the schedule DB pool (`SCHEDULER_DB`, `_sched_db_pool`, `_sched_conn`)
#     is reached by the schedule-sharing helpers and the workflow-history
#     subsystem (both still defined below) AND by _gather_recent_schedule_history;
#   - `Scheduler` is annotated on the `_scheduler` global below and
#     instantiated by server.py as `engine._scheduler = engine.Scheduler()`;
#   - the tool functions are wired into TOOL_DISPATCH unchanged;
#   - the characterization tests target brain.Scheduler / brain._calc_next_run
#     / brain._calc_next_from_last / brain._validate_thinking_level_for_model.
from engine.scheduler import (  # noqa: E402
    SCHEDULER_DB,
    _sched_db_pool,
    _sched_conn,
    _validate_thinking_level_for_model,
    Scheduler,
    tool_schedule_list,
    tool_schedule_history,
)


# --- Schedule sharing helpers (generic visibility model) ---

def _schedule_get_row(name: str) -> dict | None:
    """Return a schedule row as a dict, or None. Used by handlers/share.py."""
    try:
        with _sched_conn() as conn:
            conn.row_factory = sqlite3.Row
            r = conn.execute("SELECT * FROM schedules WHERE name = ?", (name,)).fetchone()
            return dict(r) if r else None
    except Exception:
        return None


def _schedule_share_block(row: dict) -> dict:
    """Map a schedule row to the generic five-field sharing block. The
    schedule's `user_id` is its owner."""
    def _list(v):
        if isinstance(v, list):
            return v
        if not v:
            return []
        try:
            d = json.loads(v); return d if isinstance(d, list) else []
        except Exception:
            return []
    return {
        "owner_user_id": row.get("user_id") or "",
        "visibility": row.get("visibility") or "private",
        "owner_team_id": row.get("owner_team_id") or "",
        "extra_member_user_ids": _list(row.get("extra_member_user_ids")),
        "excluded_user_ids": _list(row.get("excluded_user_ids")),
    }


def _schedule_update_share(name: str, *, visibility=None, owner_team_id=None,
                           extra_member_user_ids=None, excluded_user_ids=None,
                           owner_user_id=None):
    sets, params = [], []
    if visibility is not None:
        sets.append("visibility = ?"); params.append(visibility)
    if owner_team_id is not None:
        sets.append("owner_team_id = ?"); params.append(owner_team_id)
    if extra_member_user_ids is not None:
        sets.append("extra_member_user_ids = ?"); params.append(json.dumps(list(extra_member_user_ids)))
    if excluded_user_ids is not None:
        sets.append("excluded_user_ids = ?"); params.append(json.dumps(list(excluded_user_ids)))
    if owner_user_id is not None:
        sets.append("user_id = ?"); params.append(owner_user_id)
    if not sets:
        return
    params.append(name)
    with _sched_conn() as conn:
        conn.execute(f"UPDATE schedules SET {', '.join(sets)} WHERE name = ?", params)
        conn.commit()


# --- Workflow run history (piggybacks on scheduler.db) ---

_WF_HIST_INIT_DONE = False


def _workflow_history_init() -> None:
    """Idempotent: create workflow_history table on first use."""
    global _WF_HIST_INIT_DONE
    if _WF_HIST_INIT_DONE:
        return
    try:
        conn = _sched_conn()
        conn.execute("""
            CREATE TABLE IF NOT EXISTS workflow_history (
                execution_id     TEXT PRIMARY KEY,
                workflow_name    TEXT NOT NULL,
                workflow_file    TEXT,
                workflow_source  TEXT,
                agent_id         TEXT NOT NULL DEFAULT 'main',
                user_id          TEXT NOT NULL DEFAULT '',
                user_display     TEXT NOT NULL DEFAULT '',
                trigger_kind     TEXT NOT NULL DEFAULT 'manual',
                trigger_ref      TEXT NOT NULL DEFAULT '',
                model            TEXT NOT NULL DEFAULT '',
                status           TEXT NOT NULL DEFAULT 'running',
                started_at       TEXT NOT NULL,
                finished_at      TEXT,
                duration_ms      INTEGER NOT NULL DEFAULT 0,
                error            TEXT,
                return_value     TEXT,
                variables_json   TEXT,
                steps_json       TEXT,
                tool_calls       INTEGER NOT NULL DEFAULT 0,
                llm_calls        INTEGER NOT NULL DEFAULT 0,
                tokens_in        INTEGER NOT NULL DEFAULT 0,
                tokens_out       INTEGER NOT NULL DEFAULT 0,
                cost_usd         REAL    NOT NULL DEFAULT 0.0
            )
        """)
        conn.execute("CREATE INDEX IF NOT EXISTS idx_wfh_workflow ON workflow_history(workflow_name, started_at DESC)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_wfh_user     ON workflow_history(user_id, started_at DESC)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_wfh_status   ON workflow_history(status, started_at DESC)")
        # v9.290.2: chat-style transcript + reliable output paths, captured
        # UNTRUNCATED (the diagnostic steps_json truncates agent_step text +
        # write_file paths to 120 chars, so it can't drive a real chat view or
        # artifact seeding). Additive columns — SELECT * picks them up. Guard
        # each ADD COLUMN (SQLite has no ADD COLUMN IF NOT EXISTS pre-3.35).
        for _col, _decl in (("transcript_json", "TEXT"), ("output_paths_json", "TEXT")):
            try:
                conn.execute(f"ALTER TABLE workflow_history ADD COLUMN {_col} {_decl}")
            except Exception:
                pass  # already present
        # Zombie sweep: any row marked running/pending/waiting_approval at init
        # time has lost its in-memory WorkflowExecution (we just started up).
        # Mark them cancelled so the running set reflects reality. Idempotent.
        try:
            now_iso = datetime.datetime.now().isoformat()
            cur = conn.execute("""
                UPDATE workflow_history
                SET status = 'cancelled',
                    finished_at = COALESCE(finished_at, ?),
                    error = COALESCE(NULLIF(error, ''),
                                     'Cancelled at server startup (in-memory execution lost)')
                WHERE status IN ('running', 'pending', 'waiting_approval')
            """, (now_iso,))
            swept = cur.rowcount or 0
            if swept:
                logging.info(f"workflow_history: swept {swept} zombie running rows at startup")
        except Exception as e:
            logging.warning(f"workflow_history zombie sweep: {e}")
        conn.commit()
        _WF_HIST_INIT_DONE = True
    except Exception as e:
        logging.warning(f"workflow_history init: {e}")


def _workflow_history_insert(execution_id: str, workflow_name: str, workflow_file: str,
                             workflow_source: str, agent_id: str, user_id: str,
                             user_display: str, trigger_kind: str, trigger_ref: str,
                             model: str, started_at: str, variables_json: str) -> None:
    _workflow_history_init()
    try:
        conn = _sched_conn()
        conn.execute("""
            INSERT OR REPLACE INTO workflow_history
            (execution_id, workflow_name, workflow_file, workflow_source, agent_id,
             user_id, user_display, trigger_kind, trigger_ref, model, status,
             started_at, variables_json)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'running', ?, ?)
        """, (execution_id, workflow_name, workflow_file, workflow_source, agent_id,
              user_id or "", user_display or "", trigger_kind or "manual",
              trigger_ref or "", model or "", started_at, variables_json or "{}"))
        conn.commit()
    except Exception as e:
        logging.warning(f"workflow_history insert: {e}")


def _workflow_history_finalize(execution_id: str, status: str, finished_at: str,
                               duration_ms: int, error: str | None,
                               return_value: str, steps_json: str,
                               transcript_json: str = "[]",
                               output_paths_json: str = "[]") -> None:
    """Update terminal-state row + roll up costs from cost_log keyed by 'wf-<execution_id>'."""
    _workflow_history_init()
    # Roll up costs from cost_log
    sid = f"wf-{execution_id}"
    tool_calls = 0
    llm_calls = 0
    tokens_in = 0
    tokens_out = 0
    cost_usd = 0.0
    try:
        with _cost_conn() as cconn:
            row = cconn.execute("""
                SELECT COUNT(*) AS llm_calls,
                       COALESCE(SUM(tokens_in), 0) AS tokens_in,
                       COALESCE(SUM(tokens_out), 0) AS tokens_out,
                       COALESCE(SUM(cost_usd), 0.0) AS cost_usd
                FROM cost_log WHERE session_id = ?
            """, (sid,)).fetchone()
            if row:
                llm_calls = int(row[0] or 0)
                tokens_in = int(row[1] or 0)
                tokens_out = int(row[2] or 0)
                cost_usd = float(row[3] or 0.0)
    except Exception as e:
        logging.warning(f"workflow_history cost rollup: {e}")
    # Count tool_calls from steps_json
    try:
        steps = json.loads(steps_json) if steps_json else []
        tool_calls = sum(1 for s in steps if s.get("kind") == "call")
    except Exception:
        pass
    try:
        conn = _sched_conn()
        conn.execute("""
            UPDATE workflow_history
            SET status = ?, finished_at = ?, duration_ms = ?, error = ?,
                return_value = ?, steps_json = ?,
                transcript_json = ?, output_paths_json = ?,
                tool_calls = ?, llm_calls = ?,
                tokens_in = ?, tokens_out = ?, cost_usd = ?
            WHERE execution_id = ?
        """, (status, finished_at, duration_ms, error or "", return_value or "",
              steps_json or "[]", transcript_json or "[]", output_paths_json or "[]",
              tool_calls, llm_calls, tokens_in, tokens_out,
              cost_usd, execution_id))
        conn.commit()
    except Exception as e:
        logging.warning(f"workflow_history finalize: {e}")


def _workflow_history_list(workflow_name: str | None = None, user_id: str | None = None,
                           status: str | None = None, limit: int = 50, offset: int = 0) -> list[dict]:
    _workflow_history_init()
    try:
        conn = _sched_conn()
        conn.row_factory = sqlite3.Row
        where_parts = []
        params: list = []
        if workflow_name:
            where_parts.append("workflow_name = ?")
            params.append(workflow_name)
        if user_id:
            where_parts.append("user_id = ?")
            params.append(user_id)
        if status:
            where_parts.append("status = ?")
            params.append(status)
        where = ("WHERE " + " AND ".join(where_parts)) if where_parts else ""
        params.extend([int(limit), int(offset)])
        rows = conn.execute(f"""
            SELECT execution_id, workflow_name, workflow_file, agent_id, user_id, user_display,
                   trigger_kind, trigger_ref, model, status, started_at, finished_at,
                   duration_ms, error, return_value, tool_calls, llm_calls,
                   tokens_in, tokens_out, cost_usd
            FROM workflow_history {where}
            ORDER BY started_at DESC
            LIMIT ? OFFSET ?
        """, params).fetchall()
        return [dict(r) for r in rows]
    except Exception as e:
        logging.warning(f"workflow_history list: {e}")
        return []


def _workflow_history_get(execution_id: str) -> dict | None:
    _workflow_history_init()
    try:
        conn = _sched_conn()
        conn.row_factory = sqlite3.Row
        row = conn.execute("""
            SELECT * FROM workflow_history WHERE execution_id = ?
        """, (execution_id,)).fetchone()
        return dict(row) if row else None
    except Exception as e:
        logging.warning(f"workflow_history get: {e}")
        return None


_WF_LIVE_STATUSES = ("running", "pending", "waiting_approval")


def _workflow_history_delete_run(execution_id: str) -> dict:
    """Delete a single workflow_history row. Refuses in-flight runs — caller
    must cancel first (the cancel endpoint finalises the row). Returns a
    summary dict; idempotent (returns deleted=0 if the row is already gone).
    """
    _workflow_history_init()
    row = _workflow_history_get(execution_id)
    if not row:
        return {"status": "ok", "deleted": 0}
    if row.get("status") in _WF_LIVE_STATUSES:
        return {"error": f"Cannot delete a {row.get('status')} run; cancel it first"}
    try:
        conn = _sched_conn()
        cur = conn.execute("DELETE FROM workflow_history WHERE execution_id = ?", (execution_id,))
        conn.commit()
        return {"status": "ok", "deleted": int(cur.rowcount or 0), "execution_id": execution_id}
    except Exception as e:
        logging.warning(f"workflow_history delete_run: {e}")
        return {"error": str(e)}


def _workflow_history_delete_for_workflow(workflow_name: str,
                                          user_id: str | None = None) -> dict:
    """Purge every terminal run for a given workflow. In-flight runs are left
    intact. When `user_id` is provided, only that user's runs are deleted —
    the HTTP layer uses this for non-admin RBAC."""
    _workflow_history_init()
    try:
        conn = _sched_conn()
        params: list = [workflow_name]
        scope_clause = ""
        if user_id:
            scope_clause = " AND user_id = ?"
            params.append(user_id)
        # Build a NOT IN clause over the live statuses to avoid deleting
        # in-flight rows.
        live_placeholders = ",".join("?" * len(_WF_LIVE_STATUSES))
        params.extend(_WF_LIVE_STATUSES)
        cur = conn.execute(
            f"DELETE FROM workflow_history "
            f"WHERE workflow_name = ?{scope_clause} "
            f"AND status NOT IN ({live_placeholders})",
            params,
        )
        conn.commit()
        return {"status": "ok", "runs_removed": int(cur.rowcount or 0)}
    except Exception as e:
        logging.warning(f"workflow_history delete_for_workflow: {e}")
        return {"error": str(e)}


def _workflow_history_delete_all(user_id: str | None = None) -> dict:
    """Purge every terminal workflow run. Live runs are left intact. When
    `user_id` is provided, only that user's runs are deleted (non-admin path)."""
    _workflow_history_init()
    try:
        conn = _sched_conn()
        params: list = []
        scope_clause = ""
        if user_id:
            scope_clause = "user_id = ? AND "
            params.append(user_id)
        live_placeholders = ",".join("?" * len(_WF_LIVE_STATUSES))
        params.extend(_WF_LIVE_STATUSES)
        cur = conn.execute(
            f"DELETE FROM workflow_history "
            f"WHERE {scope_clause}status NOT IN ({live_placeholders})",
            params,
        )
        conn.commit()
        return {"status": "ok", "runs_removed": int(cur.rowcount or 0)}
    except Exception as e:
        logging.warning(f"workflow_history delete_all: {e}")
        return {"error": str(e)}



