def _tool_search(args: dict) -> str:
    """Search for available tools by name or description.

    Returns matching tool schemas from both built-in and MCP tools —
    restricted to tools that are actually DISPATCHABLE this turn (the same
    in_prompt ∪ deferred whitelist the loop enforces). A disabled tool must
    never be advertised: chat 2cb5a9dd — tool_search served the globally-
    inactive exa_search as top match, glm-5.2 (a strict function-caller)
    told the user Exa was available and spent a whole turn hunting a tool
    that could never dispatch. Discovered names are tracked on the request
    context for the resolver's deferred-tool un-hiding.
    """
    query = args.get("query", "").lower()
    max_results = args.get("max_results", 5)

    if not query:
        return _err("query is required")

    # Search built-in tools
    matches = []
    for td in TOOL_DEFINITIONS:
        name = td.get("name", "")
        desc = td.get("description", "")
        if isinstance(desc, tuple):
            desc = " ".join(desc)
        score = 0
        if query in name.lower():
            score += 10
        if query in desc.lower():
            score += 5
        # Fuzzy: match individual words
        for word in query.split():
            if word in name.lower():
                score += 3
            if word in desc.lower():
                score += 1
        if score > 0:
            matches.append((score, {"name": name, "description": desc[:200],
                                     "input_schema": td.get("input_schema", {})}))

    # Search MCP tools
    mcp_mgr = get_request_context().mcp_manager or _mcp_manager
    if mcp_mgr:
        try:
            for mcp_td in mcp_mgr.get_tool_definitions():
                name = mcp_td.get("name", "")
                desc = mcp_td.get("description", "")
                score = 0
                if query in name.lower():
                    score += 10
                if query in desc.lower():
                    score += 5
                for word in query.split():
                    if word in name.lower():
                        score += 3
                    if word in desc.lower():
                        score += 1
                if score > 0:
                    matches.append((score, {"name": name, "description": desc[:200],
                                             "input_schema": mcp_td.get("input_schema", {})}))
        except Exception:
            pass

    # Dispatchability filter — BEFORE ranking/truncation so hidden tools don't
    # eat result slots. Primary: the turn's dispatch whitelist mirrored onto
    # the request context by sidecar_proxy (exact ground truth: in_prompt ∪
    # deferred, minus excluded). Fallback (context without a whitelist, e.g.
    # a legacy/edge caller): hide built-ins whose GLOBAL interactive state is
    # inactive; non-built-in (MCP) names pass — the whitelist path covers them
    # on every real turn.
    _allowed = get_request_context().allowed_tools
    if _allowed:
        _allowed = set(_allowed)
        matches = [m for m in matches if m[1]["name"] in _allowed]
    else:
        matches = [m for m in matches
                   if m[1]["name"] not in TOOL_DISPATCH
                   or resolve_tool_state_for(m[1]["name"], None, "interactive")
                   in ("active", "deferred")]

    # Sort by score descending, take top results
    matches.sort(key=lambda x: x[0], reverse=True)
    results = [m[1] for m in matches[:max_results]]

    # Track discovered tools for deferred loading. `_discovered_tools` is a
    # set initialized by the chat worker, but non-interactive callers (the
    # scheduler fire-path, background calls) never set it — it's None there,
    # so `.add()` crashed `tool_search` with "'NoneType' has no attribute
    # 'add'" whenever a scheduled run called tool_search and got >0 hits
    # (sched-884). Initialize defensively so the tool works in every context.
    discovered = get_request_context()._discovered_tools
    if discovered is None:
        discovered = set()
    for r in results:
        discovered.add(r["name"])
    get_request_context()._discovered_tools = discovered

    if not results:
        return _ok({"matches": [], "message": f"No tools found matching '{query}'"})
    return _ok({"matches": results, "count": len(results),
                "note": "These tools are available NOW — call them directly "
                        "in your next step, like any of your other tools."})


# Per-thread tool call dedup tracking
# Session-scoped tool-call dedup state. Replaces the prior threading.local() impl,
# which silently leaked dupes whenever tool execution crossed a thread boundary
# (worker-subagent wrappers, ThreadPoolExecutor in _execute_tools_batch, etc.).
# Keyed by session_id (falls back to a sentinel when no session is available,
# e.g. CLI one-shot invocations).
# Tool-call dedup cluster (_tool_dedup_lock, _tool_dedup, _TOOL_DEDUP_TTL,
# _dedup_sid, _dedup_state, _dedup_gc_locked, _check_tool_dedup,
# reset_tool_dedup) moved to engine/tool_exec.py (refactor C2); re-exported at
# the bottom of this module. `_check_tool_dedup` raises `brain.TaskCancelled`
# (resolved lazily via the tool_exec `_brain` proxy) so the class identity is
# preserved for callers' `except TaskCancelled`.


# --- Per-session read-path tracker -------------------------------------
#
# Thin record of which files the model has called read_document / read_file
# on in this session. Used by the citation validator to grep verbatim quotes
# against the right files on disk. No content cached, no stubs, no eviction
# beyond session-delete cleanup — within a single turn the `tool_dedup` guard
# kills accidental double-reads; across turns the model is expected to re-read
# (we deliberately don't carry tool_results across turns, so the model has no
# in-context view of a prior turn's read anyway).
# The read-path tracker (_session_read_paths_lock, _session_read_paths,
# _session_read_paths_sid, _SESSION_READ_PATHS_MAX, _record_session_read_path,
# _read_doc_cache_session_paths) moved to engine/tool_exec.py (refactor C2);
# re-exported at the bottom of this module.

# --- Cross-encoder reranker (lazy, process-wide) -------------------------
# `_get_reranker_model` + `_reranker_lock` / `_reranker_cache` moved to
# engine/mempalace_glue.py (refactor C3) — used only by tool_mempalace_query,
# so they moved with it. Re-exported at the bottom of this module.


# _session_read_paths_sid / _SESSION_READ_PATHS_MAX / _record_session_read_path
# / _read_doc_cache_session_paths moved to engine/tool_exec.py (refactor C2)
# alongside the read-path globals above; re-exported at the bottom of this
# module.


# --- Citation Validator (Phase 1: validate + annotate, no re-round) ---
# Scans an assistant response for `[Quelle: <basename> — "<verbatim quote>"]`
# brackets and verifies each quote actually appears in a file the session has
# read. Counts factual sentences/bullets that lack any bracket. Emits an
# annotation block appended to the response when discipline issues are found,
# so the user can see how reliable the citations are.

_CITATION_BRACKET_RE = re.compile(
    # Match [Quelle: <basename> — "<quote>"] tolerantly:
    #   • allow em-dash, en-dash, or hyphen as separator
    #   • allow straight or smart quotes around the quote
    #   • basename is everything up to the separator (lazy)
    #   • quote spans across the closing bracket boundaries with non-greedy
    r'\[\s*Quelle:\s*([^—\-–"\]]+?)\s*[—\-–]\s*[\"“»]([^\"”«\]]+?)[\"”«]\s*\]',
)
_CITATION_BARE_RE = re.compile(r'\[\s*Quelle:\s*([^\]]+?)\]')

# Sentence-with-claim heuristic: lines that look like they make a factual
# statement but contain no [Quelle: …] bracket. Used to count uncited
# claims. Bullet markers and numbered list markers count as separate items.
_BULLET_RE = re.compile(r'^\s*(?:[-*•·]|\d+\.|[a-z]\))\s+', re.MULTILINE)
# Markdown table separator row (| --- | :--: | …) — not a data/claim row.
_TABLE_SEP_RE = re.compile(r'^\|?\s*:?-{2,}:?\s*(\|\s*:?-{2,}:?\s*)*\|?\s*$')


def _normalize_quote(s: str) -> str:
    """Whitespace + punctuation lenient match for verifying quotes are in source."""
    s = s.replace("„", "\"").replace("“", "\"").replace("”", "\"").replace("«", "\"").replace("»", "\"")
    s = s.replace("‚", "'").replace("‘", "'").replace("’", "'")
    s = re.sub(r"\s+", " ", s).strip()
    s = s.lower()
    return s


def _strip_md_companion_suffix(basename: str) -> str:
    """`policy.pdf.md` → `policy.pdf`; `something.md` (no dotted-ext before .md) is left alone."""
    if basename.endswith(".md"):
        stem = basename[:-3]
        # Only strip if there's a "real" extension before .md (e.g. .pdf, .docx)
        if "." in stem:
            return stem
    return basename


def _find_source_path_by_basename(basename: str, session_paths: list[str]) -> str | None:
    """Best-match a citation basename against paths the session has read.
    Tries: exact basename match, .md-suffixed match, prefix substring."""
    target = _strip_md_companion_suffix(basename.strip()).lower()
    candidates = []
    for p in session_paths:
        bn = os.path.basename(p)
        bn_stripped = _strip_md_companion_suffix(bn).lower()
        if bn_stripped == target:
            return p
        if target in bn_stripped or bn_stripped in target:
            candidates.append(p)
    return candidates[0] if candidates else None


def _read_file_cached_for_validation(path: str, _vcache: dict) -> str | None:
    """Lazy read with per-call cache (one validation pass)."""
    if path in _vcache:
        return _vcache[path]
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            content = f.read()
    except OSError:
        _vcache[path] = None
        return None
    _vcache[path] = content
    return content


def validate_citations_in_response(text: str, session_id: str | None = None,
                                   max_quote_len: int = 400) -> dict:
    """Scan an assistant response for citation brackets and verify each quote
    against the corresponding source file the session read.

    Returns a dict:
      {
        "verified": int,        # brackets where quote was found in source
        "unverified": list,     # [(basename, quote_excerpt, reason), ...]
        "uncited_claims": int,  # bulleted/sentence claims with no bracket
        "claim_total": int,     # total bullets + claim-like sentences detected
        "total_brackets": int,
        "annotation": str | None,  # markdown block to append to the response
      }

    No re-round, no rewriting of `text`. Caller decides whether to append
    `annotation` to the message.
    """
    out = {"verified": 0, "unverified": [], "uncited_claims": 0,
           "claim_total": 0, "total_brackets": 0, "annotation": None}
    if not text or not text.strip():
        return out

    # Verifiable sources = files read via read_document this turn PLUS the
    # on-disk companions of drawers surfaced by mempalace_query this turn. The
    # latter is what makes a memory-grounded answer (mempalace_query, no
    # read_document — the common project case) verifiable at all; without it the
    # validator marked every quote "source not in session reads".
    session_paths = set(_read_doc_cache_session_paths(session_id) or set())
    session_paths |= _session_match_region_paths(session_id)
    _vcache: dict = {}

    # 1. Find every [Quelle: X — "Y"] bracket and verify Y appears in X.
    matches = list(_CITATION_BRACKET_RE.finditer(text))
    bare_matches = list(_CITATION_BARE_RE.finditer(text))
    out["total_brackets"] = len(bare_matches)
    parsed_basenames = set()
    for m in matches:
        bn_raw, quote = m.group(1), m.group(2)
        parsed_basenames.add(bn_raw.strip())
        path = _find_source_path_by_basename(bn_raw, session_paths) if session_paths else None
        nq = _normalize_quote(quote)
        # Primary: verify against the NAMED source. If the name didn't resolve
        # (the model's human-readable source name often won't match a slugified
        # web-url/companion filename, e.g. "Jahresfinanzbericht 2025" vs
        # www-…-jahresfinanzbericht-20_….md) OR the quote isn't there, FALL BACK
        # to searching the quote across ALL session sources — the verbatim quote
        # is the strong signal; the source label is fuzzy. A quote found in any
        # session source is genuinely grounded, just mis-labelled.
        if path:
            content = _read_file_cached_for_validation(path, _vcache)
            if content is not None and nq and nq in _normalize_quote(content):
                out["verified"] += 1
                continue
        # Fallback: quote search across every session source.
        if nq and any(
            (lambda c: c is not None and nq in _normalize_quote(c))(
                _read_file_cached_for_validation(p, _vcache))
            for p in session_paths):
            out["verified"] += 1
            continue
        if not path and not session_paths:
            out["unverified"].append((bn_raw.strip(), quote[:120],
                                      "source not in session reads"))
            continue
        # Had sources to check but the quote wasn't in any of them.
        reason = "quote not found in any session source"
        if path and _read_file_cached_for_validation(path, _vcache) is None:
            reason = f"could not read {path}"
        out["unverified"].append((bn_raw.strip(), quote[:120], reason))

    # 2. Count brackets that didn't match the verbatim-quote shape (bare
    # `[Quelle: …]` without a quote part) — these are partial citations.
    bare_only = max(0, len(bare_matches) - len(matches))

    # 3. Count claim-like items (bullets + numbered list items + standalone
    # sentences) that have no bracket on the same logical line/bullet. This
    # is a heuristic — bullets are easy to count; standalone-sentence claim
    # detection is intentionally conservative to avoid false positives on
    # connector text.
    bullets = list(_BULLET_RE.finditer(text))
    out["claim_total"] = len(bullets)
    if bullets:
        # Build line-level bullet ranges
        for i, mb in enumerate(bullets):
            start = mb.end()
            end = bullets[i + 1].start() if i + 1 < len(bullets) else len(text)
            chunk = text[start:end]
            if "[Quelle:" not in chunk:
                # Probably a connector ("Zusammenfassend:", a heading…) if
                # it has < 8 words AND no period; skip those.
                words = len(re.findall(r"\w+", chunk))
                has_period = "." in chunk or "!" in chunk or ":" in chunk
                if words >= 8 or has_period:
                    out["uncited_claims"] += 1

    # 3b. Markdown TABLE data rows — each data row that carries figures is a
    # claim and needs its own citation (in a Quelle column or shared "s.o.").
    # The HEADER row (the row immediately before a |---| separator) is skipped —
    # column labels like "2025"/"2024" are not facts. Rows with no digits (pure
    # labels) are skipped too. A row counts as cited if it has a [Quelle: …] OR
    # an "s.o."/"siehe oben" cell (explicit shared-source marker).
    _tbl_lines = text.splitlines()
    _header_idx = set()
    for i, tline in enumerate(_tbl_lines):
        if _TABLE_SEP_RE.match(tline.strip()) and i > 0:
            _header_idx.add(i - 1)   # the row above a separator is the header
    for i, tline in enumerate(_tbl_lines):
        s = tline.strip()
        if not (s.startswith("|") and s.count("|") >= 2):
            continue
        if _TABLE_SEP_RE.match(s) or i in _header_idx:
            continue
        if not re.search(r"\d", s):          # no figures → label/divider row
            continue
        out["claim_total"] += 1
        low = s.lower()
        if "[quelle:" not in low and "s.o." not in low and "siehe oben" not in low:
            out["uncited_claims"] += 1

    # 3c. Standalone PROSE claims (no bullet, no table) that pack facts — e.g. a
    # "FAZIT: …" paragraph with several figures in one line. Heuristic: a
    # non-bullet, non-table line with ≥2 digit-bearing facts and no [Quelle:]
    # is an uncited multi-fact claim. Conservative — needs real numbers, so
    # connector/intro prose without figures never trips it.
    in_table = False
    for pline in text.splitlines():
        s = pline.strip()
        if s.startswith("|"):
            in_table = True
            continue
        if not s:
            in_table = False
            continue
        if in_table or _BULLET_RE.match(pline) or s.startswith(("#", ">", "---")):
            continue
        if "[Quelle:" in s:
            continue
        # count distinct numeric facts (numbers, %, ±, currency-ish)
        nums = re.findall(r"[+\-−]?\d[\d.,]*\s*%?", s)
        if len(nums) >= 2 and len(re.findall(r"\w+", s)) >= 8:
            out["claim_total"] += 1
            out["uncited_claims"] += 1

    # 4. Build human-readable annotation if there's anything to flag.
    if out["unverified"] or out["uncited_claims"] > 0 or bare_only > 0:
        lines = ["", "---", "**🛈 Citation-Validation:**"]
        if out["verified"] or out["unverified"]:
            lines.append(
                f"- {out['verified']} von {out['verified'] + len(out['unverified'])} "
                f"Zitat-Quotes konnten gegen die gelesenen Quelldateien verifiziert werden."
            )
        if out["unverified"]:
            lines.append("- ⚠ **Nicht verifizierte Zitate:**")
            for bn, q, reason in out["unverified"][:5]:
                excerpt = (q[:80] + "…") if len(q) > 80 else q
                lines.append(f"  - `{bn}` — \"{excerpt}\" *({reason})*")
            if len(out["unverified"]) > 5:
                lines.append(f"  - … und {len(out['unverified']) - 5} weitere.")
        if bare_only > 0:
            lines.append(
                f"- ⚠ {bare_only} Zitate ohne wörtliches Zitat (Form `[Quelle: X]` "
                f"statt `[Quelle: X — \"...\"]`) — pro CITATION DISCIPLINE bitte ergänzen."
            )
        if out["uncited_claims"] > 0:
            lines.append(
                f"- ⚠ {out['uncited_claims']} von {out['claim_total']} faktischen Aussagen "
                f"(Bullet-Points, Tabellenzeilen, Fakt-Sätze) ohne `[Quelle: ...]`-Citation "
                f"— pro CITATION DISCIPLINE trägt jeder faktische Claim sein eigenes Zitat "
                f"(Tabellen: Quelle-Spalte je Zeile, „s.o.“ bei geteilter Quelle)."
            )
        out["annotation"] = "\n".join(lines)
    return out


def strip_fabricated_citations(text: str) -> tuple[str, int]:
    """Remove ALL [Quelle: …] brackets from `text` — used by the worker when a
    turn retrieved NOTHING (no retrieval tool called, no curated web sources,
    no session file matched a single quote): in that situation every bracket
    is by definition fabricated decoration (the v8.40.0 lesson: models satisfy
    the citation FORMAT by inventing sources). Deterministic string surgery —
    no LLM, no re-round; the claims themselves stay untouched.

    Returns (cleaned_text, n_removed). Cleans up the residue a removed bracket
    leaves behind: doubled spaces, space before punctuation, empty table
    'Quelle' cells stay as empty cells (harmless), lines that consisted ONLY
    of a bracket collapse to empty and are pruned if they were list items.
    """
    if not text or "[Quelle:" not in text:
        return text, 0
    n = len(_CITATION_BARE_RE.findall(text))
    if not n:
        return text, 0
    cleaned = _CITATION_BARE_RE.sub("", text)
    # Residue cleanup, line-wise: collapse doubled spaces, trim trailing
    # whitespace, drop bullets that are now empty ("- " with nothing left).
    out_lines = []
    for line in cleaned.splitlines():
        line = re.sub(r"[ \t]{2,}", " ", line).rstrip()
        line = re.sub(r"\s+([.,;:!?])", r"\1", line)
        if re.fullmatch(r"\s*(?:[-*+•]|\d+[.)])\s*", line):
            continue  # bullet that held only a bracket
        out_lines.append(line)
    return "\n".join(out_lines), n


# Public message-cleanup helper used by both send_message's main path and
# the citation re-round helper. Mirrors the inline filter used at line ~22061.
_CLEAN_MSG_ALLOWED_KEYS = {"role", "content", "tool_calls", "tool_call_id", "name"}
_CLEAN_MSG_INTERNAL_ROLES = {"thinking"}


def clean_messages_for_api(messages: list) -> list:
    """Return a wire-safe copy of `messages`: internal roles dropped, only
    OpenAI-protocol fields kept. Used for both main send_message and
    out-of-band helpers (citation re-round, etc.) so they share one filter."""
    out = []
    for msg in messages:
        if msg.get("role") in _CLEAN_MSG_INTERNAL_ROLES:
            continue
        out.append({k: v for k, v in msg.items() if k in _CLEAN_MSG_ALLOWED_KEYS})
    return out


def citation_reround_needed(validation: dict,
                            uncited_ratio_threshold: float = 0.30,
                            unverified_threshold: int = 2) -> bool:
    """Decide whether the validation result warrants a re-round.

    Fires only when more than `uncited_ratio_threshold` of detected
    bullet/claim items carry no [Quelle: ...] bracket (default 30%).

    The unverified-quote signal is deliberately NOT a trigger: PDF→markdown
    extraction routinely breaks byte-exact substring match (whitespace,
    soft hyphens, smart quotes, OCR drift), producing false positives even
    when the model cited correctly. Re-rounding on those wastes ~20s on a
    local model and yields a cosmetically-different but equivalent reply.
    `unverified_threshold` is kept in the signature for back-compat.
    """
    if not validation:
        return False
    claim_total = int(validation.get("claim_total") or 0)
    uncited = int(validation.get("uncited_claims") or 0)
    if claim_total > 0 and (uncited / claim_total) > uncited_ratio_threshold:
        return True
    return False


def build_citation_reround_feedback(validation: dict, original_reply: str) -> str:
    """Build the user-message that gets injected for a citation re-round.

    Tells the model exactly what failed and how to fix it. The injected
    message references the model's previous answer (already in the message
    history at this point) so the model can rewrite it directly."""
    parts = ["Deine letzte Antwort verletzt die CITATION DISCIPLINE des Projekts. Korrigiere sie."]

    claim_total = int(validation.get("claim_total") or 0)
    uncited = int(validation.get("uncited_claims") or 0)
    unverified = validation.get("unverified") or []

    if claim_total > 0 and uncited > 0:
        parts.append(
            f"\n**{uncited} von {claim_total} Bullet-Points / Behauptungen** in "
            f"deiner Antwort haben keine `[Quelle: <basename> — \"<wörtliches Zitat>\"]`-"
            f"Citation. Jede faktische Aussage muss ihre eigene Citation tragen."
        )

    if unverified:
        parts.append(f"\n**{len(unverified)} Zitat(e) konnten nicht in der Quelldatei verifiziert werden:**")
        for bn, quote, reason in unverified[:5]:
            excerpt = (quote[:100] + "…") if len(quote) > 100 else quote
            parts.append(f"- `{bn}` — \"{excerpt}\" *({reason})*")
        parts.append(
            "Stelle sicher dass jedes Zitat WÖRTLICH aus dem `read_document`-Output "
            "kopiert ist, character-by-character. Paraphrasen sind keine Citations."
        )

    parts.append(
        "\n**Anweisung**: Schreibe die Antwort nochmal. Behalte den richtigen Inhalt, "
        "ergänze fehlende Citations mit verbatim Quotes aus dem `read_document`-Output. "
        "Wenn du für eine Behauptung keine verbatim-Quote findest — **lösche die Behauptung**. "
        "Eine kürzere, vollständig zitierte Antwort ist besser als eine lange Antwort mit "
        "nicht-zitierten Aussagen. Antworte nur mit dem korrigierten Antworttext, keine Meta-Kommentare."
    )
    return "\n".join(parts)


def run_citation_reround(messages: list, original_reply: str, validation: dict,
                         model: str, api_key: str, base_url: str,
                         temperature: float = 0.2, top_p: float = 0.85,
                         timeout: float = 180.0) -> tuple[str, dict]:
    """Single non-streaming retry to fix citation discipline. Returns
    (corrected_reply, retry_validation). On any error, returns (original_reply, {})
    so the caller can fall back gracefully.

    `messages` should be the full conversation INCLUDING the assistant's
    original reply (not yet persisted). We append a synthetic user-message
    with the validator feedback and ask for a corrected answer.
    """
    feedback = build_citation_reround_feedback(validation, original_reply)
    # Build a clean message list: original convo + the assistant's first
    # answer + our feedback as a new user turn. The model sees: question,
    # tool-call rounds (with results), original answer, our feedback.
    new_messages = list(messages)  # copy
    # Make sure the assistant's latest answer is in the list (callers vary).
    if not new_messages or new_messages[-1].get("role") != "assistant":
        new_messages.append({"role": "assistant", "content": original_reply})
    new_messages.append({"role": "user", "content": feedback})

    try:
        from handlers import sidecar_proxy as _sidecar_proxy
        prov = resolve_provider_for_model(model)
        sid = get_request_context().current_session_id or ""
        agent_id = ""
        _ag = get_request_context().current_agent or _current_agent
        if _ag is not None:
            agent_id = getattr(_ag, "agent_id", "") or ""
        tool_context = {
            "session_id": sid,
            "agent_id": agent_id or "main",
            "user_id": get_request_context().current_user_id or "",
            "team_ids": [],
            "project": get_request_context().project or "",
            "note_context": None,
            "workflow_run_id": "",
            "plan_mode": False,
            "research_mode_override": None,
            "execution_overrides": {},
            "attachment_image_model": "",
            "caveman_chat": 0,
            "caveman_system": 0,
            "trace_id": "",
        }
        sampling = {
            "temperature": temperature,
            "top_p": top_p,
            "top_k": None,
            "stop_sequences": None,
        }
        # Caller-provided api_key/base_url are honored — they may differ from
        # resolve_provider_for_model when the chat used a session-specific
        # provider override.
        _res = _sidecar_proxy.run_turn_blocking(
            messages=new_messages,
            model=model,
            api_key=api_key or prov["api_key"],
            base_url=base_url or prov["base_url"],
            system_prompt="",
            purpose="transform",
            tool_context=tool_context,
            sampling=sampling,
            thinking_level=None,
            max_tokens=4096,
            max_rounds=1,
            timeout_s=timeout,
            # Reuse the interactive session's prompt-cache prefix: the re-round
            # replays the same system prompt + history + the just-produced answer
            # on the SAME model as the chat, so keying it to the session id lets
            # that large repeated prefix bill at the discounted cache_read rate
            # (a direct run_turn_blocking otherwise sends an empty key = no cache).
            prompt_cache_key=sid,
        )
        # Cost ledger — the citation re-round is a direct run_turn_blocking (not
        # background_call), so log it here under its own bucket.
        try:
            _u = _res.get("usage_total") or {}
            _ti = (int(_u.get("input_tokens", 0) or 0)
                   + int(_u.get("cache_creation_input_tokens", 0) or 0)
                   + int(_u.get("cache_read_input_tokens", 0) or 0))
            _to = int(_u.get("output_tokens", 0) or 0)
            _log_call_cost(model, _ti, _to, session_id=sid,
                           api_key=api_key or prov.get("api_key", ""),
                           purpose="citation_reround")
        except Exception:
            pass
        content = (_res.get("reply") or "").strip()
        if not content:
            return original_reply, {}
        # Validate the corrected answer too — useful diagnostic, even if we
        # accept it unconditionally (per design: max 1 re-round).
        retry_val = validate_citations_in_response(content, session_id=sid or None)
        return content, retry_val
    except Exception as e:
        try: print(f"[citation-reround] error: {type(e).__name__}: {e}")
        except Exception: pass
        return original_reply, {}


# --- Hook Runner ---

class HookRunner:
    """Runs external hook scripts for tool execution lifecycle events."""

    def __init__(self, agent_id: str = "main"):
        self.agent_id = agent_id
        self._hooks = self._load_hooks()

    def _load_hooks(self) -> list[dict]:
        """Load hook config from agent.json."""
        try:
            cfg = AgentConfig(self.agent_id)
            hooks_cfg = cfg.config.get("hooks", {})
            if not hooks_cfg.get("enabled", False):
                return []
            return [h for h in hooks_cfg.get("scripts", []) if h.get("enabled", True)]
        except Exception:
            return []

    def reload(self):
        self._hooks = self._load_hooks()

    def _get_timeout(self) -> int:
        try:
            cfg = AgentConfig(self.agent_id)
            return cfg.config.get("hooks", {}).get("timeout", 5000)
        except Exception:
            return 5000

    def get_hooks(self, hook_type: str, tool_name: str = "") -> list[dict]:
        """Get matching hooks for a type and tool."""
        result = []
        for h in self._hooks:
            if h.get("type") != hook_type:
                continue
            tools = h.get("tools", ["*"])
            if "*" in tools or tool_name in tools:
                result.append(h)
        return result

    def run_hook(self, hook: dict, env_extra: dict) -> tuple[int, str]:
        """Run a hook script. Returns (exit_code, stdout)."""
        script = hook.get("script", "")
        if not script:
            return 0, ""

        agent_dir = os.path.join(AGENTS_DIR, self.agent_id)
        script_path = os.path.join(agent_dir, script)
        if not os.path.isfile(script_path):
            logging.warning(f"Hook script not found: {script_path}")
            return 0, ""

        env = os.environ.copy()
        env["HOOK_AGENT"] = self.agent_id
        env["HOOK_SESSION_ID"] = get_request_context().session_id or ""
        env["HOOK_TIMESTAMP"] = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())
        env.update({k: str(v) for k, v in env_extra.items()})

        timeout_s = self._get_timeout() / 1000.0
        stdin_data = json.dumps(env_extra).encode("utf-8")

        try:
            proc = subprocess.Popen(
                ["bash", script_path],
                stdout=subprocess.PIPE, stderr=subprocess.PIPE,
                stdin=subprocess.PIPE, env=env,
                cwd=agent_dir, start_new_session=True,
            )
            stdout, stderr = proc.communicate(input=stdin_data, timeout=timeout_s)
            output = stdout.decode("utf-8", errors="replace").strip()
            if stderr:
                logging.debug(f"Hook {hook.get('name','?')} stderr: {stderr.decode('utf-8', errors='replace')[:200]}")
            return proc.returncode, output
        except subprocess.TimeoutExpired:
            from engine.tool_exec import kill_process_tree
            kill_process_tree(proc.pid, proc)
            proc.communicate(timeout=2)
            logging.warning(f"Hook {hook.get('name','?')} timed out after {timeout_s}s")
            return 1, f"Hook timed out after {timeout_s}s"
        except Exception as e:
            logging.warning(f"Hook {hook.get('name','?')} failed: {e}")
            return 0, ""  # fail-open

    def run_pre_hooks(self, tool_name: str, args: dict) -> str | None:
        """Run pre-hooks. Returns error message if blocked, None if allowed."""
        hooks = self.get_hooks("pre", tool_name)
        for h in hooks:
            env = {
                "HOOK_TYPE": "pre",
                "HOOK_TOOL_NAME": tool_name,
                "HOOK_TOOL_ARGS": json.dumps(args),
            }
            code, output = self.run_hook(h, env)
            if code == 1:
                hook_name = h.get("name", "unknown")
                msg = output or f"Blocked by hook: {hook_name}"
                logging.info(f"Hook {hook_name} blocked {tool_name}: {msg[:100]}")
                return _err(f"HOOK BLOCKED ({hook_name}): {msg}")
            if code == 2:
                break  # skip remaining hooks
        return None

    def run_post_hooks(self, tool_name: str, args: dict, result: str) -> str:
        """Run post-hooks. Returns (possibly modified) result."""
        hooks = self.get_hooks("post", tool_name)
        for h in hooks:
            env = {
                "HOOK_TYPE": "post",
                "HOOK_TOOL_NAME": tool_name,
                "HOOK_TOOL_ARGS": json.dumps(args),
                "HOOK_TOOL_RESULT": result[:50000],  # cap env var size
            }
            code, output = self.run_hook(h, env)
            if code == 0 and output:
                result = output  # modify result
            if code == 2:
                break
        return result

    def run_after_file_write(self, file_path: str, action: str):
        """Run after_file_write hooks."""
        hooks = self.get_hooks("after_file_write")
        for h in hooks:
            env = {
                "HOOK_TYPE": "after_file_write",
                "HOOK_FILE_PATH": file_path,
                "HOOK_FILE_ACTION": action,
            }
            self.run_hook(h, env)


# Cache hook runners per agent
_hook_runners: dict[str, HookRunner] = {}
_hook_runners_lock = threading.Lock()


def _get_hook_runner(agent_id: str = "main") -> HookRunner:
    """Get or create a HookRunner for an agent."""
    with _hook_runners_lock:
        if agent_id not in _hook_runners:
            _hook_runners[agent_id] = HookRunner(agent_id)
        return _hook_runners[agent_id]


# --- Artifact Helpers ---

_ARTIFACT_TYPE_MAP = {
    "html": "html", "htm": "html",
    "svg": "svg",
    "md": "markdown", "markdown": "markdown",
    "png": "image", "jpg": "image", "jpeg": "image", "gif": "image", "webp": "image", "bmp": "image",
    "pdf": "document", "docx": "document", "xlsx": "document", "pptx": "document",
    "mp3": "audio", "wav": "audio", "m4a": "audio", "ogg": "audio",
    "mp4": "video", "webm": "video", "mov": "video", "m4v": "video",
    "txt": "text",
    # Quant-Workbench C: .ipynb renders as cells (markdown/code/outputs) in
    # the panel. Deliberately NOT in _ARTIFACT_INTERMEDIATE_EXTS — a notebook
    # is the deliverable/Prüfartefakt (role 'output'), not a helper script.
    "ipynb": "notebook",
}

# Intermediate = working data or helper scripts the agent uses during a run;
# the output role (default) is the deliverable the user actually cares about.
# Keeps the run-detail and browse views decluttered by default. Text/markdown
# is always "output" since that's typically the final report.
_ARTIFACT_INTERMEDIATE_EXTS = {
    "py", "sh", "bash", "zsh", "js", "ts", "rb", "pl", "r",
    "json", "jsonl", "yaml", "yml", "toml", "ini", "cfg",
    "csv", "tsv", "log",
}

def _is_artifact_path(path: str) -> bool:
    """True for a file that should be REGISTERED as an artifact (→ Artifacts panel).

    Two homes, because a code-mode chat writes into the user's project rather than
    into an artifact folder:
      • `agents/<name>/artifacts/…` — every normal chat / scheduled run.
      • `<working_dir>/chats/<title>_<date>_<id>/…` — a CODE-MODE chat's output
        folder (v9.312.7), incl. its `subagents/<task_id>/` subfolders. Without
        this the Artifacts panel stayed EMPTY in code-mode projects: the files
        exist on disk but were never registered, so the user could not see what
        the agent produced (reported).

    Source files the agent edits in the project are NOT artifacts — only what it
    generates under the chat's own output folder is, which is exactly the
    directory `_code_mode_write_base` funnels generated files into.
    """
    try:
        real_path = os.path.realpath(path)
        agents_dir = os.path.realpath(AGENTS_DIR)
        if real_path.startswith(agents_dir + os.sep):
            parts = real_path[len(agents_dir) + 1:].split(os.sep)
            return len(parts) >= 3 and parts[1] == "artifacts"
        # Code mode: is it inside THIS project's `chats/` output tree?
        _wd = get_request_context().working_dir
        if _wd and os.path.isdir(_wd):
            chats_root = os.path.realpath(os.path.join(_wd, "chats"))
            return real_path.startswith(chats_root + os.sep)
        return False
    except Exception:
        return False

def _make_image_thumbnail(content: bytes, max_px: int = 480) -> bytes | None:
    """Downscale image bytes to a small WebP thumbnail for the browse grid.
    Returns WebP bytes (or None on any failure — caller treats None as 'no
    thumbnail', client falls back to fetching the full image). Pillow handles
    the common raster formats; animated/huge images collapse to a single frame.
    max_px caps the longest side (the browse card is ~300px, 480 covers retina)."""
    try:
        from PIL import Image
        import io as _io
        im = Image.open(_io.BytesIO(content))
        # Flatten palette/alpha onto white so WebP/JPEG don't choke; keep RGB.
        im.draft("RGB", (max_px, max_px))  # fast pre-scale on JPEG decode
        im = im.convert("RGB")
        im.thumbnail((max_px, max_px), Image.LANCZOS)
        out = _io.BytesIO()
        im.save(out, format="WEBP", quality=78, method=4)
        data = out.getvalue()
        # Sanity: a thumbnail that somehow came out larger than a 5MB cap is not
        # worth storing (degenerate input).
        return data if data and len(data) < 2 * 1024 * 1024 else None
    except Exception as e:
        try: print(f"  [WARN] thumbnail gen failed: {e}", flush=True)
        except Exception: pass
        return None


def _register_artifact_version(path: str, action: str, agent_id: str,
                               produced_by: str | None = None,
                               env_snapshot: str | None = None):
    """Register or update an artifact in the DB, capturing content snapshot.
    Returns (artifact_id, version, type) or None on failure.
    produced_by/env_snapshot (Phase B provenance) come only from callers with
    an attributable script (python_exec/r_exec); default None keeps every
    other caller unchanged."""
    try:
        from server import ChatDB
        import uuid as _uuid_mod

        session_id = get_request_context().current_session_id or ""
        if not session_id:
            return None

        name = os.path.basename(path)
        ext = name.rsplit(".", 1)[-1].lower() if "." in name else ""
        artifact_type = _ARTIFACT_TYPE_MAP.get(ext, "code")
        artifact_role = "intermediate" if ext in _ARTIFACT_INTERMEDIATE_EXTS else "output"

        # Read content snapshot (cap at 5MB)
        try:
            with open(path, "rb") as f:
                content = f.read(5 * 1024 * 1024)
            size = os.path.getsize(path)
            if size > 5 * 1024 * 1024:
                content = None  # too large, disk-only
        except Exception:
            content = None
            size = 0

        # Check if artifact already exists for this path+session
        existing = ChatDB.get_artifact_by_path(session_id, path)
        if existing:
            artifact_id = existing["id"]
            next_version = existing["latest_version"] + 1
        else:
            artifact_id = str(_uuid_mod.uuid4())[:12]
            ChatDB.create_artifact(artifact_id, session_id, agent_id, name, path, artifact_type, artifact_role)
            next_version = 1

        # Anchor this version to the producing turn (latest user message's
        # array position) so the UI can group artifacts by turn in the right
        # panel. None when no user message exists yet (background writes).
        msg_idx = ChatDB.artifact_message_idx(session_id)
        # Precompute a small image thumbnail ONCE at write time (Pillow), stored
        # on the version row so the browse grid never re-fetches full image bytes
        # per card. Best-effort: any failure → no thumbnail, client falls back to
        # the /content fetch. Only for raster image types (svg is text; vectors
        # render fine client-side).
        thumb = None
        if artifact_type == "image" and content and ext not in ("svg",):
            thumb = _make_image_thumbnail(content)
        ChatDB.add_artifact_version(artifact_id, next_version, content, size, msg_idx, action, thumbnail=thumb,
                                    produced_by=produced_by, env_snapshot=env_snapshot)
        return (artifact_id, next_version, artifact_type, msg_idx)
    except Exception as e:
        print(f"  [WARN] artifact registration: {e}", flush=True)
        return None


# --- Centralized File-Write Pipeline ---

# Design-Modus attachment embedding (v9.364.0): the design comment loop lets
# users attach images to a comment ("füge diesen Screenshot hier ein"). The
# image bytes must NEVER flow through the model (a 200KB screenshot is ~70k
# tokens as base64) and the srcdoc artifact iframe cannot load disk files —
# so the model writes only a short `attachment://<filename>` reference and
# this hook (called from _after_file_write, the one choke point every write
# path passes — write_file, edit_file, shell/python writes via the folder
# diff) replaces it deterministically with the real file from
# /tmp/brain-attachments/<session>/ as a data-URI. The saved artifact is
# self-contained: viewer (srcdoc), PDF/PPTX render service and the DOCX
# converter (handles base64 raster) all work on it. Unresolvable references
# queue a model-visible warning (drained into the tool result by
# llm_loop.dispatch_tool, the _gdpr_file_warnings pattern).
_ATTACHMENT_REF_RE = re.compile(r'attachment://([^"\'\s()<>]+)')
_ATTACH_INLINE_EXT_MIME = {
    ".png": "image/png", ".jpg": "image/jpeg", ".jpeg": "image/jpeg",
    ".gif": "image/gif", ".webp": "image/webp", ".svg": "image/svg+xml",
}
# Per-image cap (raw bytes; base64 is ~4/3) + result-file budget: the
# artifact_versions snapshot is capped at 5MB — a file inlined past that
# would silently lose its panel view (content=None, disk-only).
_ATTACH_INLINE_MAX_IMG = 3 * 1024 * 1024
_ATTACH_INLINE_MAX_FILE = 4_800_000


def _queue_design_file_warning(msg: str):
    ctx = get_request_context()
    if ctx._design_file_warnings is None:
        ctx._design_file_warnings = []
    ctx._design_file_warnings.append(msg)


def _inline_attachment_refs(path: str):
    """Replace `attachment://<name>` references in a just-written .html/.htm
    file with data-URIs of the matching files in this session's attachment
    dir. Deterministic transform — no LLM involvement. Unresolvable refs are
    left in place and reported via _queue_design_file_warning so the model
    learns in the same round."""
    if os.path.splitext(path)[1].lower() not in (".html", ".htm"):
        return
    try:
        with open(path, "rb") as f:
            raw = f.read()
    except Exception:
        return
    if b"attachment://" not in raw:
        return
    sid = get_request_context().session_id or \
        get_request_context().current_session_id or ""
    if not sid:
        return
    try:
        text = raw.decode("utf-8")
    except UnicodeDecodeError:
        _queue_design_file_warning(
            f"{os.path.basename(path)}: attachment://-Referenz gefunden, aber "
            f"die Datei ist nicht UTF-8 — nichts eingebettet.")
        return
    from engine.tool_exec import brain_attachments_dir
    attach_dir = brain_attachments_dir(sid)
    budget = _ATTACH_INLINE_MAX_FILE - len(raw)

    def _repl(m):
        nonlocal budget
        from urllib.parse import unquote
        name = os.path.basename(unquote(m.group(1)))
        ref = m.group(0)
        mime = _ATTACH_INLINE_EXT_MIME.get(os.path.splitext(name)[1].lower())
        if not mime:
            _queue_design_file_warning(
                f"attachment://{name}: kein einbettbares Bildformat "
                f"(unterstützt: {', '.join(sorted(_ATTACH_INLINE_EXT_MIME))}).")
            return ref
        fpath = os.path.join(attach_dir, name)
        if not os.path.isfile(fpath):
            _queue_design_file_warning(
                f"attachment://{name}: Datei nicht unter den Anhängen dieser "
                f"Session gefunden — Dateinamen aus dem Anhang-Hinweis "
                f"verwenden (Datei auf der Platte, nicht Originalname).")
            return ref
        fsize = os.path.getsize(fpath)
        if fsize > _ATTACH_INLINE_MAX_IMG:
            _queue_design_file_warning(
                f"attachment://{name}: Bild zu groß zum Einbetten "
                f"({fsize // 1024} KB > {_ATTACH_INLINE_MAX_IMG // 1024} KB).")
            return ref
        b64_len = 4 * ((fsize + 2) // 3)
        if b64_len > budget:
            _queue_design_file_warning(
                f"attachment://{name}: Einbetten würde das Artefakt über die "
                f"5-MB-Versionsgrenze heben — Referenz belassen.")
            return ref
        import base64 as _b64mod
        with open(fpath, "rb") as fp:
            b64 = _b64mod.b64encode(fp.read()).decode("ascii")
        budget -= len(b64)
        return f"data:{mime};base64,{b64}"

    new_text = _ATTACHMENT_REF_RE.sub(_repl, text)
    if new_text != text:
        with open(path, "w", encoding="utf-8") as f:
            f.write(new_text)


def _after_file_write(path: str, action: str = "created", agent_id: str = "",
                      produced_by: str | None = None,
                      env_snapshot: str | None = None):
    """Centralized post-file-write pipeline. Called from tool_write_file and tool_edit_file.
    Replaces scattered _maybe_qmd_reindex(), _extract_entities(), file_created calls.
    produced_by/env_snapshot: Phase-B provenance, set only by python_exec/r_exec
    for files their script wrote (execute_command has no attributable script —
    honestly None)."""
    # Design-Modus attachment inlining — BEFORE the GDPR callback and artifact
    # registration, so the de-anonymise pass and the registered version both
    # see the final, self-contained bytes. Best-effort: a bug here must never
    # break the write path (expected failures queue model-visible warnings
    # inside the helper instead).
    try:
        _inline_attachment_refs(path)
    except Exception as e:
        print(f"[design-inline] failed for {path}: {e}", flush=True)

    # Transparent anonymisation: if the chat worker installed a deanonymise
    # callback on this thread, invoke it BEFORE artifact registration so the
    # UI sees the de-anonymised bytes (and the version row's hash matches the
    # user-visible content). The callback is responsible for any synthetic
    # event emission + audit logging — keeping the SessionManager dependency
    # out of brain.py.
    _gdpr_cb = get_request_context()._gdpr_after_file_write_cb
    if _gdpr_cb is not None:
        try:
            _gdpr_cb(path, action, agent_id)
        except Exception:
            pass

    is_artifact = _is_artifact_path(path)

    # MemPalace migration: QMD reindex + entity extraction + KG update removed.
    # Memory layer is now mempalace MCP — agents file content via
    # mempalace_add_drawer themselves; QMD/KG are no longer in the picture.

    # 3. Artifact REGISTRATION — persistence, NOT a UI event. Deliberately outside
    #    the `if ecb:` below: a detached background task (sub-agent) has no
    #    event_callback (nobody is listening — the spawning turn is long over), and
    #    registration used to live INSIDE that gate, so every file a sub-agent
    #    produced was silently never registered and stayed invisible in the
    #    Artifacts panel (reported: "der User kann keinen Output sehen"). The SSE
    #    emit stays gated — there is simply no one to notify.
    art_result = None
    if is_artifact:
        try:
            art_result = _register_artifact_version(
                path, action, agent_id,
                produced_by=produced_by, env_snapshot=env_snapshot)
        except Exception as e:
            print(f"[artifact] registration failed for {path}: {e}", flush=True)

    # 4. File/artifact event emission (for UI)
    ecb = get_request_context().event_callback
    if ecb:
        try:
            if is_artifact:
                if art_result:
                    art_id, art_ver, art_type, art_msg_idx = art_result
                    _name = os.path.basename(path)
                    _ext = _name.rsplit(".", 1)[-1].lower() if "." in _name else ""
                    _role = "intermediate" if _ext in _ARTIFACT_INTERMEDIATE_EXTS else "output"
                    ecb("artifact_updated", {
                        "path": path,
                        "name": _name,
                        "size": os.path.getsize(path),
                        "action": action,
                        "artifact_id": art_id,
                        "artifact_version": art_ver,
                        "artifact_type": art_type,
                        "artifact_role": _role,
                        "message_idx": art_msg_idx,
                        # Phase-B provenance; clients ignore unknown fields.
                        "produced_by": produced_by,
                        "env_snapshot": env_snapshot,
                    })
                else:
                    # Fallback to regular file event if artifact registration failed
                    ecb("file_created", {
                        "path": path,
                        "name": os.path.basename(path),
                        "size": os.path.getsize(path),
                        "action": action,
                    })
            else:
                ecb("file_created", {
                    "path": path,
                    "name": os.path.basename(path),
                    "size": os.path.getsize(path),
                    "action": action,
                })
        except Exception:
            pass

    # 4. Code index: no per-write update. The codebase-memory index is built on
    #    code-mode entry (and re-indexed on demand); cbm indexing is incremental
    #    + fast (~2s full repo), so a fresh re-index at next entry picks up the
    #    agent's own edits — a per-write whole-repo reindex would be wasteful.

    # 5. External after_file_write hooks
    if agent_id:
        try:
            runner = _get_hook_runner(agent_id)
            runner.run_after_file_write(path, action)
        except Exception:
            pass


_DATA_URI_RE = re.compile(r'data:([a-zA-Z0-9][a-zA-Z0-9!#$&\-^_]*/[a-zA-Z0-9][a-zA-Z0-9!#$&\-^_.+]*);base64,([A-Za-z0-9+/=]+)')

_MIME_TO_EXT = {
    "image/jpeg": "jpg", "image/jpg": "jpg", "image/png": "png",
    "image/gif": "gif", "image/webp": "webp", "image/svg+xml": "svg",
    "audio/wav": "wav", "audio/wave": "wav", "audio/x-wav": "wav",
    "audio/mpeg": "mp3", "audio/mp4": "m4a", "audio/ogg": "ogg",
    "audio/flac": "flac", "audio/aac": "aac",
    "video/mp4": "mp4", "video/quicktime": "mov", "video/webm": "webm",
    "video/x-msvideo": "avi", "video/mpeg": "mpeg",
    "application/pdf": "pdf", "application/zip": "zip",
}

def _mime_to_ext(mime: str) -> str:
    return _MIME_TO_EXT.get(mime) or mime.split("/")[-1].split("+")[0].split(";")[0]


def _extract_and_save_mcp_blobs_direct(raw_result: str, session_id: str) -> str:
    """Extract any binary blobs from a tool result and save as artifacts.

    Handles _mcp_images/_mcp_blobs structured blocks and data:<mime>;base64,...
    URIs anywhere in the result text. Works for all MIME types.
    Returns cleaned result string.
    """
    import base64 as _b64
    try:
        parsed = json.loads(raw_result)
    except (json.JSONDecodeError, TypeError):
        return raw_result
    if not isinstance(parsed, dict):
        return raw_result

    _sid = session_id or get_request_context().current_session_id or ""
    _agent = get_request_context().current_agent or _current_agent
    _agent_id = _agent.agent_id if _agent else "main"
    if not _sid or not _agent:
        return raw_result

    folder = _get_artifact_session_folder(_sid)
    artifact_dir = os.path.join(AGENTS_DIR, _agent_id, "artifacts", folder)
    os.makedirs(artifact_dir, exist_ok=True)

    counter = [0]
    saved_paths = []

    def _save(mime: str, b64_data: str) -> str | None:
        try:
            ext = _mime_to_ext(mime)
            raw_bytes = _b64.b64decode(b64_data)
            counter[0] += 1
            suffix = f"_{counter[0]}" if counter[0] > 1 else ""
            hint = "mcp_screenshot" if mime.startswith("image/") else "mcp_output"
            fname = f"{hint}{suffix}.{ext}"
            fpath = os.path.join(artifact_dir, fname)
            with open(fpath, "wb") as f:
                f.write(raw_bytes)
            _after_file_write(fpath, "created", _agent_id)
            return fpath
        except Exception as e:
            return f"(blob save failed: {e})"

    # Structured blob blocks from MCP clients
    for key in ("_mcp_images", "_mcp_blobs"):
        for blob in parsed.pop(key, []):
            mime = blob.get("mimeType") or blob.get("media_type") or "application/octet-stream"
            p = _save(mime, blob.get("data", ""))
            if p:
                saved_paths.append(p)

    # data:<mime>;base64,<data> URIs anywhere in result text
    result_text = parsed.get("result", "")
    if ";base64," in result_text:
        def _replace(m: re.Match) -> str:
            p = _save(m.group(1), m.group(2))
            if p:
                saved_paths.append(p)
                return f"[saved as artifact: {os.path.basename(p)}]"
            return m.group(0)
        parsed["result"] = _DATA_URI_RE.sub(_replace, result_text)

    if saved_paths:
        names = ", ".join(os.path.basename(p) for p in saved_paths)
        parsed["result"] = (parsed.get("result") or "").rstrip() + f"\n\nSaved as artifact: {names}"

    return json.dumps(parsed)


def _execute_tools_batch(tool_calls: list[dict], event_callback=None, tool_round: int = 0) -> list[dict]:
    """Execute a batch of tool calls sequentially.

    Each tool_call dict: {"id": str, "name": str, "input": dict}
    Returns list of {"tool_use_id": str, "result": str} in order.
    """
    if not tool_calls:
        return []
    # Surface the round number to tools that want to attribute "first read"
    # turns in cache stubs (read_document / read_file).
    try:
        get_request_context().tool_round = tool_round
    except Exception:
        pass

    results = []
    for tc in tool_calls:
        _display_tool_call(tc["name"], tc["input"])
        if event_callback:
            event_callback("tool_call", {"name": tc["name"], "args": tc["input"], "tool_round": tool_round})
        # NOTE: dead code (no live caller — the sidecar owns tool dispatch).
        # Set only event_callback + tool_use_id on the CURRENT context (the tool
        # needs the surrounding current_agent/session_id to stay intact — a fresh
        # request_context() would reset them), then clear the two afterward.
        _ctx = get_request_context()
        _ctx.event_callback = event_callback
        _ctx.tool_use_id = tc["id"]
        try:
            result = _execute_tool(tc["name"], tc["input"])
        finally:
            _ctx.event_callback = None
            _ctx.tool_use_id = None
        _display_tool_result(tc["name"], result)
        if event_callback:
            event_callback("tool_result", {"name": tc["name"], "result": result, "tool_round": tool_round})
        results.append({"tool_use_id": tc["id"], "result": result})
    return results


def _execute_tool(name: str, args: dict) -> str:
    """Tool dispatch entry point. Routes through the worker subagent wrapper
    for heavy tools, direct execution for light tools. (v8.0.0+)"""
    from execution import route_tool_execution
    return route_tool_execution(name, args, _execute_tool_inner)


def _execute_tool_inner(name: str, args: dict) -> str:
    """Execute a tool directly — no worker routing. Called by the router
    and by workers themselves."""
    # --- Built-in pre-hooks ---
    # Plan mode: block non-readonly tools
    if get_request_context().plan_mode:
        if name not in READONLY_TOOLS:
            return _err("Blocked in plan mode. Describe what you would do instead.")
    # Workflow tool restriction (was dead code — now enforced)
    workflow_tools = get_request_context().workflow_allowed_tools
    if workflow_tools is not None and name not in workflow_tools:
        return _err(f"Tool '{name}' not allowed in this workflow stage.")
    # Dedup check
    dedup = _check_tool_dedup(name, args)
    if dedup:
        return dedup

    # --- External pre-hooks ---
    agent = get_request_context().current_agent or _current_agent
    agent_id = agent.agent_id if agent else "main"
    session_id = get_request_context().session_id
    try:
        runner = _get_hook_runner(agent_id)
        blocked = runner.run_pre_hooks(name, args)
        if blocked:
            return blocked
    except Exception:
        pass

    # --- Tracing: start span ---
    tool_span = None
    if _trace_manager:
        parent_span = get_request_context().current_trace_span
        trace_id = parent_span["trace_id"] if parent_span else get_request_context().trace_id
        parent_id = parent_span["id"] if parent_span else None
        tool_span = _trace_manager.start_span(
            "tool_call", name, agent=agent_id, model="",
            parent_id=parent_id, trace_id=trace_id, session_id=session_id,
        )

    tool_start = time.time()
    result_status = "success"
    result = None
    try:
        # Check MCP tools first (prefer thread-local for concurrent requests)
        if (mcp := (get_request_context().mcp_manager or _mcp_manager)) and mcp.is_mcp_tool(name):
            result = mcp.call_tool(name, args)
        else:
            fn = TOOL_DISPATCH.get(name)
            if fn:
                result = fn(args)
            else:
                result = _err(f"Unknown tool: {name}")
    except Exception as e:
        result_status = "error"
        result = _err(str(e))
    finally:
        duration_ms = int((time.time() - tool_start) * 1000)
        # --- Built-in post-hooks ---
        # Determine audit status from result
        if result and result_status == "success":
            try:
                rdata = json.loads(result) if result else {}
                if isinstance(rdata, dict) and rdata.get("error"):
                    result_status = "error"
            except (json.JSONDecodeError, TypeError):
                pass

        # End trace span
        if _trace_manager and tool_span:
            _trace_manager.end_span(tool_span, status=result_status,
                                     result_summary=(result or "")[:200])

        # Audit log
        if _audit_log and result is not None:
            action_type = _AUDIT_ACTION_MAP.get(name, "mcp_tool_call" if name.startswith("mcp_") else "unknown")
            try:
                _audit_log.log_action(
                    agent=agent_id,
                    action_type=action_type,
                    tool_name=name,
                    args_summary=_audit_summarize_args(name, args),
                    result_summary=_audit_summarize_result(name, result),
                    result_status=result_status,
                    duration_ms=duration_ms,
                    session_id=session_id,
                    source=get_request_context().audit_source,
                )
            except Exception:
                pass

        # --- External post-hooks ---
        if result is not None:
            try:
                runner = _get_hook_runner(agent_id)
                result = runner.run_post_hooks(name, args, result)
            except Exception:
                pass

    return result


# Tool-round cap = a RUNAWAY BRAKE, not a work budget. It exists to bound a model
# that has lost the plot; it must never be the thing that stops a model doing real
# work. 15/25 was the latter: a code-mode turn (read 3 JSONs → render 3 diagrams →
# fix key errors → write the report) hit the cap ONE tool call short of its report
# and, worse, said nothing (v9.312.11). The real loop guards are the tool-dedup
# (2 identical calls → TaskCancelled), the per-round cost brake, and Cancel — all
# of which trigger on actual misbehaviour rather than on a counter. So: set the cap
# where only a genuinely runaway turn can reach it.
MAX_TOOL_ROUNDS = 80
MAX_TOOL_ROUNDS_PROXY = 8  # Tighter limit for CLIProxyAPI (shares personal OAuth quota)
# Intent-vs-action guard: detects "I'll write…/Let me search…" stalls where the
# model announces the next step but stops without calling the tool. Compiled
# once at module load. Anchored to the LAST sentence of the reply.
import re as _re_intent
_INTENT_ACTION_PATTERNS = _re_intent.compile(
    r"(?:^|[\.\!\?]\s+|\n)"                                     # sentence boundary
    r"(?:Now\s+(?:I[''’]?\s*ll|let\s+me|I\s+will)|"             # "Now I'll…", "Now let me…"
    r"I[''’]?ll\s+(?:now|next)?\s*(?:create|write|compile|save|"  # "I'll create/write…"
    r"compose|generate|produce|prepare|build|search|look|check|" # "I'll search/look/check"
    r"gather|fetch|find|retrieve|consult|review|examine)|"
    r"Let\s+me\s+(?:now\s+)?(?:create|write|compile|save|"      # "Let me write/compile…"
    r"compose|generate|produce|prepare|build|search|look|check|"
    r"gather|fetch|find|retrieve|consult|review|examine))"
    r"[^.!?\n]{0,200}?"                                         # short phrase
    r"[\.\!\?\…]?\s*$",                                         # end of reply
    _re_intent.IGNORECASE,
)
_INTENT_ACTION_RECOVERY_LIMIT = 1
_INTENT_ACTION_RESUME_MSG = (
    "You announced the next action but didn't actually take it. "
    "Either call the tool now, or if you've already gathered enough information, "
    "write the final answer directly. Do not announce — execute."
)

# Loop transition reasons (for debugging / state machine tracking)
# Modeled on Claude Code's query.ts transition types
TRANSITION_NEXT_TURN = "next_turn"
TRANSITION_MAX_OUTPUT_RECOVERY = "max_output_recovery"
TRANSITION_REACTIVE_COMPACT = "reactive_compact_retry"
TRANSITION_COMPLETED = "completed"
TRANSITION_MAX_TURNS = "max_turns"
TRANSITION_ABORTED = "aborted"


# --- Middleware Pipeline (Phase 9) ---
# Composable pre-turn middleware for the direct agentic loop.
# Each middleware: fn(messages, tool_round, event_callback, **ctx) -> (messages, should_continue)

def _middleware_cancel_check(messages, tool_round, event_callback, **ctx):
    """Check cancel token before each turn."""
    watcher = ctx.get("escape_watcher")
    if watcher and watcher.cancelled:
        raise TaskCancelled()
    return messages, True

def _middleware_compress_old(messages, tool_round, event_callback, **ctx):
    """Compress old tool results when accumulated budget exceeded (Layer 3)."""
    if tool_round > 0:
        accumulated = get_request_context()._tool_results_tokens
        _limit = _get_agent_limits().get("tool_results_total_tokens", MAX_TOOL_RESULTS_TOKENS)
        if accumulated > _limit:
            _compress_old_tool_results(messages, keep_recent=4)
    return messages, True

# Ordered middleware pipeline — runs between tool rounds (NOT for full LCM compaction,
# which happens at turn boundaries in send_message before round 0)
_MIDDLEWARE_PIPELINE = [
    _middleware_cancel_check,
    _middleware_compress_old,
]

def _run_middleware(messages, tool_round, event_callback, **ctx):
    """Run the pre-turn middleware pipeline. Returns (messages, should_continue)."""
    for mw in _MIDDLEWARE_PIPELINE:
        messages, should_continue = mw(messages, tool_round, event_callback, **ctx)
        if not should_continue:
            return messages, False
    return messages, True
MAX_TOOL_RESULTS_TOKENS = 50000  # Cap accumulated tool results per turn before compressing old ones

# Per-agent runtime limits (overridable via agent.json "limits" block)
AGENT_LIMITS_DEFAULTS = {
    "max_tool_rounds": MAX_TOOL_ROUNDS,
    "tool_results_total_tokens": MAX_TOOL_RESULTS_TOKENS,
    "context_safety_ratio": 0.95,
}


def _get_agent_limits(agent_id: str | None = None) -> dict:
    """Get runtime limits for an agent, merged with defaults.

    Precedence (lowest → highest):
      AGENT_LIMITS_DEFAULTS < model profile overlay < agent limits
    """
    agent = get_request_context().current_agent or _current_agent
    result = dict(AGENT_LIMITS_DEFAULTS)

    # Overlay model profile's limits fragment if a model is bound
    mid = get_request_context()._current_model
    if mid:
        prof = resolve_profile_limits(mid)
        for k, v in prof.items():
            if k in result:
                result[k] = v

    if not agent:
        return result
    cfg = agent.config.get("limits", {})
    if isinstance(cfg, dict):
        for k in AGENT_LIMITS_DEFAULTS:
            if k in cfg and cfg[k] is not None:
                result[k] = cfg[k]
    return result

# Tool-result processing cluster (_BASE64_DATA_RE, _BASE64_RAW_RE,
# _sanitize_tool_result, _compress_old_tool_results, TOOL_RESULT_BUDGET_THRESHOLD,
# TOOL_RESULT_PREVIEW_SIZE, _apply_tool_result_budget, _MICROCOMPACT_TOOLS,
# _COMPACT_TOOL_ARGS, _MICROCOMPACT_EXEMPT, _microcompact,
# _find_tool_name_for_result, _find_tool_name_for_block) moved to
# engine/tool_exec.py (refactor C2); re-exported at the bottom of this module.
# _apply_tool_result_budget reaches AGENTS_DIR / _current_agent /
# _get_artifact_session_folder via the tool_exec `_brain` lazy proxy.


def _log_call_cost(model: str, tokens_in: int, tokens_out: int,
                   session_id: str | None = None, tool_round: int = 0,
                   api_key: str = "", user_id: str | None = None,
                   agent_id: str | None = None, purpose: str | None = None,
                   cache_read_tokens: int = 0):
    """Log an LLM call to the cost tracker (if initialized).

    `user_id`/`agent_id` default to the request context (interactive path), but
    can be passed EXPLICITLY for background work (Studio gen, Deep Research) that
    runs on a daemon thread with no request context — otherwise the cost would be
    logged unattributed.

    `purpose` is the use-case tag for the per-use-case cost breakdown (chat,
    chat_summary, scheduled, translate, ...). None → read the request context's
    `cost_purpose`; pass explicitly when the local call site knows its purpose.

    `cache_read_tokens` is the prompt-cache HIT portion (billed at the discounted
    cache_read rate, stored in its own column). It is NOT part of `tokens_in` —
    callers split it out from the provider's cache_read_input_tokens. 0 = no hit."""
    if not _cost_tracker:
        return
    # NOTE: we deliberately do NOT skip zero-usage calls. A row is written even
    # when tokens_in == tokens_out == 0 so that "a call happened but reported no
    # usage" is visible in the cost breakdown — that's a traffic/logging-error
    # signal worth surfacing, not noise to hide. $0 local/free calls (real
    # tokens, zero cost) are likewise always logged for a complete audit.
    if agent_id is None:
        agent = get_request_context().current_agent or _current_agent
        agent_id = agent.agent_id if agent else "main"
    provider = _models_config.get(model, {}).get("provider", "")
    if user_id is None:
        user_id = get_request_context().current_user_id or ""
    if purpose is None:
        purpose = get_request_context().cost_purpose or ""
    # Resolve key_name from the pool using the api_key value
    key_name = ""
    if api_key and provider:
        try:
            with _key_pools_lock:
                pool = _key_pools.get(provider)
            if pool:
                for k in pool._keys:
                    if k.get("key") == api_key:
                        key_name = k.get("name", "")
                        break
        except Exception:
            pass
    try:
        _cost_tracker.log_call(agent_id, session_id, model, provider,
                               tokens_in, tokens_out, tool_round, user_id=user_id,
                               key_name=key_name, purpose=purpose or "",
                               cache_read_tokens=cache_read_tokens)
        # Record in rate limiter too
        if _rate_limiter:
            cost = _compute_cost(model, tokens_in, tokens_out, cache_read_tokens)
            _rate_limiter.record_usage(agent_id, tokens_in + tokens_out + (cache_read_tokens or 0), cost)
    except Exception as e:
        logging.warning(f"Cost logging error: {e}")


def account_background_usage(result: dict, model: str, *, session_id: str,
                             user_id: str = "", agent_id: str = "main",
                             purpose: str | None = None, log: bool = True) -> dict:
    """Compute a background_call's usage metadata `{model, tokens_in, tokens_out,
    cost}` from the sidecar result, optionally logging a cost_log row.

    `log=True` (default) writes the cost row (attributed to user_id, like chats).
    `log=False` is COMPUTE-ONLY — returns the numbers WITHOUT a ledger write, for
    callers (Studio cards, Deep Research footer, audio totals) that already get a
    central row from `background_call` and only need the figures for display. Cost
    is derived via the same _compute_cost rates the chat ledger uses.

    cache_read is split OUT and billed at the discounted cache_read rate; tokens_in
    keeps fresh input + cache_creation at full price (oMLX reports the whole prompt
    under cache_creation, so that must NOT be discounted)."""
    usage = (result or {}).get("usage_total") or {}
    cr = int(usage.get("cache_read_input_tokens", 0) or 0)
    ti = (int(usage.get("input_tokens", 0) or 0)
          + int(usage.get("cache_creation_input_tokens", 0) or 0))
    to = int(usage.get("output_tokens", 0) or 0)
    if log:
        _log_call_cost(model, ti, to, session_id=session_id,
                       user_id=user_id, agent_id=agent_id, purpose=purpose,
                       cache_read_tokens=cr)
    return {"model": model, "tokens_in": ti, "tokens_out": to,
            "cache_read_tokens": cr,
            "cost": round(_compute_cost(model, ti, to, cr), 6)}


